export function localizedAgentGuidesPartD(en: Guides): Partial<Record<LandingLocaleCode, Guides>> {
  return {
    'nl': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code voor design — Open Design",
        description: "Hoe designers Claude Code gebruiken voor UI- en webdesign, en hoe Open Design er een echte design-agent van maakt — local-first, BYOK, met een samengestelde bibliotheek van skills en design systems.",
        breadcrumb: "Claude Code",
        label: "Agent · Claude Code",
        heading: "Claude Code voor design.",
        lead: "Claude Code is de terminal-coding-agent van Anthropic. Mensen gebruiken hem al om UI's, design systems en landingspagina's te bouwen. Open Design koppelt hem aan een echte design-workflow — neem je Anthropic-key of Claude-abonnement mee en houd elk bestand lokaal.",
        rich: {"heroCtaLead": "Open Design maakt van Claude Code een local-first, open-source design-agent — je Anthropic-key of Claude-abonnement, je bestanden, en een samengestelde bibliotheek van skills en design systems eromheen.", "heroCtaActions": [{"label": "Gebruik Claude Code binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code wordt algemeen beschouwd als de coding-agent met de beste frontend-smaak — hij redeneert met ongewone precisie over interfaces, noemt exacte hex-waarden, spacing en typeschalen, en refactort UI in een grote codebase zonder de draad kwijt te raken. Maar standaard neigt hij toch naar een generieke look, tenzij je hem een design system, skills en echte referenties aanreikt. Dit is een praktische, end-to-end gids voor het gebruik van Claude Code voor UI-, frontend- en design-system-werk, en voor het inbedden ervan in een gestructureerde workflow met Open Design.", "Het behandelt wat Claude Code precies is, waarom hij sterk is in frontend, hoe je hem vanaf nul opzet, de CLAUDE.md- en Skills-workflow, de officiële Figma-round-trip, hoe hij zich verhoudt tot Codex en Cursor, de valkuilen die AI-output generiek doen ogen, en hoe Open Design de kloof dicht als een open, local-first designlaag."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Feedbacklus van Claude Code-design: terminal-agent die specifieke designbeslissingen neemt, een browser die de UI rendert, en een werkruimte, met een feedbackpijl die terugloopt", "caption": "De kernlus: Claude Code redeneert specifieke UI-beslissingen uit in de terminal, rendert en verifieert ze in een echte browser, en convergeert naar je referenties."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-claude-code", "label": "Wat Claude Code precies is"}, {"id": "why-design", "label": "Waarom Claude Code goed is in design"}, {"id": "setup", "label": "Claude Code instellen voor design (vanaf nul)"}, {"id": "skills-workflow", "label": "De CLAUDE.md- en Skills-workflow"}, {"id": "figma", "label": "Claude Code + Figma-round-trip"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "Valkuilen en de “AI slop”-look"}, {"id": "open-design", "label": "Designen met Claude Code in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-claude-code", "heading": "Wat Claude Code precies is", "blocks": [{"kind": "p", "text": "Claude Code is de agentic coding-tool van Anthropic. Hij leest je codebase, bewerkt bestanden, voert commando's uit en integreert met je dev-tools — hij plant, schrijft en verifieert werk op basis van taken in natuurlijke taal in plaats van alleen regels aan te vullen."}, {"kind": "p", "text": "Hij komt in meerdere vormen die allemaal dezelfde engine delen: een terminal-CLI, IDE-extensies voor VS Code, Cursor en JetBrains, een desktop-app met visuele diff-review, en een web-ervaring voor langlopende taken. Je CLAUDE.md-bestanden, instellingen en MCP-servers reizen overal mee."}, {"kind": "steps", "items": [{"label": "Instructiebestand", "body": "Claude Code leest aan het begin van elke sessie een CLAUDE.md-bestand in je projectroot — de natuurlijke plek om je designconventies, tokens en review-checklists vast te leggen."}, {"label": "Skills", "body": "Agent Skills bundelen herbruikbare instructies, scripts en resources die Claude op aanvraag laadt, waaronder Anthropics officiële Frontend Design-skill voor smaak."}, {"label": "Plan en subagents", "body": "Hij kan plannen voordat hij handelt en subagents opstarten die parallel aan verschillende delen van een taak werken, wat grote UI-refactors coherent houdt."}]}, {"kind": "ul", "items": ["Leverancier: Anthropic", "Credential: Anthropic API-key (BYOK, via de Console) of een Claude-abonnement (Pro / Max)", "Vormen: terminal-CLI, VS Code- / Cursor- / JetBrains-extensies, desktop-app, web"]}]}, {"id": "why-design", "heading": "Waarom Claude Code goed is in design", "blocks": [{"kind": "p", "text": "Onder coding-agents heeft Claude Code een reputatie voor smaak in frontend-werk. Een paar dingen verklaren dat."}, {"kind": "steps", "items": [{"label": "Specifieke, niet vage, beslissingen", "body": "Claude Code neigt naar concrete keuzes — exacte hex-waarden, spacing-schalen, typeschalen en componenthiërarchie — in plaats van vaagheid, en dat is wat een echte interface onderscheidt van een placeholder."}, {"label": "Codebase-bewust redeneren", "body": "Met een grote werkcontext refactort hij UI over veel bestanden tegelijk en hergebruikt hij je bestaande componenten en tokens in plaats van eenmalige stijlen opnieuw uit te vinden."}, {"label": "Een officiële frontend-skill", "body": "Anthropic levert een Frontend Design-skill die Claude eerst een designrichting laat schrijven en bewust wegstuurt van generieke systeemlettertypen en voorspelbare paarse gradiënten."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Diagram dat laat zien hoe design system, skill en referentiebeeld samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een design system, een skill en echte referentiebeelden."}, {"kind": "p", "text": "De les is dezelfde die Anthropic over zijn eigen modellen maakt: Claude heeft standaard geen smaak — aan zichzelf overgelaten convergeert hij naar het statistische midden van webdesign (Inter, paarse gradiënten, zachte schaduwen). Hij levert goed design wanneer je hem beperkingen geeft. Open Design verpakt precies die inputs, en daarom passen de twee samen (meer hieronder)."}]}, {"id": "setup", "heading": "Claude Code voor designwerk opzetten, vanaf nul", "blocks": [{"kind": "p", "text": "Dit is het volledige pad van een schone machine naar een Claude Code die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Setupflow in vijf stappen: installeren, authenticeren, CLAUDE.md configureren, skill toevoegen, verifiëren", "caption": "De setup-volgorde: installeren → authenticeren → CLAUDE.md configureren → de Frontend Design-skill toevoegen → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Leg je designregels vast", "body": "Zet je tokens, primitives en conventies in CLAUDE.md en wijs Claude erop, zodat de output bij een merk past in plaats van terug te vallen op een generieke look."}, {"label": "Voeg browserverificatie toe", "body": "Koppel een Playwright- of Chrome-MCP zodat Claude in een echte browser rendert en zijn output over breakpoints heen controleert, in plaats van alleen te bevestigen dat de build slaagt."}]}]}, {"id": "skills-workflow", "heading": "De CLAUDE.md- en Skills-workflow", "blocks": [{"kind": "p", "text": "De design-lus met de meeste hefboomwerking bij Claude Code is hem echte referenties plus je designcontext voeden en dan itereren tot de UI klopt — met CLAUDE.md en Skills die de beperkingen vasthouden, zodat je ze niet bij elke prompt opnieuw hoeft uit te leggen."}, {"kind": "ol", "items": ["Begin met de helderste visuele referenties die je hebt — en neem meerdere states mee (desktop en mobiel, hover, leeg, laden), niet alleen één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op, zelfs met een sterke agent.", "Houd je design system en conventies in CLAUDE.md en vertel Claude waar de tokens en canonieke primitives staan.", "Voeg de Frontend Design-skill toe zodat Claude zich vastlegt op een echte esthetische richting voordat hij code schrijft.", "Koppel browserverificatie zodat Claude rendert, naar breakpoints herschaalt en terugvergelijkt met de referenties — niet alleen bevestigt dat het bouwt."]}, {"kind": "p", "text": "Sleep een referentiebeeld in de sessie en prompt met concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Draai er een dev-server naast, houd prompts klein en gericht, en commit goede iteraties / draai slechte terug (vertel Claude wanneer je terugdraait) zodat elke ronde voortbouwt op een schone basis. Gebruik plan-mode voor grotere refactors zodat je de aanpak kunt beoordelen voordat er bestanden veranderen."}]}, {"id": "figma", "heading": "Claude Code + Figma: design ↔ code-round-trip", "blocks": [{"kind": "p", "text": "In februari 2026 leverden Anthropic en Figma een eersteklas, bidirectionele integratie via de Figma MCP-server. Hij werkt in beide richtingen."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Selecteer een frame in Figma of plak een link in Claude Code, haal de designcontext op en vraag hem het design te implementeren met je bestaande componentbibliotheek. Code Connect houdt de output uitgelijnd met je echte componenten."}, {"label": "Code → Design", "body": "Bouw en bekijk een feature in de browser en zeg dan “Send this to Figma” om de draaiende UI vast te leggen als bewerkbare Figma-lagen — het hele scherm of een geselecteerd element."}]}, {"kind": "p", "text": "Installeer hem eenmalig met claude plugin install figma@claude-plugins-official (Dev Mode MCP vereist een betaald Figma-plan). Dezelfde Figma MCP is beschikbaar voor Claude Code, Codex, Cursor en VS Code — precies het soort draagbare, multi-agent-capaciteit dat Open Design is gebouwd om te orkestreren."}]}, {"id": "vs", "heading": "Claude Code vs Codex vs Cursor voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een andere kracht, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Design-kracht", "Beste voor"], "rows": [["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewust UX-redeneren", "Frontend-redeneren en refactors met grote context"], ["Codex", "Sterke visuele afwerking en beeldbegrip; gesandboxte async builds", "Gedelegeerde async builds en draagbare AGENTS.md-regels"], ["Cursor", "Visuele build-and-see-lus met live preview en inline edits", "Strak itereren-en-bekijken van UI-werk binnen een IDE"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: alle drie vallen zonder skills, referenties en beperkingen terug op een generieke esthetiek. Dat is het echte probleem dat opgelost moet worden — en het heeft de vorm van een design-tool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI slop”-look vermijdt", "blocks": [{"kind": "p", "text": "Zelfs met Claude Code's reputatie voor smaak is de meest voorkomende klacht over AI-gegenereerd design dat het generiek oogt — Inter-lettertypen, paarse gradiënten op wit, zachte schaduwen, te grote afgeronde hoeken, een esthetiek die “schreeuwt dat een AI dit maakte.” Anthropic zelf schrijft dit toe aan distributionele convergentie: veilige keuzes domineren de trainingsdata van het web. Andere gemelde problemen zijn kapotte mobiele layouts en instructies die in de UI-tekst lekken."}, {"kind": "steps", "items": [{"label": "Installeer de Frontend Design-skill", "body": "Hij dwingt Claude zich op een echte richting vast te leggen en vermijdt expliciet lettertypen en gradiënten die door AI worden overgebruikt."}, {"label": "Schakel browserverificatie in", "body": "Laat Claude renderen en zichzelf controleren over breakpoints heen, zodat layouts niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste hefboom op de outputkwaliteit."}, {"label": "Leg regels vast in CLAUDE.md", "body": "Zet stijlregels als “geen hero cards, maximaal twee lettertypen, merk-eerste hiërarchie” daar waar de agent ze elke ronde leest."}]}, {"kind": "p", "text": "Merk op dat elke remedie draait om het geven van een samengestelde designcontext aan de agent. Die context met de hand onderhouden, per project, is precies het sleurwerk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Designen met Claude Code binnen Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de workflow hierboven steeds om vraagt. Het behandelt Claude Code als een first-party adapter en omhult hem met een samengestelde bibliotheek van skills en design systems, een gestructureerde render-pipeline en een lokale desktop-UI — zodat de designcontext die Claude Code goed maakt er vanaf de eerste run is, niet elke keer met de hand samengesteld."}, {"kind": "ol", "items": ["Installeer Open Design en kies Claude Code als je agent.", "Authenticeer met je Anthropic API-key (BYOK) of Claude-abonnement — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een design system en een skill, en genereer vervolgens decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand staat in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Claude Code-agent, dezelfde key — plus een echte, draagbare, open-source design-workflow eromheen. Het is local-first en Apache-2.0, dus niets over je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Is Claude Code goed voor designwerk?", "text": "Ja — hij wordt algemeen beschouwd als de coding-agent met de beste frontend-smaak, die specifieke, codebase-bewuste beslissingen neemt over hex-waarden, spacing en typeschalen. Met de Frontend Design-skill, een design system en echte referentiebeelden in context produceert hij responsieve UI van productiekwaliteit en kan hij die in een browser verifiëren. Zonder die context neigt hij naar een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Heb ik een Claude-abonnement nodig om te designen met Claude Code?", "text": "Je kunt zowel een Anthropic API-key (BYOK, via de Console) als een Claude-abonnement (Pro / Max) gebruiken. Hoe dan ook sluist Open Design je credentials nooit door — ze worden direct gebruikt door je agent op je machine."}, {"name": "Claude Code of Codex voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen en frontend-redeneren; Codex heeft sterke visuele afwerking en blinkt uit in gedelegeerde, gesandboxte builds. Veel teams gebruiken beide — met Open Design wissel je van agent zonder je design-workflow te veranderen."}, {"name": "Hoe verbind ik Claude Code met Figma?", "text": "Installeer de officiële Figma-plugin met claude plugin install figma@claude-plugins-official. Je kunt dan Figma-frames in code implementeren met de designcontext, en een draaiende UI terugduwen naar bewerkbare Figma-frames met “Send this to Figma.” Dev Mode MCP vereist een betaald Figma-plan."}, {"name": "Wat zijn Skills en CLAUDE.md?", "text": "CLAUDE.md is een markdown-bestand in je projectroot dat Claude Code aan het begin van elke sessie leest — de plek om je designconventies vast te leggen. Skills bundelen herbruikbare instructies en resources die Claude op aanvraag laadt, waaronder Anthropics officiële Frontend Design-skill. Open Design levert een samengestelde bibliotheek van beide, zodat je de setup per project overslaat."}, {"name": "Hoe vermijd ik de generieke “AI slop”-esthetiek?", "text": "Installeer de Frontend Design-skill, lever echte design-tokens en referentie-screenshots aan, leg merkregels vast in CLAUDE.md en schakel browserverificatie in. Open Design levert deze als een samengestelde bibliotheek, zodat je de setup per project overslaat."}, {"name": "Is Open Design gelieerd aan Anthropic?", "text": "Nee. Claude Code is een product van Anthropic; Open Design is een onafhankelijk open-source project dat hem ondersteunt als first-party adapter. Claude en Claude Code zijn handelsmerken van Anthropic."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en Apache-2.0. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je Anthropic-credentials worden direct gebruikt door je agent, nooit via Open Design-servers geleid."}], "ctaTitle": "Design met Claude Code, op de open manier.", "ctaBody": "Neem je eigen Anthropic-key of Claude-abonnement mee, houd elk bestand lokaal, en krijg een samengestelde design-bibliotheek rondom de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Claude Code binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex voor design — Open Design",
        description: "Hoe mensen OpenAI Codex gebruiken voor UI- en webdesign — de Product Design-plugin, Figma-integratie, frontend-skills — en hoe Open Design er een local-first, open-source design-agent van maakt.",
        breadcrumb: "Codex",
        label: "Agent · Codex",
        heading: "Codex voor design.",
        lead: "Codex is de coding-agent van OpenAI. Met de Product Design-plugin en Figma-integratie is het een serieuze design-tool geworden. Open Design koppelt Codex aan een open-source design-workflow — je OpenAI-key of ChatGPT-abonnement, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design maakt van Codex een local-first, open-source design-agent — je OpenAI-key, je bestanden, en een samengestelde bibliotheek van skills en design systems eromheen.", "heroCtaActions": [{"label": "Gebruik Codex binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex begon als codegenerator, maar werd in 2026 een geloofwaardige tool voor het ontwerpen van echte interfaces — zodra je hem de juiste referenties, skills en verificatielus geeft. Dit is een praktische, end-to-end gids voor het gebruik van Codex voor UI-, frontend- en design-system-werk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat Codex vandaag is, waarom hij plotseling goed is in frontend, hoe je hem vanaf nul opzet, de screenshot-naar-UI-lus, de officiële Figma-round-trip, hoe hij zich verhoudt tot Cursor en Claude Code, de valkuilen die AI-output generiek doen ogen, en hoe Open Design de kloof dicht als een open, local-first designlaag."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Feedbacklus van Codex-design: terminal-agent, browser die de UI rendert, en een werkruimte, met een feedbackpijl die terugloopt", "caption": "De kernlus: Codex bouwt UI in de terminal, rendert en verifieert die in een echte browser, en itereert tegen je referenties."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-codex", "label": "Wat OpenAI Codex precies is"}, {"id": "why-design", "label": "Waarom Codex nu goed is in design"}, {"id": "setup", "label": "Codex instellen voor design (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De screenshot-naar-UI-workflow"}, {"id": "figma", "label": "Codex + Figma-round-trip"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "Valkuilen en de “AI slop”-look"}, {"id": "open-design", "label": "Designen met Codex in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-codex", "heading": "Wat OpenAI Codex precies is (en wat niet)", "blocks": [{"kind": "p", "text": "Eerst een verduidelijking die bijna iedereen die op “Codex” zoekt op het verkeerde been zet. De oorspronkelijke OpenAI Codex was een code-completion-model uit 2021 dat de vroege GitHub Copilot aandreef en in 2023 werd uitgefaseerd. Daar gaat deze pagina niet over. De Codex van vandaag is de agentic coding-tool van OpenAI — hij plant, schrijft, draait en verifieert code op basis van taken in natuurlijke taal."}, {"kind": "p", "text": "De moderne Codex komt in vier vormen: een terminal-CLI (herschreven in Rust, gelicentieerd onder Apache-2.0), een IDE-extensie voor VS Code, Cursor en Windsurf, een cloud-/web-ervaring voor gedelegeerde async-taken, en een desktop-app met een ingebouwde browser en Computer Use."}, {"kind": "steps", "items": [{"label": "Standaardmodel", "body": "Vanaf medio 2026 is het aanbevolen model gpt-5.5, waarbij gpt-5.4 het model is dat OpenAI expliciet trainde voor frontend en computer use."}, {"label": "Instructiebestand", "body": "Codex leest een AGENTS.md-bestand in je project (een cross-tool-standaard) voor projectregels — de natuurlijke plek om je designconventies vast te leggen."}, {"label": "Sandbox", "body": "Hij draait in een sandbox op kernelniveau (standaard workspace-write), zodat een agent die je UI bewerkt niet buiten het project kan dwalen."}]}, {"kind": "ul", "items": ["Leverancier: OpenAI", "Credential: OpenAI API-key (BYOK) of ChatGPT-abonnement (Free / Go / Plus / Pro / Business / Enterprise)", "Licentie van de CLI: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Waarom Codex nu goed is in design", "blocks": [{"kind": "p", "text": "Begin 2026 kwamen drie dingen samen die van Codex een echte design-tool maakten in plaats van een generieke codegenerator."}, {"kind": "steps", "items": [{"label": "Een frontend-getraind model", "body": "OpenAI leverde GPT-5.4, het eerste mainline-model getraind voor frontend en computer use, met veel beter beeldbegrip over de hele design-workflow en sterkere zelfverificatie. Het kan zelfs mood boards en visuele opties genereren voordat het zich vastlegt op de definitieve assets."}, {"label": "Een officiële frontend-skill", "body": "De openai/skills-catalogus levert een samengestelde frontend-skill die echte smaak afdwingt: cardloze layouts, full-bleed hero's, merk-eerste hiërarchie, ingetogen beweging, hooguit twee lettertypen en één accentkleur — en laat Codex een visuele these schrijven voordat hij bouwt."}, {"label": "Browserverificatie", "body": "Met de Playwright-skill opent Codex een echte browser, herschaalt naar breakpoints en vergelijkt zijn output terug met de referentie in plaats van alleen te controleren of de build slaagt."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Diagram dat laat zien hoe design system, skill en referentiebeeld samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een design system, een skill en echte referentiebeelden."}, {"kind": "p", "text": "De les achter alle drie: Codex heeft standaard geen smaak. Hij levert goed design wanneer je hem beperkingen geeft — een design system, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee samen (meer hieronder)."}]}, {"id": "setup", "heading": "Codex voor designwerk opzetten, vanaf nul", "blocks": [{"kind": "p", "text": "Dit is het volledige pad van een schone machine naar een Codex die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Setupflow in vijf stappen: installeren, authenticeren, configureren, skill installeren, verifiëren", "caption": "De setup-volgorde: installeren → authenticeren → AGENTS.md configureren → de frontend-skill installeren → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Leg je designregels vast", "body": "Zet je tokens, primitives en conventies in AGENTS.md of een DESIGN.md en wijs Codex erop, zodat de output bij een merk past in plaats van terug te vallen op een generieke look."}, {"label": "Kies het juiste reasoning-niveau", "body": "OpenAI merkt op dat laag-tot-gemiddelde reasoning-niveaus vaak sterkere frontend-resultaten opleveren dan de hoogste instelling."}]}]}, {"id": "screenshot-workflow", "heading": "De screenshot-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De design-lus met de meeste hefboomwerking bij Codex is een referentiebeeld omzetten in werkende, responsieve UI en itereren tot het klopt. OpenAI's eigen richtlijnen komen neer op vijf stappen."}, {"kind": "ol", "items": ["Begin met de helderste visuele referenties die je hebt — en neem meerdere states mee (desktop en mobiel, hover, leeg, laden), niet alleen één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op.", "Bereid een design system voor en vertel Codex waar de tokens en canonieke primitives staan.", "Schakel de interactieve Playwright-skill in zodat Codex in een echte browser rendert en naar breakpoints herschaalt.", "Itereer door Codex zijn implementatie terug te laten vergelijken met de screenshots — niet alleen te bevestigen dat het bouwt."]}, {"kind": "p", "text": "Voer beelden in door een screenshot in de terminal te slepen of met de image-flag, en prompt dan met concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Draai een dev-server in een tweede terminal, houd prompts klein en gericht, en commit goede iteraties / draai slechte terug (vertel Codex wanneer je terugdraait) zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "figma", "heading": "Codex + Figma: design ↔ code-round-trip", "blocks": [{"kind": "p", "text": "In februari 2026 kondigden OpenAI en Figma een officieel partnerschap aan, waarmee de eerdere Figma MCP-bèta een eersteklas, bidirectionele integratie werd. Hij werkt in beide richtingen."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Kopieer de “link to selection” van een frame in Figma, plak die in Codex met get_design_context en vraag hem het design te implementeren met je bestaande componentbibliotheek."}, {"label": "Code → Design", "body": "De generate_figma_design-tool (“Code to Canvas”) zet een live, draaiende UI terug om in bewerkbare Figma-frames — het hele scherm, een geselecteerd element of een heel bestand."}]}, {"kind": "p", "text": "De Figma MCP draait als een remote server en is vrijgesteld van rate limits. Voeg hem eenmalig toe en hij is beschikbaar voor Codex, Claude Code, Cursor, VS Code en meer — precies het soort draagbare, multi-agent-capaciteit dat Open Design is gebouwd om te orkestreren."}]}, {"id": "vs", "heading": "Codex vs Cursor vs Claude Code voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een andere kracht, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Design-kracht", "Beste voor"], "rows": [["Codex", "Sterke visuele afwerking na GPT-5.4 + frontend-skill; beeldbegrip", "Gedelegeerde async builds, gesandboxte runs, draagbare AGENTS.md-regels"], ["Cursor", "Visuele build-and-see-lus met live preview en inline edits", "Strak itereren-en-bekijken van UI-werk binnen een IDE"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redeneren en refactors met grote context"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: alle drie vallen zonder skills, referenties en beperkingen terug op een generieke esthetiek. Dat is het echte probleem dat opgelost moet worden — en het heeft de vorm van een design-tool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over door Codex gegenereerd design is dat het generiek oogt — zachte gradiënten, zwevende panelen, te grote afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit maakte.” Andere gemelde problemen zijn kapotte mobiele layouts, instructies die in de UI-tekst lekken en het snel bereiken van gebruikslimieten."}, {"kind": "steps", "items": [{"label": "Installeer een frontend-skill", "body": "Een samengestelde esthetische skill dwingt Codex zich op een echte richting vast te leggen in plaats van de standaard look."}, {"label": "Schakel Playwright-verificatie in", "body": "Laat Codex renderen en zichzelf controleren over breakpoints heen, zodat layouts niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste hefboom op de outputkwaliteit."}, {"label": "Leg regels vast in AGENTS.md", "body": "Zet stijlregels als “geen hero cards, maximaal twee lettertypen, merk-eerste hiërarchie” daar waar de agent ze elke ronde leest."}]}, {"kind": "p", "text": "Merk op dat elke remedie draait om het geven van een samengestelde designcontext aan de agent. Die context met de hand onderhouden, per project, is precies het sleurwerk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Designen met Codex binnen Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de workflow hierboven steeds om vraagt. Het behandelt Codex als een first-party adapter en omhult hem met een samengestelde bibliotheek van skills en design systems, een gestructureerde render-pipeline en een lokale desktop-UI — zodat de designcontext die Codex goed maakt er vanaf de eerste run is, niet elke keer met de hand samengesteld."}, {"kind": "ol", "items": ["Installeer Open Design en kies Codex als je agent.", "Authenticeer met je OpenAI API-key (BYOK) of ChatGPT-abonnement — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een design system en een skill, en genereer vervolgens decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand staat in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Codex-agent, dezelfde key — plus een echte, draagbare, open-source design-workflow eromheen. Het is local-first en Apache-2.0, dus niets over je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan OpenAI Codex echt designwerk doen?", "text": "Ja — met een frontend-skill, een design system en echte referentiebeelden in context produceert Codex (zeker op GPT-5.4) responsieve UI van productiekwaliteit en kan hij die in een browser verifiëren. Zonder die context neigt hij naar een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Is dit de OpenAI Codex Product Design-plugin?", "text": "Nee. Open Design is een onafhankelijk open-source project dat Codex integreert als agent. Het vult OpenAI's eigen tooling aan met een local-first, open bibliotheek van skills en design systems."}, {"name": "Heb ik een ChatGPT-abonnement nodig om te designen met Codex?", "text": "Je kunt zowel een OpenAI API-key (BYOK) als je ChatGPT-abonnement gebruiken. Inloggen met ChatGPT geeft doorgaans ruimere limieten; Open Design sluist je credentials hoe dan ook nooit door."}, {"name": "Codex of Claude Code voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen; Codex heeft sterke visuele afwerking na GPT-5.4 en blinkt uit in gedelegeerde, gesandboxte builds. Veel teams gebruiken beide — met Open Design wissel je van agent zonder je design-workflow te veranderen."}, {"name": "Hoe verbind ik Codex met Figma?", "text": "Voeg de officiële Figma MCP-server toe (codex mcp add figma --url https://mcp.figma.com/mcp). Je kunt dan Figma-frames in code implementeren met get_design_context en een draaiende UI terugduwen naar bewerkbare Figma-frames met generate_figma_design."}, {"name": "Hoe vermijd ik de generieke “AI slop”-esthetiek?", "text": "Installeer een frontend-skill, lever echte design-tokens en referentie-screenshots aan, leg merkregels vast in AGENTS.md en schakel Playwright-verificatie in. Open Design levert deze als een samengestelde bibliotheek, zodat je de setup per project overslaat."}, {"name": "Is Open Design gelieerd aan OpenAI?", "text": "Nee. Codex is een product van OpenAI; Open Design is een onafhankelijk open-source project dat hem ondersteunt als first-party adapter. OpenAI en Codex zijn handelsmerken van OpenAI."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je OpenAI-credentials worden direct gebruikt door je agent, nooit via Open Design-servers geleid."}], "ctaTitle": "Design met Codex, op de open manier.", "ctaBody": "Neem je eigen OpenAI-key mee, houd elk bestand lokaal, en krijg een samengestelde design-bibliotheek rondom de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Codex binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor voor designers — Open Design",
        description: "Hoe designers Cursor gebruiken voor UI- en webdesign — Design Mode, Figma-naar-code, de Figma MCP — en hoe Open Design er een local-first, open-source design-agent van maakt.",
        breadcrumb: "Cursor",
        label: "Agent · Cursor",
        heading: "Cursor voor designers.",
        lead: "Cursor is de AI-code-editor, nu met een visuele Design Mode. Designers gebruiken hem om UI te bewerken door aan te wijzen en te tekenen, en om Figma in code om te zetten. Open Design koppelt Cursor Agent aan een open-source design-workflow die je bestanden lokaal houdt.",
        rich: {"heroCtaLead": "Open Design maakt van Cursor een local-first, open-source design-agent — je Cursor-account of model-keys, je bestanden, en een samengestelde bibliotheek van skills en design systems eromheen.", "heroCtaActions": [{"label": "Gebruik Cursor binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor is de AI-first code-editor die van “bouw het en zie het renderen” de standaardmanier maakte om UI te leveren. Met Agent-mode, inline edits, een preview in de editor en Figma via MCP is het een echte design-tool geworden — zodra je hem de juiste referenties, regels en een verificatielus geeft. Dit is een praktische, end-to-end gids voor het gebruik van Cursor voor UI-, frontend- en design-system-werk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat Cursor precies is, waarom zijn strakke itereren-en-bekijken-lus goed is voor design, hoe je hem vanaf nul opzet, de screenshot-en-preview-naar-UI-lus, de Figma-round-trip via MCP, hoe hij zich verhoudt tot Codex en Claude Code, de valkuilen die AI-output generiek doen ogen, en hoe Open Design de kloof dicht als een open, local-first designlaag."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Cursor-design-convergentie: editor links, een samengestelde hub met skills en design systems in het midden met het Cursor-merk centraal, en een gerenderde UI rechts", "caption": "Het kernidee: Cursor bewerkt en rendert UI in de editor, terwijl een samengestelde design-hub hem het system, de skills en de referenties voedt die de output intentioneel doen ogen."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-cursor", "label": "Wat Cursor precies is"}, {"id": "why-design", "label": "Waarom Cursor goed is in design"}, {"id": "setup", "label": "Cursor instellen voor design (vanaf nul)"}, {"id": "preview-workflow", "label": "De preview-naar-UI-workflow"}, {"id": "figma", "label": "Cursor + Figma via MCP"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "Valkuilen en de “AI slop”-look"}, {"id": "open-design", "label": "Designen met Cursor in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-cursor", "heading": "Wat Cursor precies is", "blocks": [{"kind": "p", "text": "Cursor is een AI-first code-editor gebouwd door Anysphere. Het is een fork van VS Code, dus de vertrouwde editor, extensies en keybindings blijven behouden, maar de workflow is heropgebouwd rond een AI-agent die je hele project kan lezen, meerdere bestanden kan bewerken, commando's kan uitvoeren en met jou in de lus kan itereren."}, {"kind": "p", "text": "Voor designwerk zijn de belangrijke vormen Agent-mode (je beschrijft een uitkomst en Cursor plant en bewerkt over bestanden heen), inline edits en Tab-completions voor snelle aanpassingen, een preview / browser in de editor zodat je de draaiende UI ziet zonder het venster te verlaten, en MCP-ondersteuning waarmee hij externe context kan binnenhalen, zoals een live Figma-bestand."}, {"kind": "steps", "items": [{"label": "Project-regels", "body": "Cursor leest project-instructiebestanden — geversioneerde `.mdc`-regels onder `.cursor/rules`, en een gewone `AGENTS.md` — zodat je je designconventies kunt vastleggen waar de agent ze elke ronde leest."}, {"label": "Modellen", "body": "Cursor is model-flexibel: hij wordt geleverd met frontier-modellen via je abonnement en ondersteunt ook het meebrengen van je eigen model-keys, zodat je de engine achter dezelfde editor-workflow kiest."}, {"label": "MCP", "body": "Hij spreekt het Model Context Protocol, zodat externe servers — meest relevant de Figma MCP-server — eersteklas context worden voor de agent."}]}, {"kind": "ul", "items": ["Leverancier: Anysphere", "Credential: Cursor-account / -abonnement (Hobby / Pro / Business) of je eigen model-keys (BYOK)", "Vorm: AI-first code-editor (VS Code-fork) met een agent en preview in de editor"]}]}, {"id": "why-design", "heading": "Waarom Cursor goed is in design", "blocks": [{"kind": "p", "text": "Cursors design-voorsprong is geen enkele feature — het is de strakheid van de build-and-see-lus. Drie dingen laten het aanvoelen als een design-tool in plaats van een generieke codegenerator."}, {"kind": "steps", "items": [{"label": "Een strakke itereren-en-bekijken-lus", "body": "Je prompt, Cursor bewerkt over bestanden heen, en de preview in de editor rendert het resultaat meteen — zodat je spacing, hiërarchie en beweging in seconden aanpast in plaats van heen en weer te gaan tussen een aparte terminal en browser."}, {"label": "Direct visueel bewerken", "body": "Naast chat laat Cursor je elementen in de preview selecteren en stijlen bijstellen, zodat kleine visuele correcties aanvoelen als design-edits in plaats van code-archeologie."}, {"label": "Project-regels en MCP-context", "body": "Met `.cursor/rules` (of `AGENTS.md`) en de Figma MCP-server werkt de agent tegen je tokens, componenten en echte design-specs in plaats van te gokken."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Diagram dat laat zien hoe design system, skill en referentiebeeld samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een design system, een skill en echte referentiebeelden."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: Cursor heeft standaard geen smaak. Hij levert goed design wanneer je hem beperkingen geeft — een design system, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee samen (meer hieronder)."}]}, {"id": "setup", "heading": "Cursor voor designwerk opzetten, vanaf nul", "blocks": [{"kind": "p", "text": "Dit is het volledige pad van een schone machine naar een Cursor die UI kan bouwen, previewen en verifiëren tegen je design system."}, {"kind": "ol", "items": ["Installeer Cursor vanaf cursor.com en log in met je Cursor-account, of configureer je eigen model-keys (BYOK) in Settings.", "Open je project en kies een model in het chat- / Agent-paneel.", "Voeg project-regels toe: maak `.cursor/rules/*.mdc` voor gestructureerde, glob-scoped conventies, of een gewone `AGENTS.md` voor eenvoudige, leesbare instructies.", "Verbind de Figma MCP-server (optioneel) zodat de agent live designcontext kan lezen.", "Draai je dev-server en gebruik de preview in de editor om de UI te zien en te verifiëren terwijl je itereert."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Setupflow in vijf stappen: installeren, authenticeren, regels configureren, skill toevoegen, verifiëren", "caption": "De setup-volgorde: installeren → authenticeren → project-regels configureren → een skill toevoegen → preview-verificatie inschakelen."}, {"kind": "p", "text": "Een minimaal project-regelbestand laat de agent designen naar een merk in plaats van terug te vallen op een generieke look. Zet het waar Cursor het elke ronde leest:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Leg je designregels vast", "body": "Zet je tokens, primitives en conventies in `.cursor/rules` of `AGENTS.md` en wijs Cursor erop, zodat de output bij een merk past in plaats van terug te vallen op een generieke look."}, {"label": "Houd prompts klein", "body": "Cursors strakke lus beloont gerichte vragen — itereer één component of state tegelijk en bekijk de preview tussen de rondes."}]}]}, {"id": "preview-workflow", "heading": "De preview-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De design-lus met de meeste hefboomwerking bij Cursor is een referentie omzetten in werkende, responsieve UI en in de editor itereren tot het klopt — terwijl je de hele tijd naar de live preview kijkt in plaats van te gokken."}, {"kind": "ol", "items": ["Begin met de helderste visuele referenties die je hebt — en neem meerdere states mee (desktop en mobiel, hover, leeg, laden), niet alleen één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op.", "Bereid een design system voor en vertel Cursor waar de tokens en canonieke primitives staan.", "Houd de preview in de editor open en je dev-server draaiend zodat elke edit meteen rendert op de breakpoints die voor jou belangrijk zijn.", "Itereer door de gerenderde UI terug te vergelijken met de referenties — en gebruik directe elementselectie in de preview voor kleine visuele correcties."]}, {"kind": "p", "text": "Voer referenties in door een beeld aan de chat te koppelen en prompt dan met concrete beperkingen:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Commit goede iteraties en draai slechte terug (vertel Cursor wanneer je terugdraait) zodat elke ronde voortbouwt op een schone basis — dezelfde discipline die elke agent-lus tegen afdrijven beschermt."}]}, {"id": "figma", "heading": "Cursor + Figma: design ↔ code via MCP", "blocks": [{"kind": "p", "text": "Cursor verbindt met Figma via de officiële Figma MCP-server, die de agent gestructureerde toegang geeft tot een live Figma-bestand in plaats van een platte screenshot. Dat haalt het giswerk uit de handoff."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Kopieer de link van een frame in Figma, plak die in Cursor en vraag hem het design te implementeren. De MCP-server stelt echte designcontext beschikbaar — componenten, variabelen, layout-data, tokens — zodat de gegenereerde code de bron evenaart in plaats van benadert."}, {"label": "Blijf uitgelijnd", "body": "Met design-tokens, stijlen en componenten consistent gebruikt in Figma (en Code Connect waar beschikbaar) blijft Cursors output gekoppeld aan je echte design system in plaats van primitives opnieuw uit te vinden."}]}, {"kind": "p", "text": "Stel de remote Figma MCP-server eenmalig in en hij is beschikbaar voor Cursor als eersteklas context. Omdat MCP een open standaard is, is dezelfde server herbruikbaar over Cursor, Claude Code, Codex en VS Code — precies het soort draagbare, multi-agent-capaciteit dat Open Design is gebouwd om te orkestreren."}]}, {"id": "vs", "heading": "Cursor vs Codex vs Claude Code voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een andere kracht, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Design-kracht", "Beste voor"], "rows": [["Cursor", "Visuele build-and-see-lus met live preview in de editor en direct elementen bewerken", "Strak itereren-en-bekijken van UI-werk binnen een IDE"], ["Codex", "Sterke visuele afwerking met een frontend-skill; beeldbegrip en gesandboxte runs", "Gedelegeerde async builds en draagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redeneren en refactors met grote context"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: alle drie vallen zonder skills, referenties en beperkingen terug op een generieke esthetiek. Dat is het echte probleem dat opgelost moet worden — en het heeft de vorm van een design-tool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over door Cursor gegenereerd design is dat het generiek oogt — zachte gradiënten, zwevende panelen, te grote afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit maakte.” Andere gemelde problemen zijn layouts die breken op mobiel en instructies die in de UI-tekst lekken."}, {"kind": "steps", "items": [{"label": "Voeg een design-skill toe", "body": "Een samengestelde esthetische skill dwingt Cursor zich op een echte richting vast te leggen in plaats van de standaard look."}, {"label": "Gebruik de preview om te verifiëren", "body": "Render en controleer jezelf over breakpoints heen in de preview in de editor, zodat layouts niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste hefboom op de outputkwaliteit."}, {"label": "Leg regels vast in `.cursor/rules`", "body": "Zet stijlregels als “geen hero cards, maximaal twee lettertypen, merk-eerste hiërarchie” daar waar de agent ze elke ronde leest."}]}, {"kind": "p", "text": "Merk op dat elke remedie draait om het geven van een samengestelde designcontext aan de agent. Die context met de hand onderhouden, per project, is precies het sleurwerk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Designen met Cursor binnen Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de workflow hierboven steeds om vraagt. Het behandelt Cursor als een first-party adapter en omhult hem met een samengestelde bibliotheek van skills en design systems, een gestructureerde render-pipeline en een lokale desktop-UI — zodat de designcontext die Cursor goed maakt er vanaf de eerste run is, niet elke keer met de hand samengesteld."}, {"kind": "ol", "items": ["Installeer Open Design en kies Cursor als je agent.", "Authenticeer met je Cursor-account of je eigen model-keys (BYOK) — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een design system en een skill, en genereer vervolgens decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand staat in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Cursor-agent, dezelfde key — plus een echte, draagbare, open-source design-workflow eromheen. Het is local-first en Apache-2.0, dus niets over je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan Cursor echt designwerk doen?", "text": "Ja — met een design-skill, een design system en echte referentiebeelden in context produceert Cursor responsieve UI van productiekwaliteit, en met de preview in de editor kun je die visueel verifiëren en verfijnen. Zonder die context neigt hij naar een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Is dit een officieel Cursor-product?", "text": "Nee. Open Design is een onafhankelijk open-source project dat Cursor integreert als agent. Het vult Cursor aan met een local-first, open bibliotheek van skills en design systems."}, {"name": "Heb ik een Cursor-abonnement nodig om te designen met Cursor?", "text": "Je kunt een Cursor-account / -abonnement gebruiken of je eigen model-keys meebrengen (BYOK). Open Design sluist je credentials hoe dan ook nooit door — ze worden direct gebruikt door je agent."}, {"name": "Cursor of Claude Code voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen; Cursors voorsprong is zijn strakke build-and-see-lus met een live preview in de editor. Veel teams gebruiken beide — met Open Design wissel je van agent zonder je design-workflow te veranderen."}, {"name": "Hoe verbind ik Cursor met Figma?", "text": "Voeg de officiële Figma MCP-server toe in Cursor, plak dan een Figma-frame-link in de chat en vraag Cursor die te implementeren. De server stelt echte componenten, variabelen en layout-data beschikbaar zodat de gegenereerde code het brondesign evenaart."}, {"name": "Hoe vermijd ik de generieke “AI slop”-esthetiek?", "text": "Voeg een design-skill toe, lever echte design-tokens en referentie-screenshots aan, leg merkregels vast in `.cursor/rules` of `AGENTS.md`, en verifieer over breakpoints heen in de preview. Open Design levert deze als een samengestelde bibliotheek, zodat je de setup per project overslaat."}, {"name": "Is Open Design gelieerd aan Cursor of Anysphere?", "text": "Nee. Cursor is een product van Anysphere; Open Design is een onafhankelijk open-source project dat hem ondersteunt als first-party adapter. Cursor en Anysphere zijn handelsmerken van Anysphere, Inc."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je Cursor- of model-credentials worden direct gebruikt door je agent, nooit via Open Design-servers geleid."}], "ctaTitle": "Design met Cursor, op de open manier.", "ctaBody": "Neem je eigen Cursor-account of model-keys mee, houd elk bestand lokaal, en krijg een samengestelde design-bibliotheek rondom de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Cursor binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode voor design — Open Design",
        description: "Hoe mensen OpenCode gebruiken voor UI- en webdesign — design.md-bestanden, UI/UX-skills, Figma MCP — en hoe Open Design er een local-first, open-source design-agent van maakt.",
        breadcrumb: "OpenCode",
        label: "Agent · OpenCode",
        heading: "OpenCode voor design.",
        lead: "OpenCode is de open-source terminal-AI-coding-agent. Designers schroeven er design-skills en DESIGN.md-bestanden op om echte UI te genereren. Open Design maakt daar een gestructureerde, open-source workflow van — neem je provider-keys mee en houd alles lokaal.",
        rich: {"heroCtaLead": "Open Design maakt van OpenCode een local-first, open-source design-agent — elk model dat je kiest met je eigen provider-key, je bestanden, en een samengestelde bibliotheek van skills en design systems eromheen.", "heroCtaActions": [{"label": "Gebruik OpenCode binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode is een open-source, terminal-first AI-coding-agent die bewust modelonafhankelijk is: je neemt je eigen provider-key mee en draait welk model je maar wilt achter dezelfde workflow. Die openheid maakt hem een natuurlijke basis voor designwerk — maar zoals elke agent levert hij alleen goede UI wanneer je hem de juiste referenties, skills en een verificatielus geeft. Dit is een praktische, end-to-end gids voor het gebruik van OpenCode voor UI-, frontend- en design-system-werk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat OpenCode precies is, waarom een modelonafhankelijke open agent goed past bij design, hoe je hem vanaf nul opzet, de screenshot-naar-UI-lus, hoe AGENTS.md en MCP hem uitbreiden, hoe hij zich verhoudt tot Codex, Claude Code en Cursor, de valkuilen die AI-output generiek doen ogen, en hoe Open Design de kloof dicht als een open, local-first designlaag — een natuurlijke combinatie, want beide projecten zijn open-source en draaien op je eigen machine."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Feedbacklus van OpenCode-design: een terminal-TUI-agent, een browser die de UI rendert, en een werkruimte, met een feedbackpijl die terugloopt", "caption": "De kernlus: OpenCode bouwt UI in de terminal, rendert en verifieert die in een echte browser, en itereert tegen je referenties — op welk model je ook kiest."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-opencode", "label": "Wat OpenCode precies is"}, {"id": "why-design", "label": "Waarom een open, elk-model-agent past bij design"}, {"id": "setup", "label": "OpenCode instellen voor design (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De screenshot-naar-UI-workflow"}, {"id": "extend", "label": "AGENTS.md, MCP en deelbare sessies"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Valkuilen en de “AI slop”-look"}, {"id": "open-design", "label": "Designen met OpenCode in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-opencode", "heading": "Wat OpenCode precies is", "blocks": [{"kind": "p", "text": "OpenCode is een open-source AI-coding-agent gebouwd voor de terminal, onderhouden door het team achter SST (Anomaly Innovations). Hij leest je repository, voert commando's uit, bewerkt bestanden en praat met een large language model — maar anders dan leverancier-gebonden agents levert hij geen eigen model. Je richt hem op welke provider en welk model je maar wilt en neemt je eigen key mee."}, {"kind": "p", "text": "Hij draait als een terminal-UI (TUI), met een desktop-app en IDE-extensies bovenop dezelfde engine. Onder de motorkap gebruikt hij een client/server-architectuur, zodat de agent die het werk doet losgekoppeld is van de vorm waarmee je hem aanstuurt. Twee ingebouwde agents — build en plan — wissel je met de Tab-toets."}, {"kind": "steps", "items": [{"label": "Modelonafhankelijk", "body": "Modellen en providers komen van models.dev, een open catalogus. Je configureert ze in opencode.json met een provider/model-id-string en kunt providers die je niet geladen wilt hebben uitschakelen — zodat dezelfde design-workflow draait op Anthropic, OpenAI, Google, OpenRouter, lokale modellen en meer."}, {"label": "Instructiebestand", "body": "OpenCode leest een AGENTS.md-bestand in je project (de cross-tool-standaard, ook compatibel met CLAUDE.md) voor projectregels — de natuurlijke plek om je designconventies vast te leggen. Draai /init om er een te genereren."}, {"label": "Uitbreidbaar", "body": "Hij ondersteunt LSP-integratie, MCP-servers, thema's, keybinds en custom commando's, plus deelbare sessielinks voor samenwerking."}]}, {"kind": "ul", "items": ["Maintainer: SST / Anomaly Innovations (open-source project)", "Credential: je eigen API-key(s) voor model-providers — BYOK, geen vendor lock-in", "Licentie: MIT, open source"]}]}, {"id": "why-design", "heading": "Waarom een open, elk-model-agent past bij designwerk", "blocks": [{"kind": "p", "text": "OpenCode heeft geen enkel “design-model” zoals een leverancier-agent dat heeft — en dat is precies het punt. Omdat hij modelonafhankelijk en open is, kun je dezelfde design-workflow draaien op welk model op dit moment het best is in frontend, hem later vervangen, of terugvallen op een lokaal model, allemaal zonder je setup te veranderen."}, {"kind": "p", "text": "Maar modelkeuze alleen koopt geen smaak. Zoals elke coding-agent produceert OpenCode generieke UI tenzij je hem beperkingen geeft. Goede design-output komt voort uit drie inputs die jij aanlevert."}, {"kind": "steps", "items": [{"label": "Een design system", "body": "Echte tokens, primitives en conventies die de agent hergebruikt, zodat de output bij een merk past in plaats van terug te vallen op een generieke look."}, {"label": "Een esthetische skill", "body": "Een samengestelde skill die echte smaak afdwingt — ingetogen beweging, merk-eerste hiërarchie, hooguit twee lettertypen en één accentkleur — en de agent zich op een richting laat vastleggen voordat hij bouwt."}, {"label": "Concrete referenties", "body": "Echte referentiebeelden en meerdere states (desktop en mobiel, hover, leeg, laden), niet één enkele hero-shot."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Diagram dat laat zien hoe design system, skill en referentiebeeld samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een design system, een skill en echte referentiebeelden — onafhankelijk van welk model je draait."}, {"kind": "p", "text": "De les: OpenCode geeft je modelvrijheid, maar smaak komt nog steeds voort uit een samengestelde designcontext. Open Design verpakt precies die inputs, en daarom passen de twee samen — beide zijn open-source en local-first (meer hieronder)."}]}, {"id": "setup", "heading": "OpenCode voor designwerk opzetten, vanaf nul", "blocks": [{"kind": "p", "text": "Dit is het volledige pad van een schone machine naar een OpenCode die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Setupflow in vijf stappen: installeren, authenticeren met je provider-key, AGENTS.md configureren, een skill toevoegen, verifiëren", "caption": "De setup-volgorde: installeren → authenticeren (je provider-key) → AGENTS.md configureren → een skill toevoegen → verifiëren in een echte browser."}, {"kind": "steps", "items": [{"label": "Leg je designregels vast", "body": "Zet je tokens, primitives en conventies in AGENTS.md (of een DESIGN.md die daaruit wordt aangehaald) zodat de output bij een merk past in plaats van terug te vallen op een generieke look. De instructions-optie in opencode.json kan via globs naar extra regelbestanden verwijzen."}, {"label": "Kies een capabel model", "body": "Omdat OpenCode modelonafhankelijk is, kies je welke provider/model op dit moment het sterkst is in frontend voor de design-ronde — en houd je de rest van je workflow onveranderd."}]}]}, {"id": "screenshot-workflow", "heading": "De screenshot-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De design-lus met de meeste hefboomwerking bij elke agent is een referentiebeeld omzetten in werkende, responsieve UI en itereren tot het klopt. Dezelfde vijfstappenvorm geldt in OpenCode."}, {"kind": "ol", "items": ["Begin met de helderste visuele referenties die je hebt — en neem meerdere states mee (desktop en mobiel, hover, leeg, laden), niet alleen één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op.", "Bereid een design system voor en vertel OpenCode waar de tokens en canonieke primitives staan (in AGENTS.md).", "Draai een dev-server en laat de agent in een echte browser renderen, met herschaling naar breakpoints om het resultaat te controleren.", "Itereer door OpenCode zijn implementatie terug te laten vergelijken met de screenshots — niet alleen te bevestigen dat het bouwt."]}, {"kind": "p", "text": "Verwijs naar bestanden met @ in de TUI voor een fuzzy-zoekopdracht in je werkmap, voer shell-commando's inline uit met een voorafgaande !, en stuur acties aan met /-commando's. Prompt dan met concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Houd prompts klein en gericht, commit goede iteraties en draai slechte terug (vertel OpenCode wanneer je terugdraait), zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "extend", "heading": "AGENTS.md, MCP en deelbare sessies", "blocks": [{"kind": "p", "text": "Drie uitbreidingspunten maken OpenCode praktisch voor langdurig designwerk, en alle drie sluiten naadloos aan op een open design-workflow."}, {"kind": "steps", "items": [{"label": "AGENTS.md-regels", "body": "Projectregels staan in een AGENTS.md in de repo-root (of globale regels in ~/.config/opencode/AGENTS.md). Het is de duurzame thuisbasis voor je designconventies, gelezen bij elke ronde, en compatibel met de CLAUDE.md-bestanden die andere agents gebruiken."}, {"label": "MCP-servers", "body": "OpenCode ondersteunt zowel lokale (command) als remote (URL) MCP-servers, geconfigureerd onder de mcp-sleutel — de draagbare manier om designcontext en externe tools binnen te halen die over agents heen werken, niet alleen in OpenCode."}, {"label": "Deelbare sessies", "body": "Het /share-commando maakt een publieke link naar een gesprek voor samenwerking of review, en /unshare trekt die in — handig om feedback te krijgen op een design-ronde."}]}, {"kind": "p", "text": "Dit zijn draagbare, multi-agent-capaciteiten — precies het soort dingen die Open Design is gebouwd om te orkestreren, in plaats van per project opnieuw te creëren."}]}, {"id": "vs", "heading": "OpenCode vs Codex vs Claude Code vs Cursor voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een andere kracht, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Design-kracht", "Beste voor"], "rows": [["OpenCode", "Open-source en modelonafhankelijk; draai elke provider achter één terminal-workflow", "BYOK-vrijheid, modellen wisselen, volledig open en local-first setups"], ["Codex", "Sterke visuele afwerking met een frontend-skill; beeldbegrip", "Gedelegeerd async, gesandboxte builds, draagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redeneren en refactors met grote context"], ["Cursor", "Visuele build-and-see-lus met live preview en inline edits", "Strak itereren-en-bekijken van UI-werk binnen een IDE"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: ze vallen allemaal zonder skills, referenties en beperkingen terug op een generieke esthetiek. Dat is het echte probleem dat opgelost moet worden — en het heeft de vorm van een design-tool, niet van een model, en precies daarom past een open agent als OpenCode zo goed bij een open designlaag."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over AI-gegenereerd design is dat het generiek oogt — zachte gradiënten, zwevende panelen, te grote afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit maakte.” Andere gemelde problemen zijn kapotte mobiele layouts en instructies die in de UI-tekst lekken. Geen van deze is uniek voor OpenCode; ze zijn wat er gebeurt wanneer welke agent dan ook draait zonder een samengestelde designcontext."}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een samengestelde design-skill dwingt de agent zich op een echte richting vast te leggen in plaats van de standaard look."}, {"label": "Verifieer in een echte browser", "body": "Render en controleer jezelf over breakpoints heen, zodat layouts niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste hefboom op de outputkwaliteit."}, {"label": "Leg regels vast in AGENTS.md", "body": "Zet stijlregels als “geen hero cards, maximaal twee lettertypen, merk-eerste hiërarchie” daar waar de agent ze elke ronde leest."}]}, {"kind": "p", "text": "Merk op dat elke remedie draait om het geven van een samengestelde designcontext aan de agent — ongeacht welk model je draait. Die context met de hand onderhouden, per project, is precies het sleurwerk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Designen met OpenCode binnen Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de workflow hierboven steeds om vraagt. Het behandelt OpenCode als een first-party adapter en omhult hem met een samengestelde bibliotheek van skills en design systems, een gestructureerde render-pipeline en een lokale desktop-UI — zodat de designcontext die elke agent goed maakt er vanaf de eerste run is, niet elke keer met de hand samengesteld. Beide projecten zijn open-source en local-first, wat de combinatie een natuurlijke match maakt."}, {"kind": "ol", "items": ["Installeer Open Design en kies OpenCode als je agent.", "Authenticeer met je eigen API-key voor model-providers (BYOK) — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een willekeurige provider en model, plus een design system en een skill, en genereer vervolgens decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand staat in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde OpenCode-agent, dezelfde modelvrijheid — plus een echte, draagbare, open-source design-workflow eromheen. Het is local-first en Apache-2.0, dus niets over je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan OpenCode echt designwerk doen?", "text": "Ja — met een esthetische skill, een design system en echte referentiebeelden in context produceert OpenCode responsieve UI van productiekwaliteit en kan hij die in een browser verifiëren. Omdat hij modelonafhankelijk is, draai je welk model op dit moment het best is in frontend. Zonder die samengestelde context neigt hij naar een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Welk model moet ik gebruiken met OpenCode voor design?", "text": "Welk je maar wilt — OpenCode is provider-onafhankelijk via models.dev, dus je kunt Anthropic, OpenAI, Google, OpenRouter of lokale modellen achter dezelfde workflow draaien en op elk moment wisselen. De kwaliteit van de design-output hangt veel meer af van je skill, design system en referenties dan van het model alleen."}, {"name": "Is Open Design gemaakt door het OpenCode-team (SST)?", "text": "Nee. Open Design is een onafhankelijk open-source project dat OpenCode integreert als agent. Het vult OpenCode aan met een local-first, open bibliotheek van skills en design systems."}, {"name": "Heb ik een speciaal abonnement nodig om te designen met OpenCode?", "text": "Nee — OpenCode is BYOK. Je neemt je eigen API-key voor model-providers mee, en Open Design sluist je credentials nooit door. Er is geen vendor lock-in."}, {"name": "OpenCode of Codex of Claude Code voor frontend-design?", "text": "Alle zijn sterk, en veel teams stapelen ze. OpenCode's voorsprong is dat hij volledig open-source en modelonafhankelijk is; Codex blinkt uit in gedelegeerde, gesandboxte builds; Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen. Met Open Design wissel je van agent zonder je design-workflow te veranderen."}, {"name": "Hoe breid ik OpenCode uit voor designcontext?", "text": "Leg regels vast in AGENTS.md, voeg MCP-servers toe onder de mcp-sleutel voor draagbare tools en designcontext, en gebruik deelbare sessies voor review. Open Design levert een samengestelde bibliotheek van skills en design systems zodat je de setup per project overslaat."}, {"name": "Is Open Design gelieerd aan OpenCode of SST?", "text": "Nee. OpenCode is een open-source project onderhouden door SST (Anomaly Innovations); Open Design is een onafhankelijk open-source project dat hem ondersteunt als first-party adapter."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je credentials voor model-providers worden direct gebruikt door je agent, nooit via Open Design-servers geleid."}], "ctaTitle": "Design met OpenCode, op de open manier.", "ctaBody": "Neem je eigen key voor model-providers mee, houd elk bestand lokaal, en krijg een samengestelde design-bibliotheek rondom de open agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik OpenCode binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
    },
    'ar': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code للتصميم — Open Design",
        description: "كيف يستخدم المصممون Claude Code في تصميم الواجهات والويب، وكيف يحوّله Open Design إلى وكيل تصميم حقيقي — محلي أولًا، بمبدأ BYOK، مع مكتبة منسّقة من الـ skills وأنظمة التصميم.",
        breadcrumb: "Claude Code",
        label: "وكيل · Claude Code",
        heading: "Claude Code للتصميم.",
        lead: "‏Claude Code هو وكيل البرمجة الطرفي من Anthropic. يستخدمه الناس بالفعل لبناء الواجهات وأنظمة التصميم وصفحات الهبوط. يربطه Open Design بسير عمل تصميمي حقيقي — أحضر مفتاح Anthropic أو اشتراك Claude، واحتفظ بكل ملف محليًا.",
        rich: {"heroCtaLead": "يحوّل Open Design الأداة Claude Code إلى وكيل تصميم محلي أولًا ومفتوح المصدر — مفتاح Anthropic أو اشتراك Claude الخاص بك، وملفاتك، ومكتبة منسّقة من الـ skills وأنظمة التصميم تحيط بها.", "heroCtaActions": [{"label": "استخدم Claude Code داخل Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "ضع نجمة على GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "نزّل تطبيق سطح المكتب", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["يُعدّ Claude Code على نطاق واسع وكيل البرمجة صاحب الذوق الأفضل في عمل الواجهات الأمامية — فهو يحلّل الواجهات بدقة غير معتادة، ويسمّي قيم hex بالضبط والمسافات وسلالم الخطوط، ويعيد هيكلة الواجهة عبر قاعدة شيفرة كبيرة دون أن يفقد الخيط. لكنه افتراضيًا يظل ينحرف نحو مظهر عام ما لم تزوّده بنظام تصميم وskills ومراجع حقيقية. هذا دليل عملي وشامل لاستخدام Claude Code في عمل الواجهات والواجهة الأمامية وأنظمة التصميم، ولربطه بسير عمل منظّم عبر Open Design.", "يغطّي ما هو Claude Code فعلًا، ولماذا هو قوي في الواجهة الأمامية، وكيف تعدّه من الصفر، وسير عمل CLAUDE.md والـ Skills، والتكامل الرسمي ثنائي الاتجاه مع Figma، وكيف يقارَن بـ Codex وCursor، والمزالق التي تجعل مخرجات الذكاء الاصطناعي تبدو عامة، وكيف يسدّ Open Design الفجوة بصفته طبقة تصميم مفتوحة ومحلية أولًا."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "حلقة تغذية راجعة لتصميم Claude Code: وكيل طرفي يتخذ قرارات تصميم محددة، ومتصفح يعرض الواجهة، ومساحة عمل، مع سهم تغذية راجعة يعود إلى البداية", "caption": "الحلقة الأساسية: يحلّل Claude Code قرارات الواجهة المحددة في الطرفية، ويعرضها ويتحقق منها في متصفح حقيقي، ويتقارب نحو مراجعك."}, "tocLabel": "في هذه الصفحة", "toc": [{"id": "what-is-claude-code", "label": "ما هو Claude Code فعلًا"}, {"id": "why-design", "label": "لماذا يجيد Claude Code التصميم"}, {"id": "setup", "label": "إعداد Claude Code للتصميم (من الصفر)"}, {"id": "skills-workflow", "label": "سير عمل CLAUDE.md والـ Skills"}, {"id": "figma", "label": "التكامل ثنائي الاتجاه بين Claude Code وFigma"}, {"id": "vs", "label": "‏Claude Code مقابل Codex مقابل Cursor"}, {"id": "pitfalls", "label": "المزالق ومظهر «فوضى الذكاء الاصطناعي»"}, {"id": "open-design", "label": "التصميم بـ Claude Code داخل Open Design"}, {"id": "faq", "label": "الأسئلة الشائعة"}], "sections": [{"id": "what-is-claude-code", "heading": "ما هو Claude Code فعلًا", "blocks": [{"kind": "p", "text": "‏Claude Code هو أداة البرمجة الوكيلة من Anthropic. يقرأ قاعدة شيفرتك، ويحرّر الملفات، ويشغّل الأوامر، ويتكامل مع أدوات التطوير لديك — مخطِّطًا وكاتبًا ومتحققًا من العمل انطلاقًا من مهام باللغة الطبيعية بدلًا من مجرد إكمال السطور تلقائيًا."}, {"kind": "p", "text": "يأتي عبر عدة واجهات تشترك جميعها في المحرك نفسه: واجهة سطر أوامر طرفية، وإضافات لبيئات التطوير VS Code وCursor وJetBrains، وتطبيق سطح مكتب بمراجعة فروقات مرئية، وتجربة ويب للمهام الطويلة. وتنتقل ملفات CLAUDE.md وإعداداتك وخوادم MCP عبرها كلها."}, {"kind": "steps", "items": [{"label": "ملف التعليمات", "body": "يقرأ Claude Code ملف CLAUDE.md في جذر مشروعك في بداية كل جلسة — المكان الطبيعي لترميز أعراف التصميم لديك والـ tokens وقوائم المراجعة."}, {"label": "الـ Skills", "body": "تجمع Agent Skills تعليمات وسكربتات وموارد قابلة للتكرار يحمّلها Claude عند الطلب، بما في ذلك Frontend Design skill الرسمي من Anthropic للذوق."}, {"label": "التخطيط والوكلاء الفرعيون", "body": "يمكنه التخطيط قبل التنفيذ وإنشاء وكلاء فرعيين يعملون على أجزاء مختلفة من المهمة بالتوازي، ما يحافظ على تماسك إعادة هيكلة الواجهات الكبيرة."}]}, {"kind": "ul", "items": ["المزوِّد: Anthropic", "بيانات الاعتماد: مفتاح Anthropic API (مبدأ BYOK، عبر الـ Console) أو اشتراك Claude (Pro / Max)", "الواجهات: واجهة سطر أوامر طرفية، إضافات VS Code / Cursor / JetBrains، تطبيق سطح مكتب، ويب"]}]}, {"id": "why-design", "heading": "لماذا يجيد Claude Code التصميم", "blocks": [{"kind": "p", "text": "من بين وكلاء البرمجة، يتمتع Claude Code بسمعة الذوق في عمل الواجهات الأمامية. تفسّر ذلك بضعة أمور."}, {"kind": "steps", "items": [{"label": "قرارات محددة لا غامضة", "body": "يميل Claude Code إلى الالتزام بخيارات ملموسة — قيم hex بالضبط، وسلالم المسافات، وتدرّجات الخطوط، وهرمية المكوّنات — بدلًا من التهرّب، وهذا ما يميّز واجهة حقيقية عن مجرد عنصر نائب."}, {"label": "تفكير واعٍ بقاعدة الشيفرة", "body": "بفضل سياق عمل واسع، يعيد هيكلة الواجهة عبر ملفات كثيرة دفعة واحدة، معيدًا استخدام مكوّناتك وtokens الموجودة بدلًا من ابتكار أنماط لمرة واحدة."}, {"label": "skill رسمي للواجهة الأمامية", "body": "تقدّم Anthropic مهارة Frontend Design تجعل Claude يكتب اتجاهًا تصميميًا أولًا، وتبتعد عمدًا عن خطوط النظام العامة والتدرّجات البنفسجية المتوقّعة."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "رسم تخطيطي يوضّح تقارب نظام التصميم والـ skill والصورة المرجعية نحو مخرجات تصميم جيدة", "caption": "ينبع الذوق من ثلاثة مدخلات تقدّمها أنت: نظام تصميم، وskill، وصور مرجعية حقيقية."}, {"kind": "p", "text": "الدرس هو نفسه الذي تقوله Anthropic عن نماذجها: لا يملك Claude ذوقًا افتراضيًا — وإذا تُرك وحده يتقارب نحو المركز الإحصائي لتصميم الويب (Inter، تدرّجات بنفسجية، ظلال ناعمة). إنه ينتج تصميمًا جيدًا حين تمنحه قيودًا. ويجمع Open Design تلك المدخلات بالضبط، ولهذا يتلاءم الاثنان معًا (المزيد أدناه)."}]}, {"id": "setup", "heading": "إعداد Claude Code لعمل التصميم، من الصفر", "blocks": [{"kind": "p", "text": "هذا هو المسار الكامل من جهاز نظيف إلى Claude Code قادر على بناء الواجهة والتحقق منها."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "سير إعداد من خمس خطوات: التثبيت، المصادقة، تهيئة CLAUDE.md، إضافة الـ skill، التحقق", "caption": "تسلسل الإعداد: التثبيت ← المصادقة ← تهيئة CLAUDE.md ← إضافة Frontend Design skill ← تفعيل التحقق في المتصفح."}, {"kind": "steps", "items": [{"label": "رمّز قواعد التصميم لديك", "body": "ضع tokens وعناصرك الأولية وأعرافك في CLAUDE.md ووجّه Claude إليها، كي تطابق المخرجات هوية علامة بدلًا من العودة إلى مظهر عام."}, {"label": "أضف التحقق في المتصفح", "body": "اربط Playwright أو Chrome MCP كي يعرض Claude في متصفح حقيقي ويتحقق من مخرجاته عبر نقاط التوقف بدلًا من مجرد تأكيد نجاح البناء."}]}]}, {"id": "skills-workflow", "heading": "سير عمل CLAUDE.md والـ Skills", "blocks": [{"kind": "p", "text": "أعلى حلقات التصميم رافعةً مع Claude Code هي تغذيته بمراجع حقيقية إضافةً إلى سياق التصميم لديك، ثم التكرار حتى تطابق الواجهة — مع حمل CLAUDE.md والـ Skills للقيود كي لا تعيد شرحها في كل مطالبة."}, {"kind": "ol", "items": ["ابدأ من أوضح المراجع البصرية لديك — وضمّن حالات متعددة (سطح المكتب والجوال، التحويم، الفارغ، التحميل)، لا لقطة بطل واحدة فقط.", "كن محددًا في المطالبة؛ فالمطالبات الغامضة تنتج واجهة عامة حتى مع وكيل قوي.", "احتفظ بنظام تصميمك وأعرافك في CLAUDE.md، وأخبر Claude بمكان الـ tokens والعناصر الأولية المرجعية.", "أضف Frontend Design skill كي يلتزم Claude باتجاه جمالي حقيقي قبل كتابة الشيفرة.", "اربط التحقق في المتصفح كي يعرض Claude، ويغيّر الحجم إلى نقاط التوقف، ويقارن بالمراجع — لا أن يكتفي بتأكيد البناء."]}, {"kind": "p", "text": "أسقِط صورة مرجعية في الجلسة وأرسِل مطالبة بقيود ملموسة:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "شغّل خادم تطوير بالتوازي، وأبقِ المطالبات صغيرة ومركّزة، وثبّت التكرارات الجيدة / وأرجِع السيئة (مع إخبار Claude حين تُرجِع) كي تبني كل تمريرة على قاعدة نظيفة. استخدم وضع التخطيط لإعادة الهيكلة الأكبر كي تراجع المنهج قبل أي تغيير على الملفات."}]}, {"id": "figma", "heading": "‏Claude Code + Figma: تكامل ثنائي الاتجاه بين التصميم والشيفرة", "blocks": [{"kind": "p", "text": "في فبراير 2026 أطلقت Anthropic وFigma تكاملًا متقدّمًا ثنائي الاتجاه عبر خادم Figma MCP. وهو يعمل في الاتجاهين."}, {"kind": "steps", "items": [{"label": "التصميم ← الشيفرة", "body": "حدّد إطارًا في Figma أو الصق رابطًا في Claude Code، واسحب سياق التصميم، واطلب منه تنفيذ التصميم باستخدام مكتبة مكوّناتك الموجودة. ويبقي Code Connect المخرجات متوائمة مع مكوّناتك الحقيقية."}, {"label": "الشيفرة ← التصميم", "body": "ابنِ ميزة وعاينها في المتصفح، ثم قل «Send this to Figma» لالتقاط الواجهة قيد التشغيل بصفتها طبقات Figma قابلة للتحرير — الشاشة كاملةً أو عنصرًا محددًا."}]}, {"kind": "p", "text": "ثبّته مرة واحدة عبر claude plugin install figma@claude-plugins-official (يتطلب Dev Mode MCP خطة Figma مدفوعة). وخادم Figma MCP نفسه متاح لـ Claude Code وCodex وCursor وVS Code — وهو تمامًا نوع القدرة المحمولة متعددة الوكلاء التي بُني Open Design لتنسيقها."}]}, {"id": "vs", "heading": "‏Claude Code مقابل Codex مقابل Cursor للتصميم", "blocks": [{"kind": "p", "text": "لا يوجد فائز واحد في عمل التصميم — فلكل وكيل قوة مختلفة، والفرق المتمرّسة تجمع بينها. وإليك خلاصة منصفة:"}, {"kind": "table", "columns": ["الوكيل", "قوة التصميم", "الأنسب لـ"], "rows": [["Claude Code", "قرارات تصميم محددة (hex، مسافات، خطوط) وتفكير في تجربة المستخدم واعٍ بقاعدة الشيفرة", "تفكير الواجهة الأمامية وإعادة الهيكلة بسياق واسع"], ["Codex", "صقل بصري قوي وفهم للصور؛ عمليات بناء غير متزامنة في بيئة معزولة", "عمليات البناء غير المتزامنة المفوّضة وقواعد AGENTS.md المحمولة"], ["Cursor", "حلقة بناء-ومشاهدة بصرية مع معاينة حيّة وتحريرات مضمّنة", "عمل واجهة محكم بالتكرار-والمراقبة داخل بيئة تطوير"]]}, {"kind": "p", "text": "الحكم المتكرر في المجتمع أن الذوق يأتي من البشر: فجميعها تتجه افتراضيًا إلى مظهر عام دون skills ومراجع وقيود. تلك هي المشكلة الحقيقية التي ينبغي حلّها — وهي بشكل أداة تصميم، لا بشكل نموذج."}]}, {"id": "pitfalls", "heading": "المزالق، وكيف تتجنّب مظهر «فوضى الذكاء الاصطناعي»", "blocks": [{"kind": "p", "text": "حتى مع سمعة Claude Code في الذوق، فإن أكثر شكوى شيوعًا عن التصميم المولَّد بالذكاء الاصطناعي أنه يبدو عامًا — خطوط Inter، تدرّجات بنفسجية على أبيض، ظلال ناعمة، زوايا دائرية مفرطة الحجم، جماليّة «تصرخ بأن ذكاءً اصطناعيًا صنع هذا.» وتعزو Anthropic نفسها ذلك إلى التقارب التوزيعي: الخيارات الآمنة تهيمن على بيانات تدريب الويب. وتشمل المشكلات الأخرى المبلَّغ عنها انكسار تخطيطات الجوال وتسرّب التعليمات إلى نصوص الواجهة."}, {"kind": "steps", "items": [{"label": "ثبّت Frontend Design skill", "body": "يجبر Claude على الالتزام باتجاه حقيقي ويتجنّب صراحةً الخطوط والتدرّجات المفرَطة الاستخدام من الذكاء الاصطناعي."}, {"label": "فعّل التحقق في المتصفح", "body": "اجعل Claude يعرض ويتحقق ذاتيًا عبر نقاط التوقف كي لا تنكسر التخطيطات بصمت على الجوال."}, {"label": "زوّده بالـ tokens والمراجع", "body": "tokens التصميم الحقيقية ولقطات الشاشة المرجعية هي أكبر رافعة منفردة على جودة المخرجات."}, {"label": "رمّز القواعد في CLAUDE.md", "body": "ضع قواعد بأسلوب «لا بطاقات بطل، خطّان كحد أقصى، هرمية تقدّم العلامة» حيث يقرؤها الوكيل في كل تشغيل."}]}, {"kind": "p", "text": "لاحظ أن كل إجراء تخفيف يتمحور حول منح الوكيل سياق تصميم منسّقًا. والحفاظ على ذلك السياق يدويًا، لكل مشروع، هو الكدّ الذي يزيله Open Design."}]}, {"id": "open-design", "heading": "التصميم بـ Claude Code داخل Open Design", "blocks": [{"kind": "p", "text": "‏Open Design هو طبقة التصميم مفتوحة المصدر التي يطلبها سير العمل أعلاه باستمرار. يعامل Claude Code بصفته محوّلًا أصيلًا ويغلّفه بمكتبة منسّقة من الـ skills وأنظمة التصميم، وخط معالجة عرض منظّم، وواجهة سطح مكتب محلية — كي يكون سياق التصميم الذي يجعل Claude Code جيدًا حاضرًا من أول تشغيل، لا مُجمَّعًا يدويًا في كل مرة."}, {"kind": "ol", "items": ["ثبّت Open Design واختر Claude Code وكيلًا لك.", "صادِق بمفتاح Anthropic API (مبدأ BYOK) أو اشتراك Claude — تبقى بيانات الاعتماد على جهازك ولا تُمرَّر عبرنا أبدًا.", "اختر نظام تصميم وskill، ثم ولّد العروض والنماذج الأولية وصفحات الهبوط بذوق متّسق.", "كل أثر وكل ملف DESIGN.md يعيش في مستودعك الخاص، لا في سحابة مستضافة."]}, {"kind": "p", "text": "وكيل Claude Code نفسه، المفتاح نفسه — إضافةً إلى سير عمل تصميمي حقيقي ومحمول ومفتوح المصدر يحيط به. إنه محلي أولًا وبرخصة Apache-2.0، فلا شيء عن عملك أو بيانات اعتمادك يغادر جهازك."}]}], "faqTitle": "الأسئلة الشائعة", "faq": [{"name": "هل Claude Code جيد لعمل التصميم؟", "text": "نعم — فهو يُعدّ على نطاق واسع وكيل البرمجة صاحب الذوق الأفضل في الواجهة الأمامية، إذ يتخذ قرارات محددة وواعية بقاعدة الشيفرة بشأن قيم hex والمسافات وسلالم الخطوط. ومع Frontend Design skill ونظام تصميم وصور مرجعية حقيقية في السياق، ينتج واجهة بجودة إنتاجية ومتجاوبة ويمكنه التحقق منها في متصفح. وبدون ذلك السياق يميل إلى مظهر عام، وهي الفجوة التي يسدّها Open Design."}, {"name": "هل أحتاج إلى اشتراك Claude للتصميم بـ Claude Code؟", "text": "يمكنك استخدام مفتاح Anthropic API (مبدأ BYOK، عبر الـ Console) أو اشتراك Claude (Pro / Max). وفي كلتا الحالتين لا يمرّر Open Design بيانات اعتمادك أبدًا — فهي تُستخدَم مباشرةً بواسطة وكيلك على جهازك."}, {"name": "‏Claude Code أم Codex لتصميم الواجهة الأمامية؟", "text": "كلاهما قوي. يُعرَف Claude Code بقرارات تصميم محددة وواعية بقاعدة الشيفرة وتفكير في الواجهة الأمامية؛ ويتمتع Codex بصقل بصري قوي ويتفوّق في عمليات البناء المفوّضة المعزولة. وتستخدم فرق كثيرة كليهما — ويتيح لك Open Design تبديل الوكلاء دون تغيير سير عمل التصميم."}, {"name": "كيف أصل Claude Code بـ Figma؟", "text": "ثبّت إضافة Figma الرسمية عبر claude plugin install figma@claude-plugins-official. عندها يمكنك تنفيذ إطارات Figma في شيفرة باستخدام سياق التصميم، ودفع واجهة قيد التشغيل عائدةً إلى إطارات Figma قابلة للتحرير عبر «Send this to Figma». ويتطلب Dev Mode MCP خطة Figma مدفوعة."}, {"name": "ما هي الـ Skills وملف CLAUDE.md؟", "text": "‏CLAUDE.md ملف markdown في جذر مشروعك يقرؤه Claude Code في بداية كل جلسة — وهو المكان لترميز أعراف التصميم لديك. وتجمع الـ Skills تعليمات وموارد قابلة للتكرار يحمّلها Claude عند الطلب، بما في ذلك Frontend Design skill الرسمي من Anthropic. ويقدّم Open Design مكتبة منسّقة من الاثنين كي تتخطّى الإعداد لكل مشروع."}, {"name": "كيف أتجنّب جماليّة «فوضى الذكاء الاصطناعي» العامة؟", "text": "ثبّت Frontend Design skill، وزوّده بـ tokens تصميم حقيقية ولقطات شاشة مرجعية، ورمّز قواعد العلامة في CLAUDE.md، وفعّل التحقق في المتصفح. ويقدّم Open Design هذه بصفتها مكتبة منسّقة كي تتخطّى الإعداد لكل مشروع."}, {"name": "هل Open Design تابع لـ Anthropic؟", "text": "لا. Claude Code منتج من Anthropic؛ وOpen Design مشروع مستقل مفتوح المصدر يدعمه بصفته محوّلًا أصيلًا. وClaude وClaude Code علامتان تجاريتان لـ Anthropic."}, {"name": "هل ملفاتي وبيانات اعتمادي آمنة؟", "text": "نعم — Open Design محلي أولًا وبرخصة Apache-2.0. تبقى ملفاتك وآثارك وملف DESIGN.md في مستودعك الخاص، وتُستخدَم بيانات اعتماد Anthropic مباشرةً بواسطة وكيلك، ولا تُمرَّر عبر خوادم Open Design أبدًا."}], "ctaTitle": "صمّم بـ Claude Code، بالطريقة المفتوحة.", "ctaBody": "أحضر مفتاح Anthropic أو اشتراك Claude الخاص بك، واحتفظ بكل ملف محليًا، واحصل على مكتبة تصميم منسّقة حول الوكيل الذي تستخدمه أصلًا.", "ctaActions": [{"label": "استخدم Claude Code داخل Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "ضع نجمة على GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "نزّل تطبيق سطح المكتب", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "اعرض كل الوكلاء المدعومين"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex للتصميم — Open Design",
        description: "كيف يستخدم الناس OpenAI Codex في تصميم الواجهات والويب — إضافة Product Design، تكامل Figma، skills الواجهة الأمامية — وكيف يحوّله Open Design إلى وكيل تصميم محلي أولًا ومفتوح المصدر.",
        breadcrumb: "Codex",
        label: "وكيل · Codex",
        heading: "Codex للتصميم.",
        lead: "‏Codex هو وكيل البرمجة من OpenAI. وبإضافة Product Design وتكامل Figma صار أداة تصميم جادّة. يربط Open Design الأداة Codex بسير عمل تصميمي مفتوح المصدر — مفتاح OpenAI أو اشتراك ChatGPT الخاص بك، وملفاتك، محليًا أولًا.",
        rich: {"heroCtaLead": "يحوّل Open Design الأداة Codex إلى وكيل تصميم محلي أولًا ومفتوح المصدر — مفتاح OpenAI الخاص بك، وملفاتك، ومكتبة منسّقة من الـ skills وأنظمة التصميم تحيط بها.", "heroCtaActions": [{"label": "استخدم Codex داخل Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "ضع نجمة على GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "نزّل تطبيق سطح المكتب", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["بدأ OpenAI Codex مولّدًا للشيفرة، لكنه صار في 2026 أداة موثوقة لتصميم واجهات حقيقية — بمجرد أن تزوّده بالمراجع والـ skills وحلقة التحقق الصحيحة. هذا دليل عملي وشامل لاستخدام Codex في عمل الواجهات والواجهة الأمامية وأنظمة التصميم، ولربطه بسير عمل تصميمي منظّم عبر Open Design.", "يغطّي ما هو Codex اليوم، ولماذا صار فجأةً جيدًا في الواجهة الأمامية، وكيف تعدّه من الصفر، وحلقة من-لقطة-الشاشة-إلى-الواجهة، والتكامل الرسمي ثنائي الاتجاه مع Figma، وكيف يقارَن بـ Cursor وClaude Code، والمزالق التي تجعل مخرجات الذكاء الاصطناعي تبدو عامة، وكيف يسدّ Open Design الفجوة بصفته طبقة تصميم مفتوحة ومحلية أولًا."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "حلقة تغذية راجعة لتصميم Codex: وكيل طرفي، ومتصفح يعرض الواجهة، ومساحة عمل، مع سهم تغذية راجعة يعود إلى البداية", "caption": "الحلقة الأساسية: يبني Codex الواجهة في الطرفية، ويعرضها ويتحقق منها في متصفح حقيقي، ويكرّر مقابل مراجعك."}, "tocLabel": "في هذه الصفحة", "toc": [{"id": "what-is-codex", "label": "ما هو OpenAI Codex فعلًا"}, {"id": "why-design", "label": "لماذا صار Codex جيدًا في التصميم الآن"}, {"id": "setup", "label": "إعداد Codex للتصميم (من الصفر)"}, {"id": "screenshot-workflow", "label": "سير عمل من لقطة الشاشة إلى الواجهة"}, {"id": "figma", "label": "التكامل ثنائي الاتجاه بين Codex وFigma"}, {"id": "vs", "label": "‏Codex مقابل Cursor مقابل Claude Code"}, {"id": "pitfalls", "label": "المزالق ومظهر «فوضى الذكاء الاصطناعي»"}, {"id": "open-design", "label": "التصميم بـ Codex داخل Open Design"}, {"id": "faq", "label": "الأسئلة الشائعة"}], "sections": [{"id": "what-is-codex", "heading": "ما هو OpenAI Codex فعلًا (وما ليس هو)", "blocks": [{"kind": "p", "text": "أولًا، توضيح يُربك كل من يبحث عن «Codex» تقريبًا. كان OpenAI Codex الأصلي نموذج إكمال شيفرة من 2021 شغّل النسخ المبكرة من GitHub Copilot وأُوقِف في 2023. ليس هذا موضوع الصفحة. أما Codex اليوم فهو أداة البرمجة الوكيلة من OpenAI — يخطّط ويكتب ويشغّل ويتحقق من الشيفرة انطلاقًا من مهام باللغة الطبيعية."}, {"kind": "p", "text": "يأتي Codex الحديث عبر أربع واجهات: واجهة سطر أوامر طرفية (أُعيدت كتابتها بـ Rust، برخصة Apache-2.0)، وإضافة لبيئات التطوير VS Code وCursor وWindsurf، وتجربة سحابية/ويب للمهام غير المتزامنة المفوّضة، وتطبيق سطح مكتب بمتصفح داخلي وميزة Computer Use."}, {"kind": "steps", "items": [{"label": "النموذج الافتراضي", "body": "اعتبارًا من منتصف 2026، النموذج المُوصى به هو gpt-5.5، مع كون gpt-5.4 النموذج الذي درّبته OpenAI صراحةً للواجهة الأمامية واستخدام الحاسوب."}, {"label": "ملف التعليمات", "body": "يقرأ Codex ملف AGENTS.md في مشروعك (معيار متعدد الأدوات) لقواعد المشروع — المكان الطبيعي لترميز أعراف التصميم لديك."}, {"label": "البيئة المعزولة", "body": "يعمل في بيئة معزولة على مستوى النواة (وضع الكتابة في مساحة العمل افتراضيًا)، فلا يستطيع وكيل يحرّر واجهتك أن يتجوّل خارج المشروع."}]}, {"kind": "ul", "items": ["المزوِّد: OpenAI", "بيانات الاعتماد: مفتاح OpenAI API (مبدأ BYOK) أو اشتراك ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "رخصة واجهة سطر الأوامر: Apache-2.0، مفتوحة المصدر"]}]}, {"id": "why-design", "heading": "لماذا صار Codex جيدًا في التصميم الآن", "blocks": [{"kind": "p", "text": "تقاطعت ثلاثة أمور في أوائل 2026 لتجعل Codex أداة تصميم حقيقية لا مجرد مولّد شيفرة عام."}, {"kind": "steps", "items": [{"label": "نموذج مدرَّب للواجهة الأمامية", "body": "أطلقت OpenAI النموذج GPT-5.4، أول نموذج رئيسي لها مدرَّب للواجهة الأمامية واستخدام الحاسوب، بفهم أفضل بكثير للصور عبر سير عمل التصميم وتحقّق ذاتي أقوى. بل يمكنه توليد لوحات مزاج وخيارات بصرية قبل الالتزام بالأصول النهائية."}, {"label": "skill رسمي للواجهة الأمامية", "body": "يقدّم كتالوج openai/skills مهارة frontend منسّقة تفرض ذوقًا حقيقيًا: تخطيطات بلا بطاقات، أبطال ممتدة الحواف، هرمية تقدّم العلامة، حركة مقيّدة، خطّان كحد أقصى ولون توكيد واحد — وتجعل Codex يكتب أطروحة بصرية قبل البناء."}, {"label": "التحقق في المتصفح", "body": "مع مهارة Playwright يفتح Codex متصفحًا حقيقيًا، ويغيّر الحجم إلى نقاط التوقف، ويقارن مخرجاته بالمرجع بدلًا من مجرد التحقق من نجاح البناء."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "رسم تخطيطي يوضّح تقارب نظام التصميم والـ skill والصورة المرجعية نحو مخرجات تصميم جيدة", "caption": "ينبع الذوق من ثلاثة مدخلات تقدّمها أنت: نظام تصميم، وskill، وصور مرجعية حقيقية."}, {"kind": "p", "text": "الدرس وراء الثلاثة جميعًا: لا يملك Codex ذوقًا افتراضيًا. إنه ينتج تصميمًا جيدًا حين تمنحه قيودًا — نظام تصميم، وskill جمالي، ومراجع ملموسة. ويجمع Open Design تلك المدخلات بالضبط، ولهذا يتلاءم الاثنان معًا (المزيد أدناه)."}]}, {"id": "setup", "heading": "إعداد Codex لعمل التصميم، من الصفر", "blocks": [{"kind": "p", "text": "هذا هو المسار الكامل من جهاز نظيف إلى Codex قادر على بناء الواجهة والتحقق منها."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "سير إعداد من خمس خطوات: التثبيت، المصادقة، التهيئة، تثبيت الـ skill، التحقق", "caption": "تسلسل الإعداد: التثبيت ← المصادقة ← تهيئة AGENTS.md ← تثبيت frontend skill ← تفعيل التحقق في المتصفح."}, {"kind": "steps", "items": [{"label": "رمّز قواعد التصميم لديك", "body": "ضع tokens وعناصرك الأولية وأعرافك في AGENTS.md أو في DESIGN.md ووجّه Codex إليها، كي تطابق المخرجات هوية علامة بدلًا من العودة إلى مظهر عام."}, {"label": "اختر مستوى الاستدلال الصحيح", "body": "تشير OpenAI إلى أن مستويات الاستدلال المنخفضة إلى المتوسطة كثيرًا ما تنتج نتائج واجهة أمامية أقوى من الإعداد الأعلى."}]}]}, {"id": "screenshot-workflow", "heading": "سير عمل من لقطة الشاشة إلى الواجهة", "blocks": [{"kind": "p", "text": "أعلى حلقات التصميم رافعةً مع Codex هي تحويل صورة مرجعية إلى واجهة عاملة ومتجاوبة والتكرار حتى تطابق. وتتلخّص إرشادات OpenAI نفسها في خمس خطوات."}, {"kind": "ol", "items": ["ابدأ من أوضح المراجع البصرية لديك — وضمّن حالات متعددة (سطح المكتب والجوال، التحويم، الفارغ، التحميل)، لا لقطة بطل واحدة فقط.", "كن محددًا في المطالبة؛ فالمطالبات الغامضة تنتج واجهة عامة.", "جهّز نظام تصميم وأخبر Codex بمكان الـ tokens والعناصر الأولية المرجعية.", "فعّل مهارة Playwright التفاعلية كي يعرض Codex في متصفح حقيقي ويغيّر الحجم إلى نقاط التوقف.", "كرّر بجعل Codex يقارن تنفيذه بلقطات الشاشة — لا أن يكتفي بتأكيد البناء."]}, {"kind": "p", "text": "غذِّ الصور بسحب لقطة شاشة إلى الطرفية أو عبر علامة الصورة، ثم أرسِل مطالبة بقيود ملموسة:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "شغّل خادم تطوير في طرفية ثانية، وأبقِ المطالبات صغيرة ومركّزة، وثبّت التكرارات الجيدة / وأرجِع السيئة (مع إخبار Codex حين تُرجِع) كي تبني كل تمريرة على قاعدة نظيفة."}]}, {"id": "figma", "heading": "‏Codex + Figma: تكامل ثنائي الاتجاه بين التصميم والشيفرة", "blocks": [{"kind": "p", "text": "في فبراير 2026 أعلنت OpenAI وFigma شراكة رسمية، حوّلت نسخة Figma MCP التجريبية السابقة إلى تكامل متقدّم ثنائي الاتجاه. وهو يعمل في الاتجاهين."}, {"kind": "steps", "items": [{"label": "التصميم ← الشيفرة", "body": "انسخ «link to selection» لإطار في Figma، والصقه في Codex مع get_design_context، واطلب منه تنفيذ التصميم باستخدام مكتبة مكوّناتك الموجودة."}, {"label": "الشيفرة ← التصميم", "body": "تحوّل أداة generate_figma_design («Code to Canvas») واجهةً حيّة قيد التشغيل عائدةً إلى إطارات Figma قابلة للتحرير — الشاشة كاملةً، أو عنصرًا محددًا، أو ملفًا كاملًا."}]}, {"kind": "p", "text": "يعمل Figma MCP بصفته خادمًا بعيدًا ومُعفى من حدود المعدل. أضِفه مرة واحدة فيصبح متاحًا لـ Codex وClaude Code وCursor وVS Code والمزيد — وهو تمامًا نوع القدرة المحمولة متعددة الوكلاء التي بُني Open Design لتنسيقها."}]}, {"id": "vs", "heading": "‏Codex مقابل Cursor مقابل Claude Code للتصميم", "blocks": [{"kind": "p", "text": "لا يوجد فائز واحد في عمل التصميم — فلكل وكيل قوة مختلفة، والفرق المتمرّسة تجمع بينها. وإليك خلاصة منصفة:"}, {"kind": "table", "columns": ["الوكيل", "قوة التصميم", "الأنسب لـ"], "rows": [["Codex", "صقل بصري قوي بعد GPT-5.4 + frontend-skill؛ فهم للصور", "عمليات البناء غير المتزامنة المفوّضة، التشغيل المعزول، قواعد AGENTS.md المحمولة"], ["Cursor", "حلقة بناء-ومشاهدة بصرية مع معاينة حيّة وتحريرات مضمّنة", "عمل واجهة محكم بالتكرار-والمراقبة داخل بيئة تطوير"], ["Claude Code", "قرارات تصميم محددة (hex، مسافات، خطوط) وتجربة مستخدم واعية بقاعدة الشيفرة", "تفكير الواجهة الأمامية وإعادة الهيكلة بسياق واسع"]]}, {"kind": "p", "text": "الحكم المتكرر في المجتمع أن الذوق يأتي من البشر: فجميعها تتجه افتراضيًا إلى مظهر عام دون skills ومراجع وقيود. تلك هي المشكلة الحقيقية التي ينبغي حلّها — وهي بشكل أداة تصميم، لا بشكل نموذج."}]}, {"id": "pitfalls", "heading": "المزالق، وكيف تتجنّب مظهر «فوضى الذكاء الاصطناعي»", "blocks": [{"kind": "p", "text": "أكثر شكوى شيوعًا عن التصميم المولَّد بـ Codex أنه يبدو عامًا — تدرّجات ناعمة، لوحات عائمة، زوايا دائرية مفرطة الحجم، ظلال دراميّة، أجواء Inter-والبنفسجي «تصرخ بأن ذكاءً اصطناعيًا صنع هذا.» وتشمل المشكلات الأخرى المبلَّغ عنها انكسار تخطيطات الجوال، وتسرّب التعليمات إلى نصوص الواجهة، وبلوغ حدود الاستخدام بسرعة."}, {"kind": "steps", "items": [{"label": "ثبّت frontend skill", "body": "skill جمالي منسّق يجبر Codex على الالتزام باتجاه حقيقي بدلًا من المظهر الافتراضي."}, {"label": "فعّل تحقق Playwright", "body": "اجعل Codex يعرض ويتحقق ذاتيًا عبر نقاط التوقف كي لا تنكسر التخطيطات بصمت على الجوال."}, {"label": "زوّده بالـ tokens والمراجع", "body": "tokens التصميم الحقيقية ولقطات الشاشة المرجعية هي أكبر رافعة منفردة على جودة المخرجات."}, {"label": "رمّز القواعد في AGENTS.md", "body": "ضع قواعد بأسلوب «لا بطاقات بطل، خطّان كحد أقصى، هرمية تقدّم العلامة» حيث يقرؤها الوكيل في كل تشغيل."}]}, {"kind": "p", "text": "لاحظ أن كل إجراء تخفيف يتمحور حول منح الوكيل سياق تصميم منسّقًا. والحفاظ على ذلك السياق يدويًا، لكل مشروع، هو الكدّ الذي يزيله Open Design."}]}, {"id": "open-design", "heading": "التصميم بـ Codex داخل Open Design", "blocks": [{"kind": "p", "text": "‏Open Design هو طبقة التصميم مفتوحة المصدر التي يطلبها سير العمل أعلاه باستمرار. يعامل Codex بصفته محوّلًا أصيلًا ويغلّفه بمكتبة منسّقة من الـ skills وأنظمة التصميم، وخط معالجة عرض منظّم، وواجهة سطح مكتب محلية — كي يكون سياق التصميم الذي يجعل Codex جيدًا حاضرًا من أول تشغيل، لا مُجمَّعًا يدويًا في كل مرة."}, {"kind": "ol", "items": ["ثبّت Open Design واختر Codex وكيلًا لك.", "صادِق بمفتاح OpenAI API (مبدأ BYOK) أو اشتراك ChatGPT — تبقى بيانات الاعتماد على جهازك ولا تُمرَّر عبرنا أبدًا.", "اختر نظام تصميم وskill، ثم ولّد العروض والنماذج الأولية وصفحات الهبوط بذوق متّسق.", "كل أثر وكل ملف DESIGN.md يعيش في مستودعك الخاص، لا في سحابة مستضافة."]}, {"kind": "p", "text": "وكيل Codex نفسه، المفتاح نفسه — إضافةً إلى سير عمل تصميمي حقيقي ومحمول ومفتوح المصدر يحيط به. إنه محلي أولًا وبرخصة Apache-2.0، فلا شيء عن عملك أو بيانات اعتمادك يغادر جهازك."}]}], "faqTitle": "الأسئلة الشائعة", "faq": [{"name": "هل يستطيع OpenAI Codex فعلًا أداء عمل التصميم؟", "text": "نعم — مع frontend skill ونظام تصميم وصور مرجعية حقيقية في السياق، ينتج Codex (وخاصةً على GPT-5.4) واجهة بجودة إنتاجية ومتجاوبة ويمكنه التحقق منها في متصفح. وبدون ذلك السياق يميل إلى مظهر عام، وهي الفجوة التي يسدّها Open Design."}, {"name": "هل هذه إضافة OpenAI Codex Product Design؟", "text": "لا. Open Design مشروع مستقل مفتوح المصدر يدمج Codex بصفته وكيلًا. وهو يكمّل أدوات OpenAI الخاصة بمكتبة skills وأنظمة تصميم مفتوحة ومحلية أولًا."}, {"name": "هل أحتاج إلى اشتراك ChatGPT للتصميم بـ Codex؟", "text": "يمكنك استخدام مفتاح OpenAI API (مبدأ BYOK) أو اشتراك ChatGPT الخاص بك. وعادةً ما يمنح تسجيل الدخول عبر ChatGPT حدودًا أكثر سخاءً؛ ولا يمرّر Open Design بيانات اعتمادك في كلتا الحالتين."}, {"name": "‏Codex أم Claude Code لتصميم الواجهة الأمامية؟", "text": "كلاهما قوي. يُعرَف Claude Code بقرارات تصميم محددة وواعية بقاعدة الشيفرة؛ ويتمتع Codex بصقل بصري قوي بعد GPT-5.4 ويتفوّق في عمليات البناء المفوّضة المعزولة. وتستخدم فرق كثيرة كليهما — ويتيح لك Open Design تبديل الوكلاء دون تغيير سير عمل التصميم."}, {"name": "كيف أصل Codex بـ Figma؟", "text": "أضِف خادم Figma MCP الرسمي (codex mcp add figma --url https://mcp.figma.com/mcp). عندها يمكنك تنفيذ إطارات Figma في شيفرة عبر get_design_context، ودفع واجهة قيد التشغيل عائدةً إلى إطارات Figma قابلة للتحرير عبر generate_figma_design."}, {"name": "كيف أتجنّب جماليّة «فوضى الذكاء الاصطناعي» العامة؟", "text": "ثبّت frontend skill، وزوّده بـ tokens تصميم حقيقية ولقطات شاشة مرجعية، ورمّز قواعد العلامة في AGENTS.md، وفعّل تحقق Playwright. ويقدّم Open Design هذه بصفتها مكتبة منسّقة كي تتخطّى الإعداد لكل مشروع."}, {"name": "هل Open Design تابع لـ OpenAI؟", "text": "لا. Codex منتج من OpenAI؛ وOpen Design مشروع مستقل مفتوح المصدر يدعمه بصفته محوّلًا أصيلًا. وOpenAI وCodex علامتان تجاريتان لـ OpenAI."}, {"name": "هل ملفاتي وبيانات اعتمادي آمنة؟", "text": "نعم — Open Design محلي أولًا. تبقى ملفاتك وآثارك وملف DESIGN.md في مستودعك الخاص، وتُستخدَم بيانات اعتماد OpenAI مباشرةً بواسطة وكيلك، ولا تُمرَّر عبر خوادم Open Design أبدًا."}], "ctaTitle": "صمّم بـ Codex، بالطريقة المفتوحة.", "ctaBody": "أحضر مفتاح OpenAI الخاص بك، واحتفظ بكل ملف محليًا، واحصل على مكتبة تصميم منسّقة حول الوكيل الذي تستخدمه أصلًا.", "ctaActions": [{"label": "استخدم Codex داخل Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "ضع نجمة على GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "نزّل تطبيق سطح المكتب", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "اعرض كل الوكلاء المدعومين"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor للمصممين — Open Design",
        description: "كيف يستخدم المصممون Cursor في تصميم الواجهات والويب — وضع التصميم، Figma إلى شيفرة، Figma MCP — وكيف يحوّله Open Design إلى وكيل تصميم محلي أولًا ومفتوح المصدر.",
        breadcrumb: "Cursor",
        label: "وكيل · Cursor",
        heading: "Cursor للمصممين.",
        lead: "‏Cursor هو محرّر الشيفرة بالذكاء الاصطناعي، ومعه الآن وضع تصميم بصري. يستخدمه المصممون لتحرير الواجهة بالإشارة والرسم، ولتحويل Figma إلى شيفرة. يربط Open Design وكيل Cursor بسير عمل تصميمي مفتوح المصدر يبقي ملفاتك محلية.",
        rich: {"heroCtaLead": "يحوّل Open Design الأداة Cursor إلى وكيل تصميم محلي أولًا ومفتوح المصدر — حساب Cursor أو مفاتيح النماذج الخاصة بك، وملفاتك، ومكتبة منسّقة من الـ skills وأنظمة التصميم تحيط بها.", "heroCtaActions": [{"label": "استخدم Cursor داخل Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "ضع نجمة على GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "نزّل تطبيق سطح المكتب", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["‏Cursor هو محرّر الشيفرة الذي يضع الذكاء الاصطناعي أولًا، والذي جعل «ابنِه وشاهده يُعرَض» الطريقة الافتراضية لشحن الواجهات. مع وضع الوكيل والتحريرات المضمّنة والمعاينة داخل المحرّر وFigma عبر MCP، صار أداة تصميم حقيقية — بمجرد أن تزوّده بالمراجع والقواعد الصحيحة وحلقة تحقق. هذا دليل عملي وشامل لاستخدام Cursor في عمل الواجهات والواجهة الأمامية وأنظمة التصميم، ولربطه بسير عمل تصميمي منظّم عبر Open Design.", "يغطّي ما هو Cursor فعلًا، ولماذا تُجيد حلقته المحكمة بالتكرار-والمراقبة التصميم، وكيف تعدّه من الصفر، وحلقة من-لقطة-الشاشة-والمعاينة-إلى-الواجهة، والتكامل ثنائي الاتجاه مع Figma عبر MCP، وكيف يقارَن بـ Codex وClaude Code، والمزالق التي تجعل مخرجات الذكاء الاصطناعي تبدو عامة، وكيف يسدّ Open Design الفجوة بصفته طبقة تصميم مفتوحة ومحلية أولًا."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "تقارب تصميم Cursor: محرّر على اليسار، ومركز منسّق من الـ skills وأنظمة التصميم في الوسط مع شعار Cursor في المنتصف، وواجهة معروضة على اليمين", "caption": "الفكرة الأساسية: يحرّر Cursor الواجهة ويعرضها في المحرّر، بينما يغذّيه مركز تصميم منسّق بالنظام والـ skills والمراجع التي تجعل المخرجات تبدو مقصودة."}, "tocLabel": "في هذه الصفحة", "toc": [{"id": "what-is-cursor", "label": "ما هو Cursor فعلًا"}, {"id": "why-design", "label": "لماذا يجيد Cursor التصميم"}, {"id": "setup", "label": "إعداد Cursor للتصميم (من الصفر)"}, {"id": "preview-workflow", "label": "سير عمل من المعاينة إلى الواجهة"}, {"id": "figma", "label": "‏Cursor + Figma عبر MCP"}, {"id": "vs", "label": "‏Cursor مقابل Codex مقابل Claude Code"}, {"id": "pitfalls", "label": "المزالق ومظهر «فوضى الذكاء الاصطناعي»"}, {"id": "open-design", "label": "التصميم بـ Cursor داخل Open Design"}, {"id": "faq", "label": "الأسئلة الشائعة"}], "sections": [{"id": "what-is-cursor", "heading": "ما هو Cursor فعلًا", "blocks": [{"kind": "p", "text": "‏Cursor هو محرّر شيفرة يضع الذكاء الاصطناعي أولًا، بناه Anysphere. وهو نسخة معدّلة من VS Code، فيحتفظ بالمحرّر والإضافات واختصارات المفاتيح المألوفة، لكنه يعيد بناء سير العمل حول وكيل ذكاء اصطناعي يقرأ مشروعك كاملًا، ويحرّر ملفات متعددة، ويشغّل الأوامر، ويكرّر معك ضمن الحلقة."}, {"kind": "p", "text": "في عمل التصميم، الواجهات المهمة هي وضع الوكيل (تصف نتيجة فيخطّط Cursor ويحرّر عبر الملفات)، والتحريرات المضمّنة وإكمالات Tab للتعديلات السريعة، ومعاينة/متصفح داخل المحرّر يتيحان رؤية الواجهة قيد التشغيل دون مغادرة النافذة، ودعم MCP الذي يسمح له بجلب سياق خارجي كملف Figma حيّ."}, {"kind": "steps", "items": [{"label": "قواعد المشروع", "body": "يقرأ Cursor ملفات تعليمات المشروع — قواعد `.mdc` المُدارة بإصدارات تحت `.cursor/rules`، وملف `AGENTS.md` بسيط — كي ترمّز أعراف التصميم لديك حيث يقرؤها الوكيل في كل تشغيل."}, {"label": "النماذج", "body": "‏Cursor مرن في النماذج: يأتي بنماذج متقدّمة عبر اشتراكك ويدعم أيضًا إحضار مفاتيح نماذجك الخاصة، فتختار المحرّك خلف سير عمل المحرّر نفسه."}, {"label": "MCP", "body": "يتحدّث بروتوكول Model Context Protocol، فتصبح الخوادم الخارجية — وأبرزها خادم Figma MCP — سياقًا أصيلًا للوكيل."}]}, {"kind": "ul", "items": ["المزوِّد: Anysphere", "بيانات الاعتماد: حساب / اشتراك Cursor (Hobby / Pro / Business) أو مفاتيح نماذجك الخاصة (مبدأ BYOK)", "الصيغة: محرّر شيفرة يضع الذكاء الاصطناعي أولًا (نسخة معدّلة من VS Code) مع وكيل ومعاينة داخل المحرّر"]}]}, {"id": "why-design", "heading": "لماذا يجيد Cursor التصميم", "blocks": [{"kind": "p", "text": "ميزة Cursor في التصميم ليست ميزة واحدة — بل إحكام حلقة البناء-والمشاهدة. ثلاثة أمور تجعله يبدو أداة تصميم لا مجرد مولّد شيفرة عام."}, {"kind": "steps", "items": [{"label": "حلقة محكمة بالتكرار-والمراقبة", "body": "تطالب فيحرّر Cursor عبر الملفات، وتعرض المعاينة داخل المحرّر النتيجة فورًا — فتضبط المسافات والهرمية والحركة في ثوانٍ بدلًا من التنقّل عبر طرفية ومتصفح منفصلين."}, {"label": "تحرير بصري مباشر", "body": "إلى جانب المحادثة، يتيح لك Cursor تحديد عناصر في المعاينة وتعديل الأنماط، فتبدو التصحيحات البصرية الصغيرة كتحريرات تصميم لا كتنقيب في الشيفرة."}, {"label": "قواعد المشروع وسياق MCP", "body": "مع `.cursor/rules` (أو `AGENTS.md`) وخادم Figma MCP، يعمل الوكيل مقابل tokens ومكوّناتك ومواصفات التصميم الحقيقية بدلًا من التخمين."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "رسم تخطيطي يوضّح تقارب نظام التصميم والـ skill والصورة المرجعية نحو مخرجات تصميم جيدة", "caption": "ينبع الذوق من ثلاثة مدخلات تقدّمها أنت: نظام تصميم، وskill، وصور مرجعية حقيقية."}, {"kind": "p", "text": "الدرس نفسه الذي يعلّمه كل وكيل: لا يملك Cursor ذوقًا افتراضيًا. إنه ينتج تصميمًا جيدًا حين تمنحه قيودًا — نظام تصميم، وskill جمالي، ومراجع ملموسة. ويجمع Open Design تلك المدخلات بالضبط، ولهذا يتلاءم الاثنان معًا (المزيد أدناه)."}]}, {"id": "setup", "heading": "إعداد Cursor لعمل التصميم، من الصفر", "blocks": [{"kind": "p", "text": "هذا هو المسار الكامل من جهاز نظيف إلى Cursor قادر على بناء الواجهة ومعاينتها والتحقق منها مقابل نظام تصميمك."}, {"kind": "ol", "items": ["ثبّت Cursor من cursor.com وسجّل الدخول بحساب Cursor، أو هيّئ مفاتيح نماذجك الخاصة (مبدأ BYOK) في الإعدادات.", "افتح مشروعك واختر نموذجًا في لوحة المحادثة / الوكيل.", "أضف قواعد المشروع: أنشئ `.cursor/rules/*.mdc` لأعراف منظّمة محدّدة النطاق بالأنماط، أو ملف `AGENTS.md` بسيط لتعليمات بسيطة وقابلة للقراءة.", "اربط خادم Figma MCP (اختياري) كي يقرأ الوكيل سياق التصميم الحيّ.", "شغّل خادم التطوير واستخدم المعاينة داخل المحرّر لرؤية الواجهة والتحقق منها أثناء التكرار."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "سير إعداد من خمس خطوات: التثبيت، المصادقة، تهيئة القواعد، إضافة الـ skill، التحقق", "caption": "تسلسل الإعداد: التثبيت ← المصادقة ← تهيئة قواعد المشروع ← إضافة skill ← تفعيل التحقق بالمعاينة."}, {"kind": "p", "text": "ملف قواعد مشروع بسيط يجعل الوكيل يصمّم لهوية علامة بدلًا من العودة إلى مظهر عام. ضعه حيث يقرؤه Cursor في كل تشغيل:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "رمّز قواعد التصميم لديك", "body": "ضع tokens وعناصرك الأولية وأعرافك في `.cursor/rules` أو `AGENTS.md` ووجّه Cursor إليها، كي تطابق المخرجات هوية علامة بدلًا من العودة إلى مظهر عام."}, {"label": "أبقِ المطالبات صغيرة", "body": "حلقة Cursor المحكمة تكافئ الطلبات المركّزة — كرّر مكوّنًا أو حالة واحدة في كل مرة وراقب المعاينة بين التمريرات."}]}]}, {"id": "preview-workflow", "heading": "سير عمل من المعاينة إلى الواجهة", "blocks": [{"kind": "p", "text": "أعلى حلقات التصميم رافعةً مع Cursor هي تحويل مرجع إلى واجهة عاملة ومتجاوبة والتكرار في المحرّر حتى تطابق — مع مراقبة المعاينة الحيّة طوال الوقت بدلًا من التخمين."}, {"kind": "ol", "items": ["ابدأ من أوضح المراجع البصرية لديك — وضمّن حالات متعددة (سطح المكتب والجوال، التحويم، الفارغ، التحميل)، لا لقطة بطل واحدة فقط.", "كن محددًا في المطالبة؛ فالمطالبات الغامضة تنتج واجهة عامة.", "جهّز نظام تصميم وأخبر Cursor بمكان الـ tokens والعناصر الأولية المرجعية.", "أبقِ المعاينة داخل المحرّر مفتوحة وخادم التطوير يعمل كي تُعرَض كل تحريرة فورًا عند نقاط التوقف التي تهمّك.", "كرّر بمقارنة الواجهة المعروضة بالمراجع — واستخدم تحديد العناصر المباشر في المعاينة للتصحيحات البصرية الصغيرة."]}, {"kind": "p", "text": "غذِّ المراجع بإرفاق صورة بالمحادثة، ثم أرسِل مطالبة بقيود ملموسة:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "ثبّت التكرارات الجيدة وأرجِع السيئة (مع إخبار Cursor حين تُرجِع) كي تبني كل تمريرة على قاعدة نظيفة — الانضباط نفسه الذي يمنع أي حلقة وكيل من الانحراف."}]}, {"id": "figma", "heading": "‏Cursor + Figma: التصميم ↔ الشيفرة عبر MCP", "blocks": [{"kind": "p", "text": "يتصل Cursor بـ Figma عبر خادم Figma MCP الرسمي، الذي يمنح الوكيل وصولًا منظّمًا إلى ملف Figma حيّ بدلًا من لقطة شاشة مسطّحة. وهذا يزيل التخمين من التسليم."}, {"kind": "steps", "items": [{"label": "التصميم ← الشيفرة", "body": "انسخ رابط إطار في Figma، والصقه في Cursor، واطلب منه تنفيذ التصميم. يعرض خادم MCP سياق التصميم الحقيقي — مكوّنات، متغيرات، بيانات تخطيط، tokens — كي تطابق الشيفرة المولَّدة المصدر بدلًا من مقاربته."}, {"label": "ابقَ متوائمًا", "body": "مع استخدام tokens التصميم والأنماط والمكوّنات باتّساق في Figma (وCode Connect حيث يتوفّر)، تبقى مخرجات Cursor مرتبطة بنظام تصميمك الحقيقي بدلًا من إعادة ابتكار العناصر الأولية."}]}, {"kind": "p", "text": "أعدّ خادم Figma MCP البعيد مرة واحدة فيصبح متاحًا لـ Cursor بصفته سياقًا أصيلًا. ولأن MCP معيار مفتوح، فإن الخادم نفسه قابل لإعادة الاستخدام عبر Cursor وClaude Code وCodex وVS Code — وهو تمامًا نوع القدرة المحمولة متعددة الوكلاء التي بُني Open Design لتنسيقها."}]}, {"id": "vs", "heading": "‏Cursor مقابل Codex مقابل Claude Code للتصميم", "blocks": [{"kind": "p", "text": "لا يوجد فائز واحد في عمل التصميم — فلكل وكيل قوة مختلفة، والفرق المتمرّسة تجمع بينها. وإليك خلاصة منصفة:"}, {"kind": "table", "columns": ["الوكيل", "قوة التصميم", "الأنسب لـ"], "rows": [["Cursor", "حلقة بناء-ومشاهدة بصرية مع معاينة حيّة داخل المحرّر وتحرير مباشر للعناصر", "عمل واجهة محكم بالتكرار-والمراقبة داخل بيئة تطوير"], ["Codex", "صقل بصري قوي مع frontend skill؛ فهم للصور وتشغيل معزول", "عمليات البناء غير المتزامنة المفوّضة وقواعد AGENTS.md المحمولة"], ["Claude Code", "قرارات تصميم محددة (hex، مسافات، خطوط) وتجربة مستخدم واعية بقاعدة الشيفرة", "تفكير الواجهة الأمامية وإعادة الهيكلة بسياق واسع"]]}, {"kind": "p", "text": "الحكم المتكرر في المجتمع أن الذوق يأتي من البشر: فجميعها تتجه افتراضيًا إلى مظهر عام دون skills ومراجع وقيود. تلك هي المشكلة الحقيقية التي ينبغي حلّها — وهي بشكل أداة تصميم، لا بشكل نموذج."}]}, {"id": "pitfalls", "heading": "المزالق، وكيف تتجنّب مظهر «فوضى الذكاء الاصطناعي»", "blocks": [{"kind": "p", "text": "أكثر شكوى شيوعًا عن التصميم المولَّد بـ Cursor أنه يبدو عامًا — تدرّجات ناعمة، لوحات عائمة، زوايا دائرية مفرطة الحجم، ظلال دراميّة، أجواء Inter-والبنفسجي «تصرخ بأن ذكاءً اصطناعيًا صنع هذا.» وتشمل المشكلات الأخرى المبلَّغ عنها تخطيطات تنكسر على الجوال وتسرّب التعليمات إلى نصوص الواجهة."}, {"kind": "steps", "items": [{"label": "أضف skill تصميم", "body": "skill جمالي منسّق يجبر Cursor على الالتزام باتجاه حقيقي بدلًا من المظهر الافتراضي."}, {"label": "استخدم المعاينة للتحقق", "body": "اعرض وتحقق ذاتيًا عبر نقاط التوقف في المعاينة داخل المحرّر كي لا تنكسر التخطيطات بصمت على الجوال."}, {"label": "زوّده بالـ tokens والمراجع", "body": "tokens التصميم الحقيقية ولقطات الشاشة المرجعية هي أكبر رافعة منفردة على جودة المخرجات."}, {"label": "رمّز القواعد في `.cursor/rules`", "body": "ضع قواعد بأسلوب «لا بطاقات بطل، خطّان كحد أقصى، هرمية تقدّم العلامة» حيث يقرؤها الوكيل في كل تشغيل."}]}, {"kind": "p", "text": "لاحظ أن كل إجراء تخفيف يتمحور حول منح الوكيل سياق تصميم منسّقًا. والحفاظ على ذلك السياق يدويًا، لكل مشروع، هو الكدّ الذي يزيله Open Design."}]}, {"id": "open-design", "heading": "التصميم بـ Cursor داخل Open Design", "blocks": [{"kind": "p", "text": "‏Open Design هو طبقة التصميم مفتوحة المصدر التي يطلبها سير العمل أعلاه باستمرار. يعامل Cursor بصفته محوّلًا أصيلًا ويغلّفه بمكتبة منسّقة من الـ skills وأنظمة التصميم، وخط معالجة عرض منظّم، وواجهة سطح مكتب محلية — كي يكون سياق التصميم الذي يجعل Cursor جيدًا حاضرًا من أول تشغيل، لا مُجمَّعًا يدويًا في كل مرة."}, {"kind": "ol", "items": ["ثبّت Open Design واختر Cursor وكيلًا لك.", "صادِق بحساب Cursor أو مفاتيح نماذجك الخاصة (مبدأ BYOK) — تبقى بيانات الاعتماد على جهازك ولا تُمرَّر عبرنا أبدًا.", "اختر نظام تصميم وskill، ثم ولّد العروض والنماذج الأولية وصفحات الهبوط بذوق متّسق.", "كل أثر وكل ملف DESIGN.md يعيش في مستودعك الخاص، لا في سحابة مستضافة."]}, {"kind": "p", "text": "وكيل Cursor نفسه، المفتاح نفسه — إضافةً إلى سير عمل تصميمي حقيقي ومحمول ومفتوح المصدر يحيط به. إنه محلي أولًا وبرخصة Apache-2.0، فلا شيء عن عملك أو بيانات اعتمادك يغادر جهازك."}]}], "faqTitle": "الأسئلة الشائعة", "faq": [{"name": "هل يستطيع Cursor فعلًا أداء عمل التصميم؟", "text": "نعم — مع skill تصميم ونظام تصميم وصور مرجعية حقيقية في السياق، ينتج Cursor واجهة بجودة إنتاجية ومتجاوبة، وتتيح لك المعاينة داخل المحرّر التحقق منها وصقلها بصريًا. وبدون ذلك السياق يميل إلى مظهر عام، وهي الفجوة التي يسدّها Open Design."}, {"name": "هل هذا منتج Cursor رسمي؟", "text": "لا. Open Design مشروع مستقل مفتوح المصدر يدمج Cursor بصفته وكيلًا. وهو يكمّل Cursor بمكتبة skills وأنظمة تصميم مفتوحة ومحلية أولًا."}, {"name": "هل أحتاج إلى اشتراك Cursor للتصميم بـ Cursor؟", "text": "يمكنك استخدام حساب / اشتراك Cursor أو إحضار مفاتيح نماذجك الخاصة (مبدأ BYOK). ولا يمرّر Open Design بيانات اعتمادك في كلتا الحالتين — فهي تُستخدَم مباشرةً بواسطة وكيلك."}, {"name": "‏Cursor أم Claude Code لتصميم الواجهة الأمامية؟", "text": "كلاهما قوي. يُعرَف Claude Code بقرارات تصميم محددة وواعية بقاعدة الشيفرة؛ وميزة Cursor هي حلقته المحكمة بالبناء-والمشاهدة مع معاينة حيّة داخل المحرّر. وتستخدم فرق كثيرة كليهما — ويتيح لك Open Design تبديل الوكلاء دون تغيير سير عمل التصميم."}, {"name": "كيف أصل Cursor بـ Figma؟", "text": "أضِف خادم Figma MCP الرسمي في Cursor، ثم الصق رابط إطار Figma في المحادثة واطلب من Cursor تنفيذه. يعرض الخادم مكوّنات ومتغيرات وبيانات تخطيط حقيقية كي تطابق الشيفرة المولَّدة تصميم المصدر."}, {"name": "كيف أتجنّب جماليّة «فوضى الذكاء الاصطناعي» العامة؟", "text": "أضف skill تصميم، وزوّده بـ tokens تصميم حقيقية ولقطات شاشة مرجعية، ورمّز قواعد العلامة في `.cursor/rules` أو `AGENTS.md`، وتحقق عبر نقاط التوقف في المعاينة. ويقدّم Open Design هذه بصفتها مكتبة منسّقة كي تتخطّى الإعداد لكل مشروع."}, {"name": "هل Open Design تابع لـ Cursor أو Anysphere؟", "text": "لا. Cursor منتج من Anysphere؛ وOpen Design مشروع مستقل مفتوح المصدر يدعمه بصفته محوّلًا أصيلًا. وCursor وAnysphere علامتان تجاريتان لـ Anysphere, Inc."}, {"name": "هل ملفاتي وبيانات اعتمادي آمنة؟", "text": "نعم — Open Design محلي أولًا. تبقى ملفاتك وآثارك وملف DESIGN.md في مستودعك الخاص، وتُستخدَم بيانات اعتماد Cursor أو النموذج مباشرةً بواسطة وكيلك، ولا تُمرَّر عبر خوادم Open Design أبدًا."}], "ctaTitle": "صمّم بـ Cursor، بالطريقة المفتوحة.", "ctaBody": "أحضر حساب Cursor أو مفاتيح النماذج الخاصة بك، واحتفظ بكل ملف محليًا، واحصل على مكتبة تصميم منسّقة حول الوكيل الذي تستخدمه أصلًا.", "ctaActions": [{"label": "استخدم Cursor داخل Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "ضع نجمة على GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "نزّل تطبيق سطح المكتب", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "اعرض كل الوكلاء المدعومين"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode للتصميم — Open Design",
        description: "كيف يستخدم الناس OpenCode في تصميم الواجهات والويب — ملفات design.md، skills واجهة المستخدم/تجربة المستخدم، Figma MCP — وكيف يحوّله Open Design إلى وكيل تصميم محلي أولًا ومفتوح المصدر.",
        breadcrumb: "OpenCode",
        label: "وكيل · OpenCode",
        heading: "OpenCode للتصميم.",
        lead: "‏OpenCode هو وكيل البرمجة الطرفي بالذكاء الاصطناعي مفتوح المصدر. يركّب عليه المصممون skills تصميم وملفات DESIGN.md لتوليد واجهات حقيقية. يجعل Open Design ذلك سير عمل منظّمًا مفتوح المصدر — أحضر مفاتيح مزوّدك، واحتفظ بكل شيء محليًا.",
        rich: {"heroCtaLead": "يحوّل Open Design الأداة OpenCode إلى وكيل تصميم محلي أولًا ومفتوح المصدر — أي نموذج تختاره بمفتاح مزوّدك الخاص، وملفاتك، ومكتبة منسّقة من الـ skills وأنظمة التصميم تحيط بها.", "heroCtaActions": [{"label": "استخدم OpenCode داخل Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "ضع نجمة على GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "نزّل تطبيق سطح المكتب", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["‏OpenCode هو وكيل برمجة بالذكاء الاصطناعي مفتوح المصدر يضع الطرفية أولًا ومحايد للنماذج عمدًا: تُحضر مفتاح مزوّدك الخاص وتشغّل أي نموذج تريده خلف سير العمل نفسه. هذا الانفتاح يجعله قاعدة طبيعية لعمل التصميم — لكنه، كأي وكيل، لا ينتج واجهة جيدة إلا حين تزوّده بالمراجع والـ skills وحلقة تحقق صحيحة. هذا دليل عملي وشامل لاستخدام OpenCode في عمل الواجهات والواجهة الأمامية وأنظمة التصميم، ولربطه بسير عمل تصميمي منظّم عبر Open Design.", "يغطّي ما هو OpenCode فعلًا، ولماذا يلائم وكيل مفتوح محايد للنماذج التصميم، وكيف تعدّه من الصفر، وحلقة من-لقطة-الشاشة-إلى-الواجهة، وكيف يوسّعه AGENTS.md وMCP، وكيف يقارَن بـ Codex وClaude Code وCursor، والمزالق التي تجعل مخرجات الذكاء الاصطناعي تبدو عامة، وكيف يسدّ Open Design الفجوة بصفته طبقة تصميم مفتوحة ومحلية أولًا — وهو اقتران طبيعي، إذ إن كلا المشروعين مفتوحا المصدر ويعملان على جهازك."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "حلقة تغذية راجعة لتصميم OpenCode: وكيل بواجهة طرفية نصية، ومتصفح يعرض الواجهة، ومساحة عمل، مع سهم تغذية راجعة يعود إلى البداية", "caption": "الحلقة الأساسية: يبني OpenCode الواجهة في الطرفية، ويعرضها ويتحقق منها في متصفح حقيقي، ويكرّر مقابل مراجعك — على أي نموذج تختاره."}, "tocLabel": "في هذه الصفحة", "toc": [{"id": "what-is-opencode", "label": "ما هو OpenCode فعلًا"}, {"id": "why-design", "label": "لماذا يلائم وكيل مفتوح متعدد النماذج التصميم"}, {"id": "setup", "label": "إعداد OpenCode للتصميم (من الصفر)"}, {"id": "screenshot-workflow", "label": "سير عمل من لقطة الشاشة إلى الواجهة"}, {"id": "extend", "label": "AGENTS.md وMCP والجلسات القابلة للمشاركة"}, {"id": "vs", "label": "‏OpenCode مقابل Codex مقابل Claude Code مقابل Cursor"}, {"id": "pitfalls", "label": "المزالق ومظهر «فوضى الذكاء الاصطناعي»"}, {"id": "open-design", "label": "التصميم بـ OpenCode داخل Open Design"}, {"id": "faq", "label": "الأسئلة الشائعة"}], "sections": [{"id": "what-is-opencode", "heading": "ما هو OpenCode فعلًا", "blocks": [{"kind": "p", "text": "‏OpenCode هو وكيل برمجة بالذكاء الاصطناعي مفتوح المصدر مبني للطرفية، يصونه الفريق وراء SST (Anomaly Innovations). يقرأ مستودعك، ويشغّل الأوامر، ويحرّر الملفات، ويتحدّث إلى نموذج لغوي كبير — لكنه، بخلاف الوكلاء المرتبطين بمزوّد، لا يأتي بنموذجه الخاص. توجّهه نحو أي مزوّد ونموذج تريده وتُحضر مفتاحك الخاص."}, {"kind": "p", "text": "يعمل بواجهة طرفية نصية (TUI)، مع تطبيق سطح مكتب وإضافات بيئات تطوير فوق المحرك نفسه. وتحت الغطاء يستخدم بنية عميل/خادم، فيكون الوكيل الذي ينجز العمل منفصلًا عن الواجهة التي تقوده منها. ويتبدّل وكيلان مدمجان — build وplan — بمفتاح Tab."}, {"kind": "steps", "items": [{"label": "محايد للنماذج", "body": "تأتي النماذج والمزوّدون من models.dev، وهو كتالوج مفتوح. تهيّئهم في opencode.json بسلسلة provider/model-id ويمكنك تعطيل المزوّدين الذين لا تريد تحميلهم — فيعمل سير عمل التصميم نفسه على Anthropic وOpenAI وGoogle وOpenRouter والنماذج المحلية والمزيد."}, {"label": "ملف التعليمات", "body": "يقرأ OpenCode ملف AGENTS.md في مشروعك (المعيار متعدد الأدوات، المتوافق أيضًا مع CLAUDE.md) لقواعد المشروع — المكان الطبيعي لترميز أعراف التصميم لديك. شغّل /init لتوليد واحد."}, {"label": "قابل للتوسيع", "body": "يدعم تكامل LSP وخوادم MCP والثيمات واختصارات المفاتيح والأوامر المخصّصة، إضافةً إلى روابط جلسات قابلة للمشاركة للتعاون."}]}, {"kind": "ul", "items": ["الصائن: SST / Anomaly Innovations (مشروع مفتوح المصدر)", "بيانات الاعتماد: مفاتيح API الخاصة بمزوّد نماذجك — مبدأ BYOK، بلا ارتباط بمزوّد", "الرخصة: MIT، مفتوحة المصدر"]}]}, {"id": "why-design", "heading": "لماذا يلائم وكيل مفتوح متعدد النماذج عمل التصميم", "blocks": [{"kind": "p", "text": "لا يملك OpenCode «نموذج تصميم» واحدًا كما يملك وكيل مرتبط بمزوّد — وهذا هو المغزى. ولأنه محايد للنماذج ومفتوح، يمكنك تشغيل سير عمل التصميم نفسه على أي نموذج أفضل حاليًا في الواجهة الأمامية، أو تبديله لاحقًا، أو الرجوع إلى نموذج محلي، كل ذلك دون تغيير إعدادك."}, {"kind": "p", "text": "لكن اختيار النموذج وحده لا يشتري ذوقًا. وكأي وكيل برمجة، ينتج OpenCode واجهة عامة ما لم تمنحه قيودًا. ومخرجات التصميم الجيدة تأتي من ثلاثة مدخلات تقدّمها أنت."}, {"kind": "steps", "items": [{"label": "نظام تصميم", "body": "tokens وعناصر أولية وأعراف حقيقية يعيد الوكيل استخدامها، كي تطابق المخرجات هوية علامة بدلًا من العودة إلى مظهر عام."}, {"label": "skill جمالي", "body": "skill منسّق يفرض ذوقًا حقيقيًا — حركة مقيّدة، هرمية تقدّم العلامة، خطّان كحد أقصى ولون توكيد واحد — ويجعل الوكيل يلتزم باتجاه قبل البناء."}, {"label": "مراجع ملموسة", "body": "صور مرجعية فعلية وحالات متعددة (سطح المكتب والجوال، التحويم، الفارغ، التحميل)، لا لقطة بطل واحدة."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "رسم تخطيطي يوضّح تقارب نظام التصميم والـ skill والصورة المرجعية نحو مخرجات تصميم جيدة", "caption": "ينبع الذوق من ثلاثة مدخلات تقدّمها أنت: نظام تصميم، وskill، وصور مرجعية حقيقية — بمعزل عن النموذج الذي تشغّله."}, {"kind": "p", "text": "الدرس: يمنحك OpenCode حرية النماذج، لكن الذوق ما زال يأتي من سياق تصميم منسّق. ويجمع Open Design تلك المدخلات بالضبط، ولهذا يتلاءم الاثنان معًا — كلاهما مفتوح المصدر ومحلي أولًا (المزيد أدناه)."}]}, {"id": "setup", "heading": "إعداد OpenCode لعمل التصميم، من الصفر", "blocks": [{"kind": "p", "text": "هذا هو المسار الكامل من جهاز نظيف إلى OpenCode قادر على بناء الواجهة والتحقق منها."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "سير إعداد من خمس خطوات: التثبيت، المصادقة بمفتاح مزوّدك، تهيئة AGENTS.md، إضافة skill، التحقق", "caption": "تسلسل الإعداد: التثبيت ← المصادقة (مفتاح مزوّدك) ← تهيئة AGENTS.md ← إضافة skill ← التحقق في متصفح حقيقي."}, {"kind": "steps", "items": [{"label": "رمّز قواعد التصميم لديك", "body": "ضع tokens وعناصرك الأولية وأعرافك في AGENTS.md (أو في DESIGN.md مُشار إليه منه) كي تطابق المخرجات هوية علامة بدلًا من العودة إلى مظهر عام. ويمكن لخيار instructions في opencode.json أن يشير إلى ملفات قواعد إضافية عبر الأنماط."}, {"label": "اختر نموذجًا قادرًا", "body": "لأن OpenCode محايد للنماذج، اختر المزوّد/النموذج الأقوى حاليًا في الواجهة الأمامية لتمريرة التصميم — وأبقِ بقية سير عملك دون تغيير."}]}]}, {"id": "screenshot-workflow", "heading": "سير عمل من لقطة الشاشة إلى الواجهة", "blocks": [{"kind": "p", "text": "أعلى حلقات التصميم رافعةً مع أي وكيل هي تحويل صورة مرجعية إلى واجهة عاملة ومتجاوبة والتكرار حتى تطابق. وينطبق الشكل نفسه من خمس خطوات في OpenCode."}, {"kind": "ol", "items": ["ابدأ من أوضح المراجع البصرية لديك — وضمّن حالات متعددة (سطح المكتب والجوال، التحويم، الفارغ، التحميل)، لا لقطة بطل واحدة فقط.", "كن محددًا في المطالبة؛ فالمطالبات الغامضة تنتج واجهة عامة.", "جهّز نظام تصميم وأخبر OpenCode بمكان الـ tokens والعناصر الأولية المرجعية (في AGENTS.md).", "شغّل خادم تطوير واجعل الوكيل يعرض في متصفح حقيقي، مغيّرًا الحجم إلى نقاط التوقف لفحص النتيجة.", "كرّر بجعل OpenCode يقارن تنفيذه بلقطات الشاشة — لا أن يكتفي بتأكيد البناء."]}, {"kind": "p", "text": "أشِر إلى الملفات بـ @ في الواجهة الطرفية لبحث ضبابي في مجلد عملك، وشغّل أوامر الصدفة مضمّنةً ببادئة !، وقُد الإجراءات بأوامر /. ثم أرسِل مطالبة بقيود ملموسة:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "أبقِ المطالبات صغيرة ومركّزة، وثبّت التكرارات الجيدة وأرجِع السيئة (مع إخبار OpenCode حين تُرجِع)، كي تبني كل تمريرة على قاعدة نظيفة."}]}, {"id": "extend", "heading": "AGENTS.md وMCP والجلسات القابلة للمشاركة", "blocks": [{"kind": "p", "text": "ثلاث نقاط توسيع تجعل OpenCode عمليًا لعمل التصميم المستمر، وتنطبق الثلاث جميعًا بسلاسة على سير عمل تصميم مفتوح."}, {"kind": "steps", "items": [{"label": "قواعد AGENTS.md", "body": "تعيش قواعد المشروع في AGENTS.md في جذر المستودع (أو قواعد عامة في ~/.config/opencode/AGENTS.md). إنه المنزل الدائم لأعراف التصميم لديك، يُقرأ في كل تشغيل، وهو متوافق مع ملفات CLAUDE.md التي تستخدمها وكلاء أخرى."}, {"label": "خوادم MCP", "body": "يدعم OpenCode خوادم MCP المحلية (أمر) والبعيدة (URL)، المهيّأة تحت مفتاح mcp — الطريقة المحمولة لجلب سياق التصميم والأدوات الخارجية التي تعمل عبر الوكلاء، لا OpenCode فقط."}, {"label": "جلسات قابلة للمشاركة", "body": "ينشئ الأمر /share رابطًا عامًا لمحادثة للتعاون أو المراجعة، ويلغيه /unshare — مفيد للحصول على ملاحظات على تمريرة تصميم."}]}, {"kind": "p", "text": "هذه قدرات محمولة متعددة الوكلاء — تمامًا نوع الشيء الذي بُني Open Design لتنسيقه، بدلًا من إعادة بنائه لكل مشروع."}]}, {"id": "vs", "heading": "‏OpenCode مقابل Codex مقابل Claude Code مقابل Cursor للتصميم", "blocks": [{"kind": "p", "text": "لا يوجد فائز واحد في عمل التصميم — فلكل وكيل قوة مختلفة، والفرق المتمرّسة تجمع بينها. وإليك خلاصة منصفة:"}, {"kind": "table", "columns": ["الوكيل", "قوة التصميم", "الأنسب لـ"], "rows": [["OpenCode", "مفتوح المصدر ومحايد للنماذج؛ شغّل أي مزوّد خلف سير عمل طرفي واحد", "حرية BYOK، وتبديل النماذج، والإعدادات المفتوحة والمحلية أولًا بالكامل"], ["Codex", "صقل بصري قوي مع frontend skill؛ فهم للصور", "غير المتزامن المفوّض، عمليات البناء المعزولة، قواعد AGENTS.md المحمولة"], ["Claude Code", "قرارات تصميم محددة (hex، مسافات، خطوط) وتجربة مستخدم واعية بقاعدة الشيفرة", "تفكير الواجهة الأمامية وإعادة الهيكلة بسياق واسع"], ["Cursor", "حلقة بناء-ومشاهدة بصرية مع معاينة حيّة وتحريرات مضمّنة", "عمل واجهة محكم بالتكرار-والمراقبة داخل بيئة تطوير"]]}, {"kind": "p", "text": "الحكم المتكرر في المجتمع أن الذوق يأتي من البشر: فجميعها تتجه افتراضيًا إلى مظهر عام دون skills ومراجع وقيود. تلك هي المشكلة الحقيقية التي ينبغي حلّها — وهي بشكل أداة تصميم، لا بشكل نموذج، وهذا بالضبط سبب تلاؤم وكيل مفتوح مثل OpenCode تلاؤمًا جيدًا مع طبقة تصميم مفتوحة."}]}, {"id": "pitfalls", "heading": "المزالق، وكيف تتجنّب مظهر «فوضى الذكاء الاصطناعي»", "blocks": [{"kind": "p", "text": "أكثر شكوى شيوعًا عن التصميم المولَّد بالذكاء الاصطناعي أنه يبدو عامًا — تدرّجات ناعمة، لوحات عائمة، زوايا دائرية مفرطة الحجم، ظلال دراميّة، أجواء Inter-والبنفسجي «تصرخ بأن ذكاءً اصطناعيًا صنع هذا.» وتشمل المشكلات الأخرى المبلَّغ عنها انكسار تخطيطات الجوال وتسرّب التعليمات إلى نصوص الواجهة. وليست أيٌّ منها خاصةً بـ OpenCode؛ بل هي ما يحدث حين يعمل أي وكيل دون سياق تصميم منسّق."}, {"kind": "steps", "items": [{"label": "أضف skill جماليًا", "body": "skill تصميم منسّق يجبر الوكيل على الالتزام باتجاه حقيقي بدلًا من المظهر الافتراضي."}, {"label": "تحقق في متصفح حقيقي", "body": "اعرض وتحقق ذاتيًا عبر نقاط التوقف كي لا تنكسر التخطيطات بصمت على الجوال."}, {"label": "زوّده بالـ tokens والمراجع", "body": "tokens التصميم الحقيقية ولقطات الشاشة المرجعية هي أكبر رافعة منفردة على جودة المخرجات."}, {"label": "رمّز القواعد في AGENTS.md", "body": "ضع قواعد بأسلوب «لا بطاقات بطل، خطّان كحد أقصى، هرمية تقدّم العلامة» حيث يقرؤها الوكيل في كل تشغيل."}]}, {"kind": "p", "text": "لاحظ أن كل إجراء تخفيف يتمحور حول منح الوكيل سياق تصميم منسّقًا — بمعزل عن النموذج الذي تشغّله. والحفاظ على ذلك السياق يدويًا، لكل مشروع، هو الكدّ الذي يزيله Open Design."}]}, {"id": "open-design", "heading": "التصميم بـ OpenCode داخل Open Design", "blocks": [{"kind": "p", "text": "‏Open Design هو طبقة التصميم مفتوحة المصدر التي يطلبها سير العمل أعلاه باستمرار. يعامل OpenCode بصفته محوّلًا أصيلًا ويغلّفه بمكتبة منسّقة من الـ skills وأنظمة التصميم، وخط معالجة عرض منظّم، وواجهة سطح مكتب محلية — كي يكون سياق التصميم الذي يجعل أي وكيل جيدًا حاضرًا من أول تشغيل، لا مُجمَّعًا يدويًا في كل مرة. وكلا المشروعين مفتوحا المصدر ومحليان أولًا، ما يجعل الاقتران ملائمًا بطبيعته."}, {"kind": "ol", "items": ["ثبّت Open Design واختر OpenCode وكيلًا لك.", "صادِق بمفتاح API الخاص بمزوّد نماذجك (مبدأ BYOK) — تبقى بيانات الاعتماد على جهازك ولا تُمرَّر عبرنا أبدًا.", "اختر أي مزوّد ونموذج، إضافةً إلى نظام تصميم وskill، ثم ولّد العروض والنماذج الأولية وصفحات الهبوط بذوق متّسق.", "كل أثر وكل ملف DESIGN.md يعيش في مستودعك الخاص، لا في سحابة مستضافة."]}, {"kind": "p", "text": "وكيل OpenCode نفسه، حرية النماذج نفسها — إضافةً إلى سير عمل تصميمي حقيقي ومحمول ومفتوح المصدر يحيط به. إنه محلي أولًا وبرخصة Apache-2.0، فلا شيء عن عملك أو بيانات اعتمادك يغادر جهازك."}]}], "faqTitle": "الأسئلة الشائعة", "faq": [{"name": "هل يستطيع OpenCode فعلًا أداء عمل التصميم؟", "text": "نعم — مع skill جمالي ونظام تصميم وصور مرجعية حقيقية في السياق، ينتج OpenCode واجهة بجودة إنتاجية ومتجاوبة ويمكنه التحقق منها في متصفح. ولأنه محايد للنماذج، تشغّل النموذج الأفضل حاليًا في الواجهة الأمامية. وبدون ذلك السياق المنسّق يميل إلى مظهر عام، وهي الفجوة التي يسدّها Open Design."}, {"name": "أي نموذج ينبغي أن أستخدم مع OpenCode للتصميم؟", "text": "أيًّا أحببت — OpenCode محايد للمزوّدين عبر models.dev، فيمكنك تشغيل Anthropic أو OpenAI أو Google أو OpenRouter أو نماذج محلية خلف سير العمل نفسه والتبديل في أي وقت. وتعتمد جودة مخرجات التصميم على skill ونظام تصميمك ومراجعك أكثر بكثير من النموذج وحده."}, {"name": "هل صنع Open Design فريق OpenCode (SST)؟", "text": "لا. Open Design مشروع مستقل مفتوح المصدر يدمج OpenCode بصفته وكيلًا. وهو يكمّل OpenCode بمكتبة skills وأنظمة تصميم مفتوحة ومحلية أولًا."}, {"name": "هل أحتاج إلى اشتراك خاص للتصميم بـ OpenCode؟", "text": "لا — OpenCode يقوم على مبدأ BYOK. تُحضر مفتاح API الخاص بمزوّد نماذجك، ولا يمرّر Open Design بيانات اعتمادك أبدًا. ولا يوجد ارتباط بمزوّد."}, {"name": "‏OpenCode أم Codex أم Claude Code لتصميم الواجهة الأمامية؟", "text": "جميعها قوية، وفرق كثيرة تجمع بينها. ميزة OpenCode أنه مفتوح المصدر بالكامل ومحايد للنماذج؛ ويتفوّق Codex في عمليات البناء المفوّضة المعزولة؛ ويُعرَف Claude Code بقرارات تصميم محددة وواعية بقاعدة الشيفرة. ويتيح لك Open Design تبديل الوكلاء دون تغيير سير عمل التصميم."}, {"name": "كيف أوسّع OpenCode من أجل سياق التصميم؟", "text": "رمّز القواعد في AGENTS.md، وأضِف خوادم MCP تحت مفتاح mcp للأدوات المحمولة وسياق التصميم، واستخدم الجلسات القابلة للمشاركة للمراجعة. ويقدّم Open Design مكتبة منسّقة من الـ skills وأنظمة التصميم كي تتخطّى الإعداد لكل مشروع."}, {"name": "هل Open Design تابع لـ OpenCode أو SST؟", "text": "لا. OpenCode مشروع مفتوح المصدر يصونه SST (Anomaly Innovations)؛ وOpen Design مشروع مستقل مفتوح المصدر يدعمه بصفته محوّلًا أصيلًا."}, {"name": "هل ملفاتي وبيانات اعتمادي آمنة؟", "text": "نعم — Open Design محلي أولًا. تبقى ملفاتك وآثارك وملف DESIGN.md في مستودعك الخاص، وتُستخدَم بيانات اعتماد مزوّد نماذجك مباشرةً بواسطة وكيلك، ولا تُمرَّر عبر خوادم Open Design أبدًا."}], "ctaTitle": "صمّم بـ OpenCode، بالطريقة المفتوحة.", "ctaBody": "أحضر مفتاح مزوّد نماذجك الخاص، واحتفظ بكل ملف محليًا، واحصل على مكتبة تصميم منسّقة حول الوكيل المفتوح الذي تستخدمه أصلًا.", "ctaActions": [{"label": "استخدم OpenCode داخل Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "ضع نجمة على GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "نزّل تطبيق سطح المكتب", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "اعرض كل الوكلاء المدعومين"},
      },
    },
    'tr': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Tasarım için Claude Code — Open Design",
        description: "Tasarımcılar Claude Code'u UI ve web tasarımı için nasıl kullanır ve Open Design onu nasıl gerçek bir tasarım ajanına dönüştürür — yerel öncelikli, BYOK, özenle seçilmiş skill ve tasarım sistemi kütüphanesiyle.",
        breadcrumb: "Claude Code",
        label: "Ajan · Claude Code",
        heading: "Tasarım için Claude Code.",
        lead: "Claude Code, Anthropic'in terminal kodlama ajanıdır. İnsanlar onu zaten UI'lar, tasarım sistemleri ve açılış sayfaları oluşturmak için kullanıyor. Open Design onu gerçek bir tasarım iş akışına bağlar — Anthropic anahtarınızı veya Claude aboneliğinizi getirin, her dosyayı yerel tutun.",
        rich: {"heroCtaLead": "Open Design, Claude Code'u yerel öncelikli, açık kaynaklı bir tasarım ajanına dönüştürür — Anthropic anahtarınız veya Claude aboneliğiniz, dosyalarınız ve etrafında özenle seçilmiş bir skill ve tasarım sistemi kütüphanesi.", "heroCtaActions": [{"label": "Claude Code'u Open Design içinde kullanın", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub'da yıldız verin", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Masaüstü uygulamasını indirin", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code, frontend konusunda en iyi zevke sahip kodlama ajanı olarak yaygın biçimde kabul edilir — arayüzler üzerinde alışılmadık bir kesinlikle akıl yürütür, tam hex değerlerini, boşlukları ve tipografi ölçeklerini adlandırır ve büyük bir kod tabanı boyunca UI'ı, bağlamı kaybetmeden yeniden düzenler. Ama kutudan çıktığı haliyle, ona bir tasarım sistemi, skill'ler ve gerçek referanslar vermediğiniz sürece yine de jenerik bir görünüme kayar. Bu, Claude Code'u UI, frontend ve tasarım sistemi çalışmaları için kullanmaya ve onu Open Design ile yapılandırılmış bir iş akışına bağlamaya dair pratik, uçtan uca bir rehberdir.", "Claude Code'un gerçekte ne olduğunu, frontend'de neden güçlü olduğunu, sıfırdan nasıl kurulacağını, CLAUDE.md ve Skills iş akışını, resmi Figma gidiş-dönüşünü, Codex ve Cursor ile nasıl karşılaştırıldığını, AI çıktısını jenerik gösteren tuzakları ve Open Design'ın açık, yerel öncelikli bir tasarım katmanı olarak bu boşluğu nasıl kapattığını ele alır."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Claude Code tasarım geri bildirim döngüsü: spesifik tasarım kararları veren terminal ajanı, UI'ı işleyen bir tarayıcı ve bir çalışma alanı, geri döngü oluşturan bir geri bildirim okuyla", "caption": "Çekirdek döngü: Claude Code terminalde spesifik UI kararlarını akıl yürüterek belirler, bunları gerçek bir tarayıcıda işler ve doğrular, referanslarınıza karşı yakınsar."}, "tocLabel": "Bu sayfada", "toc": [{"id": "what-is-claude-code", "label": "Claude Code gerçekte nedir"}, {"id": "why-design", "label": "Claude Code tasarımda neden iyi"}, {"id": "setup", "label": "Claude Code'u tasarım için kurun (sıfırdan)"}, {"id": "skills-workflow", "label": "CLAUDE.md ve Skills iş akışı"}, {"id": "figma", "label": "Claude Code + Figma gidiş-dönüşü"}, {"id": "vs", "label": "Claude Code, Codex ve Cursor karşılaştırması"}, {"id": "pitfalls", "label": "Tuzaklar ve “AI çöplüğü” görünümü"}, {"id": "open-design", "label": "Open Design içinde Claude Code ile tasarım"}, {"id": "faq", "label": "SSS"}], "sections": [{"id": "what-is-claude-code", "heading": "Claude Code gerçekte nedir", "blocks": [{"kind": "p", "text": "Claude Code, Anthropic'in ajansal kodlama aracıdır. Kod tabanınızı okur, dosyaları düzenler, komutları çalıştırır ve geliştirme araçlarınızla entegre olur — yalnızca satırları otomatik tamamlamak yerine doğal dildeki görevlerden işi planlar, yazar ve doğrular."}, {"kind": "p", "text": "Hepsi aynı motoru paylaşan birkaç yüzey üzerinden sunulur: bir terminal CLI'si, VS Code, Cursor ve JetBrains için IDE eklentileri, görsel diff incelemesi olan bir masaüstü uygulaması ve uzun süren görevler için bir web deneyimi. CLAUDE.md dosyalarınız, ayarlarınız ve MCP sunucularınız hepsinde geçerlidir."}, {"kind": "steps", "items": [{"label": "Talimat dosyası", "body": "Claude Code, her oturumun başında proje kökünüzdeki bir CLAUDE.md dosyasını okur — tasarım kurallarınızı, token'larınızı ve inceleme kontrol listelerinizi kodlamak için doğal yer."}, {"label": "Skills", "body": "Agent Skills, Claude'un talep üzerine yüklediği yinelenebilir talimatları, betikleri ve kaynakları paketler; buna zevk için Anthropic'in resmi Frontend Design skill'i de dahildir."}, {"label": "Plan ve alt ajanlar", "body": "Eylemden önce plan yapabilir ve bir görevin farklı parçaları üzerinde paralel çalışan alt ajanlar başlatabilir; bu da büyük UI yeniden düzenlemelerini tutarlı tutar."}]}, {"kind": "ul", "items": ["Sağlayıcı: Anthropic", "Kimlik bilgisi: Anthropic API anahtarı (BYOK, Console üzerinden) veya bir Claude aboneliği (Pro / Max)", "Yüzeyler: terminal CLI, VS Code / Cursor / JetBrains eklentileri, masaüstü uygulaması, web"]}]}, {"id": "why-design", "heading": "Claude Code tasarımda neden iyi", "blocks": [{"kind": "p", "text": "Kodlama ajanları arasında Claude Code, frontend çalışmasında zevk konusunda bir üne sahiptir. Birkaç şey bunu açıklar."}, {"kind": "steps", "items": [{"label": "Belirsiz değil, spesifik kararlar", "body": "Claude Code, el sallayarak geçiştirmek yerine somut seçimlere bağlanma eğilimindedir — tam hex değerleri, boşluk ölçekleri, tipografi rampaları ve bileşen hiyerarşisi — gerçek bir arayüzü bir yer tutucudan ayıran şey de budur."}, {"label": "Kod tabanının farkında akıl yürütme", "body": "Geniş bir çalışma bağlamıyla, UI'ı bir kerede birçok dosya boyunca yeniden düzenler; tek seferlik stiller icat etmek yerine mevcut bileşenlerinizi ve token'larınızı yeniden kullanır."}, {"label": "Resmi bir frontend skill'i", "body": "Anthropic, Claude'un önce bir tasarım yönü yazmasını sağlayan ve jenerik sistem yazı tiplerinden ve tahmin edilebilir mor degradelerden bilinçli olarak uzaklaşan bir Frontend Design skill'i sunar."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Tasarım sistemi, skill ve referans görselin iyi tasarım çıktısına yakınsadığını gösteren diyagram", "caption": "Zevk, sağladığınız üç girdiden gelir: bir tasarım sistemi, bir skill ve gerçek referans görseller."}, {"kind": "p", "text": "Çıkarılan ders, Anthropic'in kendi modelleri hakkında söylediğiyle aynıdır: Claude varsayılan olarak zevke sahip değildir — kendi haline bırakılırsa web tasarımının istatistiksel merkezine yakınsar (Inter, mor degradeler, yumuşak gölgeler). Ona kısıtlar verdiğinizde iyi tasarım üretir. Open Design tam olarak bu girdileri paketler; ikisinin neden birbirine uyduğunun nedeni de budur (daha fazlası aşağıda)."}]}, {"id": "setup", "heading": "Claude Code'u tasarım çalışması için sıfırdan kurun", "blocks": [{"kind": "p", "text": "Temiz bir makineden, UI oluşturabilen ve doğrulayabilen bir Claude Code'a giden tam yol şudur."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Beş adımlı kurulum akışı: kur, kimlik doğrula, CLAUDE.md yapılandır, skill ekle, doğrula", "caption": "Kurulum sırası: kur → kimlik doğrula → CLAUDE.md yapılandır → Frontend Design skill'ini ekle → tarayıcı doğrulamasını etkinleştir."}, {"kind": "steps", "items": [{"label": "Tasarım kurallarınızı kodlayın", "body": "Token'larınızı, ilkellerinizi ve kurallarınızı CLAUDE.md içine koyun ve Claude'u bunlara yönlendirin; böylece çıktı jenerik bir görünüme dönmek yerine bir markayla eşleşsin."}, {"label": "Tarayıcı doğrulaması ekleyin", "body": "Bir Playwright veya Chrome MCP bağlayın, böylece Claude yalnızca derlemenin geçtiğini onaylamak yerine gerçek bir tarayıcıda işlesin ve çıktısını kırılma noktaları boyunca kontrol etsin."}]}]}, {"id": "skills-workflow", "heading": "CLAUDE.md ve Skills iş akışı", "blocks": [{"kind": "p", "text": "Claude Code ile en yüksek kaldıraçlı tasarım döngüsü, ona gerçek referansları artı tasarım bağlamınızı beslemek ve ardından UI eşleşene kadar yinelemektir — CLAUDE.md ve Skills kısıtları taşır, böylece bunları her komutta yeniden açıklamazsınız."}, {"kind": "ol", "items": ["Sahip olduğunuz en net görsel referanslardan başlayın — ve yalnızca tek bir hero görseli değil, birden çok durumu (masaüstü ve mobil, hover, boş, yükleniyor) dahil edin.", "Komutta spesifik olun; belirsiz komutlar, güçlü bir ajanla bile jenerik UI üretir.", "Tasarım sisteminizi ve kurallarınızı CLAUDE.md içinde tutun ve Claude'a token'ların ve kanonik ilkellerin nerede yaşadığını söyleyin.", "Frontend Design skill'ini ekleyin, böylece Claude kod yazmadan önce gerçek bir estetik yöne bağlansın.", "Tarayıcı doğrulamasını bağlayın, böylece Claude işlesin, kırılma noktalarına yeniden boyutlandırsın ve referanslarla karşılaştırsın — yalnızca derlendiğini onaylamasın."]}, {"kind": "p", "text": "Oturuma bir referans görseli bırakın ve somut kısıtlarla komut verin:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Yanında bir dev sunucusu çalıştırın, komutları küçük ve odaklı tutun, iyi yinelemeleri commit edin / kötü olanları geri alın (geri aldığınızda Claude'a söyleyin), böylece her geçiş temiz bir temel üzerine inşa edilsin. Büyük yeniden düzenlemeler için plan modunu kullanın, böylece herhangi bir dosya değişikliğinden önce yaklaşımı inceleyebilirsiniz."}]}, {"id": "figma", "heading": "Claude Code + Figma: tasarım ↔ kod gidiş-dönüşü", "blocks": [{"kind": "p", "text": "Şubat 2026'da Anthropic ve Figma, Figma MCP sunucusu aracılığıyla birinci sınıf, çift yönlü bir entegrasyon yayınladı. Her iki yönde de çalışır."}, {"kind": "steps", "items": [{"label": "Tasarım → Kod", "body": "Figma'da bir frame seçin veya Claude Code'a bir bağlantı yapıştırın, tasarım bağlamını çekin ve ondan mevcut bileşen kütüphanenizi kullanarak tasarımı uygulamasını isteyin. Code Connect, çıktıyı gerçek bileşenlerinizle hizalı tutar."}, {"label": "Kod → Tasarım", "body": "Bir özelliği tarayıcıda oluşturup önizleyin, ardından çalışan UI'ı düzenlenebilir Figma katmanları olarak yakalamak için “Send this to Figma” deyin — tüm ekran veya seçili bir öğe."}]}, {"kind": "p", "text": "Bir kez claude plugin install figma@claude-plugins-official ile kurun (Dev Mode MCP, ücretli bir Figma planı gerektirir). Aynı Figma MCP; Claude Code, Codex, Cursor ve VS Code için kullanılabilir — tam olarak Open Design'ın düzenlemek için inşa edildiği türden taşınabilir, çok ajanlı bir yetenek."}]}, {"id": "vs", "heading": "Tasarım için Claude Code, Codex ve Cursor", "blocks": [{"kind": "p", "text": "Tasarım çalışması için tek bir kazanan yoktur — her ajanın farklı bir gücü vardır ve deneyimli ekipler bunları üst üste yığar. Adil bir özet:"}, {"kind": "table", "columns": ["Ajan", "Tasarım gücü", "En iyi olduğu alan"], "rows": [["Claude Code", "Spesifik tasarım kararları (hex, boşluk, tipografi) ve kod tabanının farkında UX akıl yürütmesi", "Frontend akıl yürütmesi ve geniş bağlamlı yeniden düzenlemeler"], ["Codex", "Güçlü görsel cila ve görsel anlama; sandbox'lanmış asenkron derlemeler", "Devredilen asenkron derlemeler ve taşınabilir AGENTS.md kuralları"], ["Cursor", "Canlı önizleme ve satır içi düzenlemelerle görsel oluştur-ve-gör döngüsü", "Bir IDE içinde sıkı yinele-ve-izle UI çalışması"]]}, {"kind": "p", "text": "Tekrarlanan topluluk kararı, zevkin insanlardan geldiğidir: üçü de skill'ler, referanslar ve kısıtlar olmadan jenerik bir estetiğe varsayılan olarak kayar. Çözülmesi gereken asıl sorun budur — ve bu sorun, model biçimli değil, tasarım aracı biçimlidir."}]}, {"id": "pitfalls", "heading": "Tuzaklar ve “AI çöplüğü” görünümünden nasıl kaçınılır", "blocks": [{"kind": "p", "text": "Claude Code'un zevk konusundaki ününe rağmen, AI tarafından üretilen tasarımla ilgili en yaygın şikayet, jenerik görünmesidir — Inter yazı tipleri, beyaz üzerine mor degradeler, yumuşak gölgeler, aşırı büyük yuvarlatılmış köşeler, “bunu bir AI yaptı diye bağıran” bir estetik. Anthropic bunu dağılımsal yakınsamaya bağlar: güvenli seçimler web eğitim verilerine hakimdir. Bildirilen diğer sorunlar arasında bozuk mobil düzenler ve UI metnine sızan talimatlar yer alır."}, {"kind": "steps", "items": [{"label": "Frontend Design skill'ini kurun", "body": "Claude'u gerçek bir yöne bağlanmaya zorlar ve AI tarafından aşırı kullanılan yazı tiplerinden ve degradelerden açıkça kaçınır."}, {"label": "Tarayıcı doğrulamasını etkinleştirin", "body": "Claude'un kırılma noktaları boyunca işlemesini ve kendi kendini kontrol etmesini sağlayın, böylece düzenler mobilde sessizce bozulmasın."}, {"label": "Token ve referans sağlayın", "body": "Gerçek tasarım token'ları ve referans ekran görüntüleri, çıktı kalitesi üzerindeki en büyük tek kaldıraçtır."}, {"label": "Kuralları CLAUDE.md içinde kodlayın", "body": "“hero kartı yok, en fazla iki yazı tipi, marka öncelikli hiyerarşi” gibi kuralları, ajanın her çalıştırmada okuduğu yere koyun."}]}, {"kind": "p", "text": "Her hafifletmenin, ajana özenle seçilmiş bir tasarım bağlamı vermekle ilgili olduğuna dikkat edin. Bu bağlamı proje başına elle sürdürmek, Open Design'ın ortadan kaldırdığı zahmettir."}]}, {"id": "open-design", "heading": "Open Design içinde Claude Code ile tasarım", "blocks": [{"kind": "p", "text": "Open Design, yukarıdaki iş akışının sürekli istediği açık kaynaklı tasarım katmanıdır. Claude Code'u birinci taraf bir adaptör olarak ele alır ve onu özenle seçilmiş bir skill ve tasarım sistemi kütüphanesi, yapılandırılmış bir render hattı ve yerel bir masaüstü UI'sı ile sarmalar — böylece Claude Code'u iyi yapan tasarım bağlamı, her seferinde elle bir araya getirilmek yerine ilk çalıştırmadan itibaren oradadır."}, {"kind": "ol", "items": ["Open Design'ı kurun ve ajanınız olarak Claude Code'u seçin.", "Anthropic API anahtarınız (BYOK) veya Claude aboneliğinizle kimlik doğrulayın — kimlik bilgileri makinenizde kalır ve asla bizim üzerimizden proxy'lenmez.", "Bir tasarım sistemi ve bir skill seçin, ardından tutarlı bir zevkle sunumlar, prototipler ve açılış sayfaları üretin.", "Her artefakt ve DESIGN.md dosyası, barındırılan bir bulutta değil, kendi reponuzda yaşar."]}, {"kind": "p", "text": "Aynı Claude Code ajanı, aynı anahtar — artı etrafında gerçek, taşınabilir, açık kaynaklı bir tasarım iş akışı. Yerel öncelikli ve Apache-2.0'dır, bu yüzden çalışmanız veya kimlik bilgileriniz hakkında hiçbir şey makinenizden ayrılmaz."}]}], "faqTitle": "Sıkça sorulan sorular", "faq": [{"name": "Claude Code tasarım çalışması için iyi mi?", "text": "Evet — frontend konusunda en iyi zevke sahip kodlama ajanı olarak yaygın biçimde kabul edilir; hex değerleri, boşluk ve tipografi ölçekleri hakkında spesifik, kod tabanının farkında kararlar verir. Frontend Design skill'i, bir tasarım sistemi ve bağlamdaki gerçek referans görsellerle, üretim kalitesinde, duyarlı UI üretir ve bunu bir tarayıcıda doğrulayabilir. Bu bağlam olmadan jenerik bir görünüme dönme eğilimindedir; Open Design'ın doldurduğu boşluk da budur."}, {"name": "Claude Code ile tasarım yapmak için bir Claude aboneliğine ihtiyacım var mı?", "text": "Bir Anthropic API anahtarı (BYOK, Console üzerinden) veya bir Claude aboneliği (Pro / Max) kullanabilirsiniz. Her iki durumda da Open Design kimlik bilgilerinizi asla proxy'lemez — bunlar doğrudan makinenizdeki ajanınız tarafından kullanılır."}, {"name": "Frontend tasarımı için Claude Code mı yoksa Codex mı?", "text": "İkisi de güçlüdür. Claude Code, spesifik, kod tabanının farkında tasarım kararları ve frontend akıl yürütmesiyle bilinir; Codex'in güçlü bir görsel cilası vardır ve devredilen, sandbox'lanmış derlemelerde öne çıkar. Birçok ekip ikisini de kullanır — Open Design, tasarım iş akışınızı değiştirmeden ajanlar arasında geçiş yapmanızı sağlar."}, {"name": "Claude Code'u Figma'ya nasıl bağlarım?", "text": "Resmi Figma eklentisini claude plugin install figma@claude-plugins-official ile kurun. Ardından tasarım bağlamını kullanarak Figma frame'lerini kod olarak uygulayabilir ve çalışan bir UI'ı “Send this to Figma” ile düzenlenebilir Figma frame'lerine geri gönderebilirsiniz. Dev Mode MCP, ücretli bir Figma planı gerektirir."}, {"name": "Skills ve CLAUDE.md nedir?", "text": "CLAUDE.md, Claude Code'un her oturumun başında okuduğu, proje kökünüzdeki bir markdown dosyasıdır — tasarım kurallarınızı kodlama yeri. Skills, Claude'un talep üzerine yüklediği yinelenebilir talimatları ve kaynakları paketler; buna Anthropic'in resmi Frontend Design skill'i de dahildir. Open Design her ikisinden de özenle seçilmiş bir kütüphane sunar, böylece proje başına kurulumu atlarsınız."}, {"name": "Jenerik “AI çöplüğü” estetiğinden nasıl kaçınırım?", "text": "Frontend Design skill'ini kurun, gerçek tasarım token'ları ve referans ekran görüntüleri sağlayın, marka kurallarını CLAUDE.md içinde kodlayın ve tarayıcı doğrulamasını etkinleştirin. Open Design bunları özenle seçilmiş bir kütüphane olarak sunar, böylece proje başına kurulumu atlarsınız."}, {"name": "Open Design, Anthropic ile bağlantılı mı?", "text": "Hayır. Claude Code, Anthropic'in bir ürünüdür; Open Design, onu birinci taraf bir adaptör olarak destekleyen bağımsız bir açık kaynaklı projedir. Claude ve Claude Code, Anthropic'in ticari markalarıdır."}, {"name": "Dosyalarım ve kimlik bilgilerim güvende mi?", "text": "Evet — Open Design yerel öncelikli ve Apache-2.0'dır. Dosyalarınız, artefaktlarınız ve DESIGN.md'niz kendi reponuzda kalır ve Anthropic kimlik bilgileriniz doğrudan ajanınız tarafından kullanılır, asla Open Design sunucuları üzerinden yönlendirilmez."}], "ctaTitle": "Claude Code ile açık yolla tasarlayın.", "ctaBody": "Kendi Anthropic anahtarınızı veya Claude aboneliğinizi getirin, her dosyayı yerel tutun ve zaten kullandığınız ajanın etrafında özenle seçilmiş bir tasarım kütüphanesi edinin.", "ctaActions": [{"label": "Claude Code'u Open Design içinde kullanın", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub'da yıldız verin", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Masaüstü uygulamasını indirin", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Desteklenen tüm ajanları görün"},
      },
      'codex': {
        ...en['codex']!,
        title: "Tasarım için Codex — Open Design",
        description: "İnsanlar OpenAI Codex'i UI ve web tasarımı için nasıl kullanır — Product Design eklentisi, Figma entegrasyonu, frontend skill'leri — ve Open Design Codex'i nasıl yerel öncelikli, açık kaynaklı bir tasarım ajanına dönüştürür.",
        breadcrumb: "Codex",
        label: "Ajan · Codex",
        heading: "Tasarım için Codex.",
        lead: "Codex, OpenAI'nin kodlama ajanıdır. Product Design eklentisi ve Figma entegrasyonu ile ciddi bir tasarım aracı haline geldi. Open Design, Codex'i açık kaynaklı bir tasarım iş akışına bağlar — OpenAI anahtarınız veya ChatGPT aboneliğiniz, dosyalarınız, yerel öncelikli.",
        rich: {"heroCtaLead": "Open Design, Codex'i yerel öncelikli, açık kaynaklı bir tasarım ajanına dönüştürür — OpenAI anahtarınız, dosyalarınız ve etrafında özenle seçilmiş bir skill ve tasarım sistemi kütüphanesi.", "heroCtaActions": [{"label": "Codex'i Open Design içinde kullanın", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub'da yıldız verin", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Masaüstü uygulamasını indirin", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex bir kod üreticisi olarak başladı, ancak 2026'da — ona doğru referansları, skill'leri ve doğrulama döngüsünü verdiğinizde — gerçek arayüzler tasarlamak için inandırıcı bir araç haline geldi. Bu, Codex'i UI, frontend ve tasarım sistemi çalışmaları için kullanmaya ve onu Open Design ile yapılandırılmış bir tasarım iş akışına bağlamaya dair pratik, uçtan uca bir rehberdir.", "Codex'in bugün ne olduğunu, frontend'de neden birden iyi olduğunu, sıfırdan nasıl kurulacağını, ekran görüntüsünden UI'a döngüyü, resmi Figma gidiş-dönüşünü, Cursor ve Claude Code ile nasıl karşılaştırıldığını, AI çıktısını jenerik gösteren tuzakları ve Open Design'ın açık, yerel öncelikli bir tasarım katmanı olarak bu boşluğu nasıl kapattığını ele alır."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Codex tasarım geri bildirim döngüsü: terminal ajanı, UI'ı işleyen tarayıcı ve bir çalışma alanı, geri döngü oluşturan bir geri bildirim okuyla", "caption": "Çekirdek döngü: Codex terminalde UI oluşturur, bunu gerçek bir tarayıcıda işler ve doğrular, referanslarınıza karşı yineler."}, "tocLabel": "Bu sayfada", "toc": [{"id": "what-is-codex", "label": "OpenAI Codex gerçekte nedir"}, {"id": "why-design", "label": "Codex artık tasarımda neden iyi"}, {"id": "setup", "label": "Codex'i tasarım için kurun (sıfırdan)"}, {"id": "screenshot-workflow", "label": "Ekran görüntüsünden UI'a iş akışı"}, {"id": "figma", "label": "Codex + Figma gidiş-dönüşü"}, {"id": "vs", "label": "Codex, Cursor ve Claude Code karşılaştırması"}, {"id": "pitfalls", "label": "Tuzaklar ve “AI çöplüğü” görünümü"}, {"id": "open-design", "label": "Open Design içinde Codex ile tasarım"}, {"id": "faq", "label": "SSS"}], "sections": [{"id": "what-is-codex", "heading": "OpenAI Codex gerçekte nedir (ve ne değildir)", "blocks": [{"kind": "p", "text": "Önce, “Codex” arayan hemen herkesi tökezleten bir kavram karmaşasını giderelim. Orijinal OpenAI Codex, erken GitHub Copilot'a güç veren ve 2023'te kullanımdan kaldırılan 2021 tarihli bir kod tamamlama modeliydi. Bu sayfanın konusu o değil. Bugünün Codex'i, OpenAI'nin ajansal kodlama aracıdır — doğal dildeki görevlerden kodu planlar, yazar, çalıştırır ve doğrular."}, {"kind": "p", "text": "Modern Codex dört yüzey üzerinden sunulur: bir terminal CLI'si (Rust ile yeniden yazılmış, Apache-2.0 lisanslı), VS Code, Cursor ve Windsurf için bir IDE eklentisi, devredilen asenkron görevler için bir bulut/web deneyimi ve uygulama içi bir tarayıcı ve Computer Use'a sahip bir masaüstü uygulaması."}, {"kind": "steps", "items": [{"label": "Varsayılan model", "body": "2026 ortası itibarıyla önerilen model gpt-5.5'tir; gpt-5.4 ise OpenAI'nin frontend ve bilgisayar kullanımı için açıkça eğittiği modeldir."}, {"label": "Talimat dosyası", "body": "Codex, proje kuralları için projenizdeki bir AGENTS.md dosyasını (araçlar arası bir standart) okur — tasarım kurallarınızı kodlamak için doğal yer."}, {"label": "Sandbox", "body": "Çekirdek düzeyinde bir sandbox'ta çalışır (varsayılan olarak workspace-write), böylece UI'ınızı düzenleyen bir ajan projenin dışına çıkamaz."}]}, {"kind": "ul", "items": ["Sağlayıcı: OpenAI", "Kimlik bilgisi: OpenAI API anahtarı (BYOK) veya ChatGPT aboneliği (Free / Go / Plus / Pro / Business / Enterprise)", "CLI'nin lisansı: Apache-2.0, açık kaynak"]}]}, {"id": "why-design", "heading": "Codex artık tasarımda neden iyi", "blocks": [{"kind": "p", "text": "2026'nın başlarında üç şey bir araya gelerek Codex'i jenerik bir kod üreticisi yerine gerçek bir tasarım aracı haline getirdi."}, {"kind": "steps", "items": [{"label": "Frontend için eğitilmiş bir model", "body": "OpenAI, frontend ve bilgisayar kullanımı için eğitilmiş ilk ana hat modeli olan GPT-5.4'ü, tasarım iş akışı boyunca çok daha iyi görsel anlama ve daha güçlü kendi kendini doğrulama ile yayınladı. Hatta son varlıklara bağlanmadan önce mood board'lar ve görsel seçenekler bile üretebilir."}, {"label": "Resmi bir frontend skill'i", "body": "openai/skills kataloğu, gerçek bir zevki dayatan özenle seçilmiş bir frontend-skill sunar: kartsız düzenler, tam genişlikte hero'lar, marka öncelikli hiyerarşi, ölçülü hareket, en fazla iki yazı tipi ve bir vurgu rengi — ve Codex'in oluşturmadan önce bir görsel tez yazmasını sağlar."}, {"label": "Tarayıcı doğrulaması", "body": "Playwright skill'i ile Codex, yalnızca derlemenin geçtiğini kontrol etmek yerine gerçek bir tarayıcı açar, kırılma noktalarına yeniden boyutlandırır ve çıktısını referansla karşılaştırır."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Tasarım sistemi, skill ve referans görselin iyi tasarım çıktısına yakınsadığını gösteren diyagram", "caption": "Zevk, sağladığınız üç girdiden gelir: bir tasarım sistemi, bir skill ve gerçek referans görseller."}, {"kind": "p", "text": "Üçünün de ardındaki ders: Codex varsayılan olarak zevke sahip değildir. Ona kısıtlar verdiğinizde iyi tasarım üretir — bir tasarım sistemi, estetik bir skill ve somut referanslar. Open Design tam olarak bu girdileri paketler; ikisinin neden birbirine uyduğunun nedeni de budur (daha fazlası aşağıda)."}]}, {"id": "setup", "heading": "Codex'i tasarım çalışması için sıfırdan kurun", "blocks": [{"kind": "p", "text": "Temiz bir makineden, UI oluşturabilen ve doğrulayabilen bir Codex'e giden tam yol şudur."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Beş adımlı kurulum akışı: kur, kimlik doğrula, yapılandır, skill kur, doğrula", "caption": "Kurulum sırası: kur → kimlik doğrula → AGENTS.md yapılandır → frontend skill'ini kur → tarayıcı doğrulamasını etkinleştir."}, {"kind": "steps", "items": [{"label": "Tasarım kurallarınızı kodlayın", "body": "Token'larınızı, ilkellerinizi ve kurallarınızı AGENTS.md veya bir DESIGN.md içine koyun ve Codex'i bunlara yönlendirin; böylece çıktı jenerik bir görünüme dönmek yerine bir markayla eşleşsin."}, {"label": "Doğru akıl yürütme seviyesini seçin", "body": "OpenAI, düşük-orta akıl yürütme seviyelerinin sıklıkla en yüksek ayardan daha güçlü frontend sonuçları ürettiğini belirtiyor."}]}]}, {"id": "screenshot-workflow", "heading": "Ekran görüntüsünden UI'a iş akışı", "blocks": [{"kind": "p", "text": "Codex ile en yüksek kaldıraçlı tasarım döngüsü, bir referans görseli çalışan, duyarlı bir UI'a dönüştürmek ve eşleşene kadar yinelemektir. OpenAI'nin kendi rehberliği beş adıma indirgenir."}, {"kind": "ol", "items": ["Sahip olduğunuz en net görsel referanslardan başlayın — ve yalnızca tek bir hero görseli değil, birden çok durumu (masaüstü ve mobil, hover, boş, yükleniyor) dahil edin.", "Komutta spesifik olun; belirsiz komutlar jenerik UI üretir.", "Bir tasarım sistemi hazırlayın ve Codex'e token'ların ve kanonik ilkellerin nerede yaşadığını söyleyin.", "Playwright etkileşimli skill'ini etkinleştirin, böylece Codex gerçek bir tarayıcıda işler ve kırılma noktalarına yeniden boyutlandırır.", "Codex'in uygulamasını ekran görüntüleriyle karşılaştırmasını sağlayarak yineleyin — yalnızca derlendiğini onaylamasın."]}, {"kind": "p", "text": "Bir ekran görüntüsünü terminale sürükleyerek veya image bayrağı ile görselleri besleyin, ardından somut kısıtlarla komut verin:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "İkinci bir terminalde bir dev sunucusu çalıştırın, komutları küçük ve odaklı tutun ve iyi yinelemeleri commit edin / kötü olanları geri alın (geri aldığınızda Codex'e söyleyin), böylece her geçiş temiz bir temel üzerine inşa edilsin."}]}, {"id": "figma", "heading": "Codex + Figma: tasarım ↔ kod gidiş-dönüşü", "blocks": [{"kind": "p", "text": "Şubat 2026'da OpenAI ve Figma resmi bir ortaklık duyurarak önceki Figma MCP beta'sını birinci sınıf, çift yönlü bir entegrasyona dönüştürdü. Her iki yönde de çalışır."}, {"kind": "steps", "items": [{"label": "Tasarım → Kod", "body": "Figma'da bir frame'in “link to selection” bağlantısını kopyalayın, onu get_design_context ile Codex'e yapıştırın ve ondan mevcut bileşen kütüphanenizi kullanarak tasarımı uygulamasını isteyin."}, {"label": "Kod → Tasarım", "body": "generate_figma_design aracı (“Code to Canvas”), canlı, çalışan bir UI'ı düzenlenebilir Figma frame'lerine geri dönüştürür — tüm ekran, seçili bir öğe veya bütün bir dosya."}]}, {"kind": "p", "text": "Figma MCP, uzak bir sunucu olarak çalışır ve hız sınırlarından muaftır. Bir kez ekleyin ve Codex, Claude Code, Cursor, VS Code ve daha fazlası için kullanılabilir olsun — tam olarak Open Design'ın düzenlemek için inşa edildiği türden taşınabilir, çok ajanlı bir yetenek."}]}, {"id": "vs", "heading": "Tasarım için Codex, Cursor ve Claude Code", "blocks": [{"kind": "p", "text": "Tasarım çalışması için tek bir kazanan yoktur — her ajanın farklı bir gücü vardır ve deneyimli ekipler bunları üst üste yığar. Adil bir özet:"}, {"kind": "table", "columns": ["Ajan", "Tasarım gücü", "En iyi olduğu alan"], "rows": [["Codex", "GPT-5.4 + frontend-skill sonrası güçlü görsel cila; görsel anlama", "Devredilen asenkron derlemeler, sandbox'lanmış çalıştırmalar, taşınabilir AGENTS.md kuralları"], ["Cursor", "Canlı önizleme ve satır içi düzenlemelerle görsel oluştur-ve-gör döngüsü", "Bir IDE içinde sıkı yinele-ve-izle UI çalışması"], ["Claude Code", "Spesifik tasarım kararları (hex, boşluk, tipografi) ve kod tabanının farkında UX", "Frontend akıl yürütmesi ve geniş bağlamlı yeniden düzenlemeler"]]}, {"kind": "p", "text": "Tekrarlanan topluluk kararı, zevkin insanlardan geldiğidir: üçü de skill'ler, referanslar ve kısıtlar olmadan jenerik bir estetiğe varsayılan olarak kayar. Çözülmesi gereken asıl sorun budur — ve bu sorun, model biçimli değil, tasarım aracı biçimlidir."}]}, {"id": "pitfalls", "heading": "Tuzaklar ve “AI çöplüğü” görünümünden nasıl kaçınılır", "blocks": [{"kind": "p", "text": "Codex tarafından üretilen tasarımla ilgili en yaygın şikayet, jenerik görünmesidir — yumuşak degradeler, yüzen paneller, aşırı büyük yuvarlatılmış köşeler, dramatik gölgeler, “bunu bir AI yaptı diye bağıran” bir Inter-ve-mor havası. Bildirilen diğer sorunlar arasında bozuk mobil düzenler, UI metnine sızan talimatlar ve kullanım sınırlarına hızla ulaşmak yer alır."}, {"kind": "steps", "items": [{"label": "Bir frontend skill'i kurun", "body": "Özenle seçilmiş bir estetik skill, Codex'i varsayılan görünüm yerine gerçek bir yöne bağlanmaya zorlar."}, {"label": "Playwright doğrulamasını etkinleştirin", "body": "Codex'in kırılma noktaları boyunca işlemesini ve kendi kendini kontrol etmesini sağlayın, böylece düzenler mobilde sessizce bozulmasın."}, {"label": "Token ve referans sağlayın", "body": "Gerçek tasarım token'ları ve referans ekran görüntüleri, çıktı kalitesi üzerindeki en büyük tek kaldıraçtır."}, {"label": "Kuralları AGENTS.md içinde kodlayın", "body": "“hero kartı yok, en fazla iki yazı tipi, marka öncelikli hiyerarşi” gibi kuralları, ajanın her çalıştırmada okuduğu yere koyun."}]}, {"kind": "p", "text": "Her hafifletmenin, ajana özenle seçilmiş bir tasarım bağlamı vermekle ilgili olduğuna dikkat edin. Bu bağlamı proje başına elle sürdürmek, Open Design'ın ortadan kaldırdığı zahmettir."}]}, {"id": "open-design", "heading": "Open Design içinde Codex ile tasarım", "blocks": [{"kind": "p", "text": "Open Design, yukarıdaki iş akışının sürekli istediği açık kaynaklı tasarım katmanıdır. Codex'i birinci taraf bir adaptör olarak ele alır ve onu özenle seçilmiş bir skill ve tasarım sistemi kütüphanesi, yapılandırılmış bir render hattı ve yerel bir masaüstü UI'sı ile sarmalar — böylece Codex'i iyi yapan tasarım bağlamı, her seferinde elle bir araya getirilmek yerine ilk çalıştırmadan itibaren oradadır."}, {"kind": "ol", "items": ["Open Design'ı kurun ve ajanınız olarak Codex'i seçin.", "OpenAI API anahtarınız (BYOK) veya ChatGPT aboneliğinizle kimlik doğrulayın — kimlik bilgileri makinenizde kalır ve asla bizim üzerimizden proxy'lenmez.", "Bir tasarım sistemi ve bir skill seçin, ardından tutarlı bir zevkle sunumlar, prototipler ve açılış sayfaları üretin.", "Her artefakt ve DESIGN.md dosyası, barındırılan bir bulutta değil, kendi reponuzda yaşar."]}, {"kind": "p", "text": "Aynı Codex ajanı, aynı anahtar — artı etrafında gerçek, taşınabilir, açık kaynaklı bir tasarım iş akışı. Yerel öncelikli ve Apache-2.0'dır, bu yüzden çalışmanız veya kimlik bilgileriniz hakkında hiçbir şey makinenizden ayrılmaz."}]}], "faqTitle": "Sıkça sorulan sorular", "faq": [{"name": "OpenAI Codex gerçekten tasarım çalışması yapabilir mi?", "text": "Evet — bağlamda bir frontend skill'i, bir tasarım sistemi ve gerçek referans görsellerle Codex (özellikle GPT-5.4 üzerinde) üretim kalitesinde, duyarlı UI üretir ve bunu bir tarayıcıda doğrulayabilir. Bu bağlam olmadan jenerik bir görünüme dönme eğilimindedir; Open Design'ın doldurduğu boşluk da budur."}, {"name": "Bu, OpenAI Codex Product Design eklentisi mi?", "text": "Hayır. Open Design, Codex'i bir ajan olarak entegre eden bağımsız bir açık kaynaklı projedir. OpenAI'nin kendi araçlarını yerel öncelikli, açık bir skill ve tasarım sistemi kütüphanesiyle tamamlar."}, {"name": "Codex ile tasarım yapmak için bir ChatGPT aboneliğine ihtiyacım var mı?", "text": "Bir OpenAI API anahtarı (BYOK) veya ChatGPT aboneliğinizi kullanabilirsiniz. ChatGPT ile oturum açmak genellikle daha cömert sınırlar verir; Open Design her iki durumda da kimlik bilgilerinizi asla proxy'lemez."}, {"name": "Frontend tasarımı için Codex mi yoksa Claude Code mu?", "text": "İkisi de güçlüdür. Claude Code, spesifik, kod tabanının farkında tasarım kararlarıyla bilinir; Codex'in GPT-5.4 sonrası güçlü bir görsel cilası vardır ve devredilen, sandbox'lanmış derlemelerde öne çıkar. Birçok ekip ikisini de kullanır — Open Design, tasarım iş akışınızı değiştirmeden ajanlar arasında geçiş yapmanızı sağlar."}, {"name": "Codex'i Figma'ya nasıl bağlarım?", "text": "Resmi Figma MCP sunucusunu ekleyin (codex mcp add figma --url https://mcp.figma.com/mcp). Ardından get_design_context ile Figma frame'lerini kod olarak uygulayabilir ve çalışan bir UI'ı generate_figma_design ile düzenlenebilir Figma frame'lerine geri gönderebilirsiniz."}, {"name": "Jenerik “AI çöplüğü” estetiğinden nasıl kaçınırım?", "text": "Bir frontend skill'i kurun, gerçek tasarım token'ları ve referans ekran görüntüleri sağlayın, marka kurallarını AGENTS.md içinde kodlayın ve Playwright doğrulamasını etkinleştirin. Open Design bunları özenle seçilmiş bir kütüphane olarak sunar, böylece proje başına kurulumu atlarsınız."}, {"name": "Open Design, OpenAI ile bağlantılı mı?", "text": "Hayır. Codex, OpenAI'nin bir ürünüdür; Open Design, onu birinci taraf bir adaptör olarak destekleyen bağımsız bir açık kaynaklı projedir. OpenAI ve Codex, OpenAI'nin ticari markalarıdır."}, {"name": "Dosyalarım ve kimlik bilgilerim güvende mi?", "text": "Evet — Open Design yerel önceliklidir. Dosyalarınız, artefaktlarınız ve DESIGN.md'niz kendi reponuzda kalır ve OpenAI kimlik bilgileriniz doğrudan ajanınız tarafından kullanılır, asla Open Design sunucuları üzerinden yönlendirilmez."}], "ctaTitle": "Codex ile açık yolla tasarlayın.", "ctaBody": "Kendi OpenAI anahtarınızı getirin, her dosyayı yerel tutun ve zaten kullandığınız ajanın etrafında özenle seçilmiş bir tasarım kütüphanesi edinin.", "ctaActions": [{"label": "Codex'i Open Design içinde kullanın", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub'da yıldız verin", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Masaüstü uygulamasını indirin", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Desteklenen tüm ajanları görün"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Tasarımcılar için Cursor — Open Design",
        description: "Tasarımcılar Cursor'ı UI ve web tasarımı için nasıl kullanır — Design Mode, Figma'dan koda, Figma MCP — ve Open Design Cursor'ı nasıl yerel öncelikli, açık kaynaklı bir tasarım ajanına dönüştürür.",
        breadcrumb: "Cursor",
        label: "Ajan · Cursor",
        heading: "Tasarımcılar için Cursor.",
        lead: "Cursor, artık görsel bir Design Mode'a sahip AI kod editörüdür. Tasarımcılar onu işaret ve çizim yoluyla UI düzenlemek ve Figma'yı koda dönüştürmek için kullanır. Open Design, Cursor Agent'ı dosyalarınızı yerel tutan açık kaynaklı bir tasarım iş akışına bağlar.",
        rich: {"heroCtaLead": "Open Design, Cursor'ı yerel öncelikli, açık kaynaklı bir tasarım ajanına dönüştürür — Cursor hesabınız veya model anahtarlarınız, dosyalarınız ve etrafında özenle seçilmiş bir skill ve tasarım sistemi kütüphanesi.", "heroCtaActions": [{"label": "Cursor'ı Open Design içinde kullanın", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub'da yıldız verin", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Masaüstü uygulamasını indirin", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor, “oluştur ve işlenmesini izle” yaklaşımını UI'ı yayınlamanın varsayılan yolu haline getiren AI öncelikli kod editörüdür. Agent modu, satır içi düzenlemeler, editör içi bir önizleme ve MCP üzerinden Figma ile — ona doğru referansları, kuralları ve bir doğrulama döngüsü verdiğinizde — gerçek bir tasarım aracı haline geldi. Bu, Cursor'ı UI, frontend ve tasarım sistemi çalışmaları için kullanmaya ve onu Open Design ile yapılandırılmış bir tasarım iş akışına bağlamaya dair pratik, uçtan uca bir rehberdir.", "Cursor'ın gerçekte ne olduğunu, sıkı yinele-ve-izle döngüsünün tasarım için neden iyi olduğunu, sıfırdan nasıl kurulacağını, ekran görüntüsünden ve önizlemeden UI'a döngüyü, MCP üzerinden Figma gidiş-dönüşünü, Codex ve Claude Code ile nasıl karşılaştırıldığını, AI çıktısını jenerik gösteren tuzakları ve Open Design'ın açık, yerel öncelikli bir tasarım katmanı olarak bu boşluğu nasıl kapattığını ele alır."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Cursor tasarım yakınsaması: solda editör, ortada merkezinde Cursor işaretiyle özenle seçilmiş bir skill ve tasarım sistemi merkezi ve sağda işlenmiş bir UI", "caption": "Çekirdek fikir: Cursor, editörde UI'ı düzenler ve işler, bu sırada özenle seçilmiş bir tasarım merkezi ona çıktıyı bilinçli gösteren sistemi, skill'leri ve referansları besler."}, "tocLabel": "Bu sayfada", "toc": [{"id": "what-is-cursor", "label": "Cursor gerçekte nedir"}, {"id": "why-design", "label": "Cursor tasarımda neden iyi"}, {"id": "setup", "label": "Cursor'ı tasarım için kurun (sıfırdan)"}, {"id": "preview-workflow", "label": "Önizlemeden UI'a iş akışı"}, {"id": "figma", "label": "MCP üzerinden Cursor + Figma"}, {"id": "vs", "label": "Cursor, Codex ve Claude Code karşılaştırması"}, {"id": "pitfalls", "label": "Tuzaklar ve “AI çöplüğü” görünümü"}, {"id": "open-design", "label": "Open Design içinde Cursor ile tasarım"}, {"id": "faq", "label": "SSS"}], "sections": [{"id": "what-is-cursor", "heading": "Cursor gerçekte nedir", "blocks": [{"kind": "p", "text": "Cursor, Anysphere tarafından geliştirilen AI öncelikli bir kod editörüdür. VS Code'un bir fork'udur, bu yüzden tanıdık editörü, eklentileri ve kısayol tuşlarını korur, ancak iş akışını; tüm projenizi okuyabilen, birden çok dosyayı düzenleyebilen, komutları çalıştırabilen ve sizinle döngü içinde yineleyebilen bir AI ajanı etrafında yeniden inşa eder."}, {"kind": "p", "text": "Tasarım çalışması için önemli yüzeyler şunlardır: Agent modu (bir sonuç tarif edersiniz ve Cursor dosyalar boyunca planlar ve düzenler), hızlı ince ayarlar için satır içi düzenlemeler ve Tab tamamlamaları, pencereyi terk etmeden çalışan UI'ı görebilmeniz için editör içi bir önizleme / tarayıcı ve canlı bir Figma dosyası gibi harici bağlamı çekmesine izin veren MCP desteği."}, {"kind": "steps", "items": [{"label": "Proje kuralları", "body": "Cursor, proje talimat dosyalarını okur — `.cursor/rules` altındaki sürümlenmiş `.mdc` kuralları ve sade bir `AGENTS.md` — böylece tasarım kurallarınızı ajanın her çalıştırmada okuduğu yere kodlayabilirsiniz."}, {"label": "Modeller", "body": "Cursor model açısından esnektir: aboneliğiniz üzerinden öncü modellerle gelir ve ayrıca kendi model anahtarlarınızı getirmeyi destekler, böylece aynı editör iş akışının arkasındaki motoru siz seçersiniz."}, {"label": "MCP", "body": "Model Context Protocol konuşur, böylece harici sunucular — en alakalısı Figma MCP sunucusu — ajan için birinci sınıf bağlam haline gelir."}]}, {"kind": "ul", "items": ["Sağlayıcı: Anysphere", "Kimlik bilgisi: Cursor hesabı / aboneliği (Hobby / Pro / Business) veya kendi model anahtarlarınız (BYOK)", "Biçim: Editör içi bir ajan ve önizlemeye sahip AI öncelikli kod editörü (VS Code fork'u)"]}]}, {"id": "why-design", "heading": "Cursor tasarımda neden iyi", "blocks": [{"kind": "p", "text": "Cursor'ın tasarım üstünlüğü tek bir özellik değildir — oluştur-ve-gör döngüsünün sıkılığıdır. Üç şey onu jenerik bir kod üreticisi yerine bir tasarım aracı gibi hissettirir."}, {"kind": "steps", "items": [{"label": "Sıkı bir yinele-ve-izle döngüsü", "body": "Komut verirsiniz, Cursor dosyalar boyunca düzenler ve editör içi önizleme sonucu hemen işler — böylece boşluğu, hiyerarşiyi ve hareketi ayrı bir terminal ve tarayıcı arasında gidip gelmek yerine saniyeler içinde ayarlarsınız."}, {"label": "Doğrudan görsel düzenleme", "body": "Sohbetin ötesinde, Cursor önizlemede öğeleri seçmenize ve stilleri ince ayar yapmanıza izin verir, böylece küçük görsel düzeltmeler kod arkeolojisi yerine tasarım düzenlemeleri gibi hissettirir."}, {"label": "Proje kuralları ve MCP bağlamı", "body": "`.cursor/rules` (veya `AGENTS.md`) ve Figma MCP sunucusu ile ajan, tahmin yürütmek yerine token'larınıza, bileşenlerinize ve gerçek tasarım spesifikasyonlarınıza karşı çalışır."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Tasarım sistemi, skill ve referans görselin iyi tasarım çıktısına yakınsadığını gösteren diyagram", "caption": "Zevk, sağladığınız üç girdiden gelir: bir tasarım sistemi, bir skill ve gerçek referans görseller."}, {"kind": "p", "text": "Çıkarılan ders, her ajanın öğrettiğiyle aynıdır: Cursor varsayılan olarak zevke sahip değildir. Ona kısıtlar verdiğinizde iyi tasarım üretir — bir tasarım sistemi, estetik bir skill ve somut referanslar. Open Design tam olarak bu girdileri paketler; ikisinin neden birbirine uyduğunun nedeni de budur (daha fazlası aşağıda)."}]}, {"id": "setup", "heading": "Cursor'ı tasarım çalışması için sıfırdan kurun", "blocks": [{"kind": "p", "text": "Temiz bir makineden; tasarım sisteminize karşı UI oluşturabilen, önizleyebilen ve doğrulayabilen bir Cursor'a giden tam yol şudur."}, {"kind": "ol", "items": ["Cursor'ı cursor.com'dan kurun ve Cursor hesabınızla oturum açın veya Ayarlar'da kendi model anahtarlarınızı (BYOK) yapılandırın.", "Projenizi açın ve sohbet / Agent panelinde bir model seçin.", "Proje kuralları ekleyin: yapılandırılmış, glob kapsamlı kurallar için `.cursor/rules/*.mdc` oluşturun veya basit, okunabilir talimatlar için sade bir `AGENTS.md` oluşturun.", "Figma MCP sunucusunu bağlayın (isteğe bağlı), böylece ajan canlı tasarım bağlamını okuyabilir.", "Dev sunucunuzu çalıştırın ve yinelerken UI'ı görmek ve doğrulamak için editör içi önizlemeyi kullanın."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Beş adımlı kurulum akışı: kur, kimlik doğrula, kuralları yapılandır, skill ekle, doğrula", "caption": "Kurulum sırası: kur → kimlik doğrula → proje kurallarını yapılandır → bir skill ekle → önizleme doğrulamasını etkinleştir."}, {"kind": "p", "text": "Minimal bir proje kuralları dosyası, ajanın jenerik bir görünüme dönmek yerine bir markaya göre tasarlamasını sağlar. Onu Cursor'ın her çalıştırmada okuduğu yere koyun:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Tasarım kurallarınızı kodlayın", "body": "Token'larınızı, ilkellerinizi ve kurallarınızı `.cursor/rules` veya `AGENTS.md` içine koyun ve Cursor'ı bunlara yönlendirin; böylece çıktı jenerik bir görünüme dönmek yerine bir markayla eşleşsin."}, {"label": "Komutları küçük tutun", "body": "Cursor'ın sıkı döngüsü odaklı isteklere ödül verir — bir seferde bir bileşen veya durum üzerinde yineleyin ve geçişler arasında önizlemeyi izleyin."}]}]}, {"id": "preview-workflow", "heading": "Önizlemeden UI'a iş akışı", "blocks": [{"kind": "p", "text": "Cursor ile en yüksek kaldıraçlı tasarım döngüsü, bir referansı çalışan, duyarlı bir UI'a dönüştürmek ve eşleşene kadar editörde yinelemektir — tahmin yürütmek yerine canlı önizlemeyi sürekli izleyerek."}, {"kind": "ol", "items": ["Sahip olduğunuz en net görsel referanslardan başlayın — ve yalnızca tek bir hero görseli değil, birden çok durumu (masaüstü ve mobil, hover, boş, yükleniyor) dahil edin.", "Komutta spesifik olun; belirsiz komutlar jenerik UI üretir.", "Bir tasarım sistemi hazırlayın ve Cursor'a token'ların ve kanonik ilkellerin nerede yaşadığını söyleyin.", "Editör içi önizlemeyi açık ve dev sunucunuzu çalışır tutun, böylece her düzenleme önemsediğiniz kırılma noktalarında hemen işlensin.", "İşlenmiş UI'ı referanslarla karşılaştırarak yineleyin — ve küçük görsel düzeltmeler için önizlemede doğrudan öğe seçimini kullanın."]}, {"kind": "p", "text": "Sohbete bir görsel ekleyerek referansları besleyin, ardından somut kısıtlarla komut verin:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "İyi yinelemeleri commit edin ve kötü olanları geri alın (geri aldığınızda Cursor'a söyleyin), böylece her geçiş temiz bir temel üzerine inşa edilsin — herhangi bir ajan döngüsünün sapmasını önleyen aynı disiplin."}]}, {"id": "figma", "heading": "Cursor + Figma: MCP üzerinden tasarım ↔ kod", "blocks": [{"kind": "p", "text": "Cursor, resmi Figma MCP sunucusu aracılığıyla Figma'ya bağlanır; bu da ajana düz bir ekran görüntüsü yerine canlı bir Figma dosyasına yapılandırılmış erişim sağlar. Bu, devirden tahmin yürütmeyi ortadan kaldırır."}, {"kind": "steps", "items": [{"label": "Tasarım → Kod", "body": "Figma'da bir frame'in bağlantısını kopyalayın, onu Cursor'a yapıştırın ve ondan tasarımı uygulamasını isteyin. MCP sunucusu gerçek tasarım bağlamını — bileşenler, değişkenler, düzen verisi, token'lar — açığa çıkarır, böylece üretilen kod kaynağa yaklaşmak yerine onunla eşleşir."}, {"label": "Hizalı kalın", "body": "Figma'da tutarlı kullanılan tasarım token'ları, stiller ve bileşenlerle (ve mevcut olduğunda Code Connect ile), Cursor'ın çıktısı ilkelleri yeniden icat etmek yerine gerçek tasarım sisteminize eşlenmiş kalır."}]}, {"kind": "p", "text": "Uzak Figma MCP sunucusunu bir kez kurun, Cursor için birinci sınıf bağlam olarak kullanılabilir olsun. MCP açık bir standart olduğundan, aynı sunucu Cursor, Claude Code, Codex ve VS Code arasında yeniden kullanılabilir — tam olarak Open Design'ın düzenlemek için inşa edildiği türden taşınabilir, çok ajanlı bir yetenek."}]}, {"id": "vs", "heading": "Tasarım için Cursor, Codex ve Claude Code", "blocks": [{"kind": "p", "text": "Tasarım çalışması için tek bir kazanan yoktur — her ajanın farklı bir gücü vardır ve deneyimli ekipler bunları üst üste yığar. Adil bir özet:"}, {"kind": "table", "columns": ["Ajan", "Tasarım gücü", "En iyi olduğu alan"], "rows": [["Cursor", "Canlı editör içi önizleme ve doğrudan öğe düzenlemeyle görsel oluştur-ve-gör döngüsü", "Bir IDE içinde sıkı yinele-ve-izle UI çalışması"], ["Codex", "Bir frontend skill'i ile güçlü görsel cila; görsel anlama ve sandbox'lanmış çalıştırmalar", "Devredilen asenkron derlemeler ve taşınabilir AGENTS.md kuralları"], ["Claude Code", "Spesifik tasarım kararları (hex, boşluk, tipografi) ve kod tabanının farkında UX", "Frontend akıl yürütmesi ve geniş bağlamlı yeniden düzenlemeler"]]}, {"kind": "p", "text": "Tekrarlanan topluluk kararı, zevkin insanlardan geldiğidir: üçü de skill'ler, referanslar ve kısıtlar olmadan jenerik bir estetiğe varsayılan olarak kayar. Çözülmesi gereken asıl sorun budur — ve bu sorun, model biçimli değil, tasarım aracı biçimlidir."}]}, {"id": "pitfalls", "heading": "Tuzaklar ve “AI çöplüğü” görünümünden nasıl kaçınılır", "blocks": [{"kind": "p", "text": "Cursor tarafından üretilen tasarımla ilgili en yaygın şikayet, jenerik görünmesidir — yumuşak degradeler, yüzen paneller, aşırı büyük yuvarlatılmış köşeler, dramatik gölgeler, “bunu bir AI yaptı diye bağıran” bir Inter-ve-mor havası. Bildirilen diğer sorunlar arasında mobilde bozulan düzenler ve UI metnine sızan talimatlar yer alır."}, {"kind": "steps", "items": [{"label": "Bir tasarım skill'i ekleyin", "body": "Özenle seçilmiş bir estetik skill, Cursor'ı varsayılan görünüm yerine gerçek bir yöne bağlanmaya zorlar."}, {"label": "Doğrulamak için önizlemeyi kullanın", "body": "Editör içi önizlemede kırılma noktaları boyunca işleyin ve kendi kendini kontrol edin, böylece düzenler mobilde sessizce bozulmasın."}, {"label": "Token ve referans sağlayın", "body": "Gerçek tasarım token'ları ve referans ekran görüntüleri, çıktı kalitesi üzerindeki en büyük tek kaldıraçtır."}, {"label": "Kuralları `.cursor/rules` içinde kodlayın", "body": "“hero kartı yok, en fazla iki yazı tipi, marka öncelikli hiyerarşi” gibi kuralları, ajanın her çalıştırmada okuduğu yere koyun."}]}, {"kind": "p", "text": "Her hafifletmenin, ajana özenle seçilmiş bir tasarım bağlamı vermekle ilgili olduğuna dikkat edin. Bu bağlamı proje başına elle sürdürmek, Open Design'ın ortadan kaldırdığı zahmettir."}]}, {"id": "open-design", "heading": "Open Design içinde Cursor ile tasarım", "blocks": [{"kind": "p", "text": "Open Design, yukarıdaki iş akışının sürekli istediği açık kaynaklı tasarım katmanıdır. Cursor'ı birinci taraf bir adaptör olarak ele alır ve onu özenle seçilmiş bir skill ve tasarım sistemi kütüphanesi, yapılandırılmış bir render hattı ve yerel bir masaüstü UI'sı ile sarmalar — böylece Cursor'ı iyi yapan tasarım bağlamı, her seferinde elle bir araya getirilmek yerine ilk çalıştırmadan itibaren oradadır."}, {"kind": "ol", "items": ["Open Design'ı kurun ve ajanınız olarak Cursor'ı seçin.", "Cursor hesabınız veya kendi model anahtarlarınızla (BYOK) kimlik doğrulayın — kimlik bilgileri makinenizde kalır ve asla bizim üzerimizden proxy'lenmez.", "Bir tasarım sistemi ve bir skill seçin, ardından tutarlı bir zevkle sunumlar, prototipler ve açılış sayfaları üretin.", "Her artefakt ve DESIGN.md dosyası, barındırılan bir bulutta değil, kendi reponuzda yaşar."]}, {"kind": "p", "text": "Aynı Cursor ajanı, aynı anahtar — artı etrafında gerçek, taşınabilir, açık kaynaklı bir tasarım iş akışı. Yerel öncelikli ve Apache-2.0'dır, bu yüzden çalışmanız veya kimlik bilgileriniz hakkında hiçbir şey makinenizden ayrılmaz."}]}], "faqTitle": "Sıkça sorulan sorular", "faq": [{"name": "Cursor gerçekten tasarım çalışması yapabilir mi?", "text": "Evet — bağlamda bir tasarım skill'i, bir tasarım sistemi ve gerçek referans görsellerle Cursor üretim kalitesinde, duyarlı UI üretir ve editör içi önizlemesi onu görsel olarak doğrulamanıza ve iyileştirmenize olanak tanır. Bu bağlam olmadan jenerik bir görünüme dönme eğilimindedir; Open Design'ın doldurduğu boşluk da budur."}, {"name": "Bu resmi bir Cursor ürünü mü?", "text": "Hayır. Open Design, Cursor'ı bir ajan olarak entegre eden bağımsız bir açık kaynaklı projedir. Cursor'ı yerel öncelikli, açık bir skill ve tasarım sistemi kütüphanesiyle tamamlar."}, {"name": "Cursor ile tasarım yapmak için bir Cursor aboneliğine ihtiyacım var mı?", "text": "Bir Cursor hesabı / aboneliği kullanabilir veya kendi model anahtarlarınızı (BYOK) getirebilirsiniz. Open Design her iki durumda da kimlik bilgilerinizi asla proxy'lemez — bunlar doğrudan ajanınız tarafından kullanılır."}, {"name": "Frontend tasarımı için Cursor mı yoksa Claude Code mu?", "text": "İkisi de güçlüdür. Claude Code, spesifik, kod tabanının farkında tasarım kararlarıyla bilinir; Cursor'ın üstünlüğü, editör içinde canlı bir önizlemeyle sıkı oluştur-ve-gör döngüsüdür. Birçok ekip ikisini de kullanır — Open Design, tasarım iş akışınızı değiştirmeden ajanlar arasında geçiş yapmanızı sağlar."}, {"name": "Cursor'ı Figma'ya nasıl bağlarım?", "text": "Cursor'a resmi Figma MCP sunucusunu ekleyin, ardından bir Figma frame bağlantısını sohbete yapıştırın ve Cursor'dan onu uygulamasını isteyin. Sunucu gerçek bileşenleri, değişkenleri ve düzen verisini açığa çıkarır, böylece üretilen kod kaynak tasarımla eşleşir."}, {"name": "Jenerik “AI çöplüğü” estetiğinden nasıl kaçınırım?", "text": "Bir tasarım skill'i ekleyin, gerçek tasarım token'ları ve referans ekran görüntüleri sağlayın, marka kurallarını `.cursor/rules` veya `AGENTS.md` içinde kodlayın ve önizlemede kırılma noktaları boyunca doğrulayın. Open Design bunları özenle seçilmiş bir kütüphane olarak sunar, böylece proje başına kurulumu atlarsınız."}, {"name": "Open Design, Cursor veya Anysphere ile bağlantılı mı?", "text": "Hayır. Cursor, Anysphere'in bir ürünüdür; Open Design, onu birinci taraf bir adaptör olarak destekleyen bağımsız bir açık kaynaklı projedir. Cursor ve Anysphere, Anysphere, Inc.'in ticari markalarıdır."}, {"name": "Dosyalarım ve kimlik bilgilerim güvende mi?", "text": "Evet — Open Design yerel önceliklidir. Dosyalarınız, artefaktlarınız ve DESIGN.md'niz kendi reponuzda kalır ve Cursor veya model kimlik bilgileriniz doğrudan ajanınız tarafından kullanılır, asla Open Design sunucuları üzerinden yönlendirilmez."}], "ctaTitle": "Cursor ile açık yolla tasarlayın.", "ctaBody": "Kendi Cursor hesabınızı veya model anahtarlarınızı getirin, her dosyayı yerel tutun ve zaten kullandığınız ajanın etrafında özenle seçilmiş bir tasarım kütüphanesi edinin.", "ctaActions": [{"label": "Cursor'ı Open Design içinde kullanın", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub'da yıldız verin", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Masaüstü uygulamasını indirin", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Desteklenen tüm ajanları görün"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "Tasarım için OpenCode — Open Design",
        description: "İnsanlar OpenCode'u UI ve web tasarımı için nasıl kullanır — design.md dosyaları, UI/UX skill'leri, Figma MCP — ve Open Design OpenCode'u nasıl yerel öncelikli, açık kaynaklı bir tasarım ajanına dönüştürür.",
        breadcrumb: "OpenCode",
        label: "Ajan · OpenCode",
        heading: "Tasarım için OpenCode.",
        lead: "OpenCode, açık kaynaklı terminal AI kodlama ajanıdır. Tasarımcılar gerçek UI üretmek için ona tasarım skill'leri ve DESIGN.md dosyaları ekler. Open Design bunu yapılandırılmış, açık kaynaklı bir iş akışı haline getirir — sağlayıcı anahtarlarınızı getirin, her şeyi yerel tutun.",
        rich: {"heroCtaLead": "Open Design, OpenCode'u yerel öncelikli, açık kaynaklı bir tasarım ajanına dönüştürür — kendi sağlayıcı anahtarınızla seçtiğiniz herhangi bir model, dosyalarınız ve etrafında özenle seçilmiş bir skill ve tasarım sistemi kütüphanesi.", "heroCtaActions": [{"label": "OpenCode'u Open Design içinde kullanın", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub'da yıldız verin", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Masaüstü uygulamasını indirin", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode, bilinçli olarak modelden bağımsız, açık kaynaklı, terminal öncelikli bir AI kodlama ajanıdır: kendi sağlayıcı anahtarınızı getirir ve aynı iş akışının arkasında istediğiniz herhangi bir modeli çalıştırırsınız. Bu açıklık onu tasarım çalışması için doğal bir temel haline getirir — ama her ajan gibi, yalnızca ona doğru referansları, skill'leri ve bir doğrulama döngüsü verdiğinizde iyi UI üretir. Bu, OpenCode'u UI, frontend ve tasarım sistemi çalışmaları için kullanmaya ve onu Open Design ile yapılandırılmış bir tasarım iş akışına bağlamaya dair pratik, uçtan uca bir rehberdir.", "OpenCode'un gerçekte ne olduğunu, modelden bağımsız, açık bir ajanın tasarım için neden iyi bir uyum olduğunu, sıfırdan nasıl kurulacağını, ekran görüntüsünden UI'a döngüyü, AGENTS.md ve MCP'nin onu nasıl genişlettiğini, Codex, Claude Code ve Cursor ile nasıl karşılaştırıldığını, AI çıktısını jenerik gösteren tuzakları ve Open Design'ın açık, yerel öncelikli bir tasarım katmanı olarak bu boşluğu nasıl kapattığını ele alır — doğal bir eşleşme, çünkü her iki proje de açık kaynaklı ve kendi makinenizde çalışır."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "OpenCode tasarım geri bildirim döngüsü: bir terminal TUI ajanı, UI'ı işleyen bir tarayıcı ve bir çalışma alanı, geri döngü oluşturan bir geri bildirim okuyla", "caption": "Çekirdek döngü: OpenCode terminalde UI oluşturur, bunu gerçek bir tarayıcıda işler ve doğrular, referanslarınıza karşı yineler — seçtiğiniz hangi model olursa olsun."}, "tocLabel": "Bu sayfada", "toc": [{"id": "what-is-opencode", "label": "OpenCode gerçekte nedir"}, {"id": "why-design", "label": "Açık, her-model ajanı tasarıma neden uyar"}, {"id": "setup", "label": "OpenCode'u tasarım için kurun (sıfırdan)"}, {"id": "screenshot-workflow", "label": "Ekran görüntüsünden UI'a iş akışı"}, {"id": "extend", "label": "AGENTS.md, MCP ve paylaşılabilir oturumlar"}, {"id": "vs", "label": "OpenCode, Codex, Claude Code ve Cursor karşılaştırması"}, {"id": "pitfalls", "label": "Tuzaklar ve “AI çöplüğü” görünümü"}, {"id": "open-design", "label": "Open Design içinde OpenCode ile tasarım"}, {"id": "faq", "label": "SSS"}], "sections": [{"id": "what-is-opencode", "heading": "OpenCode gerçekte nedir", "blocks": [{"kind": "p", "text": "OpenCode, SST'nin (Anomaly Innovations) arkasındaki ekip tarafından sürdürülen, terminal için inşa edilmiş açık kaynaklı bir AI kodlama ajanıdır. Reponuzu okur, komutları çalıştırır, dosyaları düzenler ve büyük bir dil modeliyle konuşur — ama sağlayıcıya bağlı ajanların aksine, kendi modelini sunmaz. Onu istediğiniz herhangi bir sağlayıcıya ve modele yönlendirir ve kendi anahtarınızı getirirsiniz."}, {"kind": "p", "text": "Aynı motorun üzerinde bir masaüstü uygulaması ve IDE eklentileriyle birlikte bir terminal UI'sı (TUI) olarak çalışır. Kaputun altında bir istemci/sunucu mimarisi kullanır, böylece işi yapan ajan, onu sürdüğünüz yüzeyden ayrıştırılmıştır. İki yerleşik ajan — build ve plan — Tab tuşuyla geçiş yapar."}, {"kind": "steps", "items": [{"label": "Modelden bağımsız", "body": "Modeller ve sağlayıcılar, açık bir katalog olan models.dev'den gelir. Bunları opencode.json içinde bir provider/model-id dizesiyle yapılandırır ve yüklenmesini istemediğiniz sağlayıcıları devre dışı bırakabilirsiniz — böylece aynı tasarım iş akışı Anthropic, OpenAI, Google, OpenRouter, yerel modeller ve daha fazlasında çalışır."}, {"label": "Talimat dosyası", "body": "OpenCode, proje kuralları için projenizdeki bir AGENTS.md dosyasını (araçlar arası standart, CLAUDE.md ile de uyumlu) okur — tasarım kurallarınızı kodlamak için doğal yer. Bir tane oluşturmak için /init çalıştırın."}, {"label": "Genişletilebilir", "body": "LSP entegrasyonunu, MCP sunucularını, temaları, kısayol tuşlarını ve özel komutları destekler, ayrıca işbirliği için paylaşılabilir oturum bağlantıları sunar."}]}, {"kind": "ul", "items": ["Sürdüren: SST / Anomaly Innovations (açık kaynaklı proje)", "Kimlik bilgisi: kendi model sağlayıcı API anahtar(lar)ınız — BYOK, sağlayıcı kilidi yok", "Lisans: MIT, açık kaynak"]}]}, {"id": "why-design", "heading": "Açık, her-model ajanı tasarım çalışmasına neden uyar", "blocks": [{"kind": "p", "text": "OpenCode'un, bir sağlayıcı ajanı gibi tek bir “tasarım modeli” yoktur — ve asıl mesele de budur. Modelden bağımsız ve açık olduğundan, aynı tasarım iş akışını şu anda frontend'de en iyi olan modelde çalıştırabilir, sonra değiştirebilir veya yerel bir modele geri dönebilirsiniz, hepsi kurulumunuzu değiştirmeden."}, {"kind": "p", "text": "Ama model seçimi tek başına zevk satın almaz. Her kodlama ajanı gibi, OpenCode da ona kısıtlar vermediğiniz sürece jenerik UI üretir. İyi tasarım çıktısı, sağladığınız üç girdiden gelir."}, {"kind": "steps", "items": [{"label": "Bir tasarım sistemi", "body": "Ajanın yeniden kullandığı gerçek token'lar, ilkeller ve kurallar, böylece çıktı jenerik bir görünüme dönmek yerine bir markayla eşleşir."}, {"label": "Estetik bir skill", "body": "Gerçek bir zevki dayatan özenle seçilmiş bir skill — ölçülü hareket, marka öncelikli hiyerarşi, en fazla iki yazı tipi ve bir vurgu rengi — ve ajanın oluşturmadan önce bir yöne bağlanmasını sağlar."}, {"label": "Somut referanslar", "body": "Gerçek referans görseller ve birden çok durum (masaüstü ve mobil, hover, boş, yükleniyor), tek bir hero görseli değil."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Tasarım sistemi, skill ve referans görselin iyi tasarım çıktısına yakınsadığını gösteren diyagram", "caption": "Zevk, sağladığınız üç girdiden gelir: bir tasarım sistemi, bir skill ve gerçek referans görseller — hangi modeli çalıştırdığınızdan bağımsız olarak."}, {"kind": "p", "text": "Ders: OpenCode size model özgürlüğü verir, ama zevk yine de özenle seçilmiş bir tasarım bağlamından gelir. Open Design tam olarak bu girdileri paketler; ikisinin neden birbirine uyduğunun nedeni de budur — her ikisi de açık kaynaklı ve yerel önceliklidir (daha fazlası aşağıda)."}]}, {"id": "setup", "heading": "OpenCode'u tasarım çalışması için sıfırdan kurun", "blocks": [{"kind": "p", "text": "Temiz bir makineden, UI oluşturabilen ve doğrulayabilen bir OpenCode'a giden tam yol şudur."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Beş adımlı kurulum akışı: kur, sağlayıcı anahtarınızla kimlik doğrula, AGENTS.md yapılandır, bir skill ekle, doğrula", "caption": "Kurulum sırası: kur → kimlik doğrula (sağlayıcı anahtarınız) → AGENTS.md yapılandır → bir skill ekle → gerçek bir tarayıcıda doğrula."}, {"kind": "steps", "items": [{"label": "Tasarım kurallarınızı kodlayın", "body": "Token'larınızı, ilkellerinizi ve kurallarınızı AGENTS.md (veya ondan referans verilen bir DESIGN.md) içine koyun, böylece çıktı jenerik bir görünüme dönmek yerine bir markayla eşleşsin. opencode.json içindeki instructions seçeneği, glob'lar aracılığıyla ek kural dosyalarına işaret edebilir."}, {"label": "Yetenekli bir model seçin", "body": "OpenCode modelden bağımsız olduğundan, tasarım geçişi için şu anda frontend'de en güçlü olan sağlayıcı/modeli seçin — ve iş akışınızın geri kalanını değişmeden bırakın."}]}]}, {"id": "screenshot-workflow", "heading": "Ekran görüntüsünden UI'a iş akışı", "blocks": [{"kind": "p", "text": "Herhangi bir ajanla en yüksek kaldıraçlı tasarım döngüsü, bir referans görseli çalışan, duyarlı bir UI'a dönüştürmek ve eşleşene kadar yinelemektir. Aynı beş adımlı biçim OpenCode'da da geçerlidir."}, {"kind": "ol", "items": ["Sahip olduğunuz en net görsel referanslardan başlayın — ve yalnızca tek bir hero görseli değil, birden çok durumu (masaüstü ve mobil, hover, boş, yükleniyor) dahil edin.", "Komutta spesifik olun; belirsiz komutlar jenerik UI üretir.", "Bir tasarım sistemi hazırlayın ve OpenCode'a token'ların ve kanonik ilkellerin nerede yaşadığını söyleyin (AGENTS.md içinde).", "Bir dev sunucusu çalıştırın ve ajanın gerçek bir tarayıcıda işlemesini sağlayın, sonucu kontrol etmek için kırılma noktalarına yeniden boyutlandırarak.", "OpenCode'un uygulamasını ekran görüntüleriyle karşılaştırmasını sağlayarak yineleyin — yalnızca derlendiğini onaylamasın."]}, {"kind": "p", "text": "TUI'da çalışma dizininizin bulanık bir aramasını yapmak için dosyalara @ ile referans verin, satır içi shell komutlarını başta bir ! ile çalıştırın ve eylemleri / komutlarıyla sürün. Ardından somut kısıtlarla komut verin:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Komutları küçük ve odaklı tutun, iyi yinelemeleri commit edin ve kötü olanları geri alın (geri aldığınızda OpenCode'a söyleyin), böylece her geçiş temiz bir temel üzerine inşa edilsin."}]}, {"id": "extend", "heading": "AGENTS.md, MCP ve paylaşılabilir oturumlar", "blocks": [{"kind": "p", "text": "Üç genişletme noktası, OpenCode'u sürekli tasarım çalışması için pratik kılar ve üçü de açık bir tasarım iş akışına temizce eşlenir."}, {"kind": "steps", "items": [{"label": "AGENTS.md kuralları", "body": "Proje kuralları, repo kökündeki bir AGENTS.md içinde yaşar (veya ~/.config/opencode/AGENTS.md içindeki global kurallar). Her çalıştırmada okunan, tasarım kurallarınız için kalıcı evdir ve diğer ajanların kullandığı CLAUDE.md dosyalarıyla uyumludur."}, {"label": "MCP sunucuları", "body": "OpenCode, mcp anahtarı altında yapılandırılan hem yerel (command) hem de uzak (URL) MCP sunucularını destekler — yalnızca OpenCode'da değil, ajanlar arasında çalışan tasarım bağlamı ve harici araçları getirmenin taşınabilir yolu."}, {"label": "Paylaşılabilir oturumlar", "body": "/share komutu, işbirliği veya inceleme için bir konuşmaya genel bir bağlantı oluşturur ve /unshare onu iptal eder — bir tasarım geçişi üzerine geri bildirim almak için kullanışlıdır."}]}, {"kind": "p", "text": "Bunlar taşınabilir, çok ajanlı yeteneklerdir — tam olarak Open Design'ın, her proje başına yeniden oluşturmak yerine düzenlemek için inşa edildiği türden şeyler."}]}, {"id": "vs", "heading": "Tasarım için OpenCode, Codex, Claude Code ve Cursor", "blocks": [{"kind": "p", "text": "Tasarım çalışması için tek bir kazanan yoktur — her ajanın farklı bir gücü vardır ve deneyimli ekipler bunları üst üste yığar. Adil bir özet:"}, {"kind": "table", "columns": ["Ajan", "Tasarım gücü", "En iyi olduğu alan"], "rows": [["OpenCode", "Açık kaynaklı ve modelden bağımsız; tek bir terminal iş akışının arkasında herhangi bir sağlayıcı çalıştırın", "BYOK özgürlüğü, model değiştirme, tamamen açık ve yerel öncelikli kurulumlar"], ["Codex", "Bir frontend skill'i ile güçlü görsel cila; görsel anlama", "Devredilen asenkron, sandbox'lanmış derlemeler, taşınabilir AGENTS.md kuralları"], ["Claude Code", "Spesifik tasarım kararları (hex, boşluk, tipografi) ve kod tabanının farkında UX", "Frontend akıl yürütmesi ve geniş bağlamlı yeniden düzenlemeler"], ["Cursor", "Canlı önizleme ve satır içi düzenlemelerle görsel oluştur-ve-gör döngüsü", "Bir IDE içinde sıkı yinele-ve-izle UI çalışması"]]}, {"kind": "p", "text": "Tekrarlanan topluluk kararı, zevkin insanlardan geldiğidir: hepsi skill'ler, referanslar ve kısıtlar olmadan jenerik bir estetiğe varsayılan olarak kayar. Çözülmesi gereken asıl sorun budur — ve bu sorun, model biçimli değil, tasarım aracı biçimlidir; OpenCode gibi açık bir ajanın açık bir tasarım katmanıyla bu kadar iyi eşleşmesinin nedeni de tam olarak budur."}]}, {"id": "pitfalls", "heading": "Tuzaklar ve “AI çöplüğü” görünümünden nasıl kaçınılır", "blocks": [{"kind": "p", "text": "AI tarafından üretilen tasarımla ilgili en yaygın şikayet, jenerik görünmesidir — yumuşak degradeler, yüzen paneller, aşırı büyük yuvarlatılmış köşeler, dramatik gölgeler, “bunu bir AI yaptı diye bağıran” bir Inter-ve-mor havası. Bildirilen diğer sorunlar arasında bozuk mobil düzenler ve UI metnine sızan talimatlar yer alır. Bunların hiçbiri OpenCode'a özgü değildir; herhangi bir ajan özenle seçilmiş bir tasarım bağlamı olmadan çalıştığında olan budur."}, {"kind": "steps", "items": [{"label": "Estetik bir skill ekleyin", "body": "Özenle seçilmiş bir tasarım skill'i, ajanı varsayılan görünüm yerine gerçek bir yöne bağlanmaya zorlar."}, {"label": "Gerçek bir tarayıcıda doğrulayın", "body": "Kırılma noktaları boyunca işleyin ve kendi kendini kontrol edin, böylece düzenler mobilde sessizce bozulmasın."}, {"label": "Token ve referans sağlayın", "body": "Gerçek tasarım token'ları ve referans ekran görüntüleri, çıktı kalitesi üzerindeki en büyük tek kaldıraçtır."}, {"label": "Kuralları AGENTS.md içinde kodlayın", "body": "“hero kartı yok, en fazla iki yazı tipi, marka öncelikli hiyerarşi” gibi kuralları, ajanın her çalıştırmada okuduğu yere koyun."}]}, {"kind": "p", "text": "Her hafifletmenin, hangi modeli çalıştırdığınızdan bağımsız olarak, ajana özenle seçilmiş bir tasarım bağlamı vermekle ilgili olduğuna dikkat edin. Bu bağlamı proje başına elle sürdürmek, Open Design'ın ortadan kaldırdığı zahmettir."}]}, {"id": "open-design", "heading": "Open Design içinde OpenCode ile tasarım", "blocks": [{"kind": "p", "text": "Open Design, yukarıdaki iş akışının sürekli istediği açık kaynaklı tasarım katmanıdır. OpenCode'u birinci taraf bir adaptör olarak ele alır ve onu özenle seçilmiş bir skill ve tasarım sistemi kütüphanesi, yapılandırılmış bir render hattı ve yerel bir masaüstü UI'sı ile sarmalar — böylece herhangi bir ajanı iyi yapan tasarım bağlamı, her seferinde elle bir araya getirilmek yerine ilk çalıştırmadan itibaren oradadır. Her iki proje de açık kaynaklı ve yerel önceliklidir, bu da eşleşmeyi doğal bir uyum haline getirir."}, {"kind": "ol", "items": ["Open Design'ı kurun ve ajanınız olarak OpenCode'u seçin.", "Kendi model sağlayıcı API anahtarınızla (BYOK) kimlik doğrulayın — kimlik bilgileri makinenizde kalır ve asla bizim üzerimizden proxy'lenmez.", "Herhangi bir sağlayıcı ve model seçin, artı bir tasarım sistemi ve bir skill, ardından tutarlı bir zevkle sunumlar, prototipler ve açılış sayfaları üretin.", "Her artefakt ve DESIGN.md dosyası, barındırılan bir bulutta değil, kendi reponuzda yaşar."]}, {"kind": "p", "text": "Aynı OpenCode ajanı, aynı model özgürlüğü — artı etrafında gerçek, taşınabilir, açık kaynaklı bir tasarım iş akışı. Yerel öncelikli ve Apache-2.0'dır, bu yüzden çalışmanız veya kimlik bilgileriniz hakkında hiçbir şey makinenizden ayrılmaz."}]}], "faqTitle": "Sıkça sorulan sorular", "faq": [{"name": "OpenCode gerçekten tasarım çalışması yapabilir mi?", "text": "Evet — bağlamda estetik bir skill, bir tasarım sistemi ve gerçek referans görsellerle OpenCode üretim kalitesinde, duyarlı UI üretir ve bunu bir tarayıcıda doğrulayabilir. Modelden bağımsız olduğundan, şu anda frontend'de en iyi olan hangi modelse onu çalıştırırsınız. Bu özenle seçilmiş bağlam olmadan jenerik bir görünüme dönme eğilimindedir; Open Design'ın doldurduğu boşluk da budur."}, {"name": "Tasarım için OpenCode ile hangi modeli kullanmalıyım?", "text": "Hangisini isterseniz — OpenCode, models.dev aracılığıyla sağlayıcıdan bağımsızdır, böylece Anthropic, OpenAI, Google, OpenRouter veya yerel modelleri aynı iş akışının arkasında çalıştırabilir ve istediğiniz zaman değiştirebilirsiniz. Tasarım çıktısının kalitesi, modelden çok daha fazla skill'inize, tasarım sisteminize ve referanslarınıza bağlıdır."}, {"name": "Open Design, OpenCode (SST) ekibi tarafından mı yapıldı?", "text": "Hayır. Open Design, OpenCode'u bir ajan olarak entegre eden bağımsız bir açık kaynaklı projedir. OpenCode'u yerel öncelikli, açık bir skill ve tasarım sistemi kütüphanesiyle tamamlar."}, {"name": "OpenCode ile tasarım yapmak için özel bir aboneliğe ihtiyacım var mı?", "text": "Hayır — OpenCode BYOK'tur. Kendi model sağlayıcı API anahtarınızı getirirsiniz ve Open Design kimlik bilgilerinizi asla proxy'lemez. Sağlayıcı kilidi yoktur."}, {"name": "Frontend tasarımı için OpenCode mu, Codex mi yoksa Claude Code mu?", "text": "Hepsi güçlüdür ve birçok ekip bunları üst üste yığar. OpenCode'un üstünlüğü tamamen açık kaynaklı ve modelden bağımsız olmasıdır; Codex devredilen, sandbox'lanmış derlemelerde öne çıkar; Claude Code spesifik, kod tabanının farkında tasarım kararlarıyla bilinir. Open Design, tasarım iş akışınızı değiştirmeden ajanlar arasında geçiş yapmanızı sağlar."}, {"name": "OpenCode'u tasarım bağlamı için nasıl genişletirim?", "text": "Kuralları AGENTS.md içinde kodlayın, taşınabilir araçlar ve tasarım bağlamı için mcp anahtarı altına MCP sunucuları ekleyin ve inceleme için paylaşılabilir oturumları kullanın. Open Design, özenle seçilmiş bir skill ve tasarım sistemi kütüphanesi sunar, böylece proje başına kurulumu atlarsınız."}, {"name": "Open Design, OpenCode veya SST ile bağlantılı mı?", "text": "Hayır. OpenCode, SST (Anomaly Innovations) tarafından sürdürülen açık kaynaklı bir projedir; Open Design, onu birinci taraf bir adaptör olarak destekleyen bağımsız bir açık kaynaklı projedir."}, {"name": "Dosyalarım ve kimlik bilgilerim güvende mi?", "text": "Evet — Open Design yerel önceliklidir. Dosyalarınız, artefaktlarınız ve DESIGN.md'niz kendi reponuzda kalır ve model sağlayıcı kimlik bilgileriniz doğrudan ajanınız tarafından kullanılır, asla Open Design sunucuları üzerinden yönlendirilmez."}], "ctaTitle": "OpenCode ile açık yolla tasarlayın.", "ctaBody": "Kendi model sağlayıcı anahtarınızı getirin, her dosyayı yerel tutun ve zaten kullandığınız açık ajanın etrafında özenle seçilmiş bir tasarım kütüphanesi edinin.", "ctaActions": [{"label": "OpenCode'u Open Design içinde kullanın", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub'da yıldız verin", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Masaüstü uygulamasını indirin", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Desteklenen tüm ajanları görün"},
      },
    },
    'uk': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code для дизайну — Open Design",
        description: "Як дизайнери використовують Claude Code для UI та вебдизайну, і як Open Design перетворює його на справжнього дизайн-агента — local-first, BYOK, із кураторською бібліотекою skill-ів і дизайн-систем.",
        breadcrumb: "Claude Code",
        label: "Агент · Claude Code",
        heading: "Claude Code для дизайну.",
        lead: "Claude Code — це термінальний агент для кодування від Anthropic. Люди вже використовують його для створення UI, дизайн-систем і лендингів. Open Design вбудовує його в повноцінний дизайн-процес — підключіть свій ключ Anthropic або підписку Claude, тримайте кожен файл локально.",
        rich: {"heroCtaLead": "Open Design перетворює Claude Code на local-first дизайн-агента з відкритим кодом — ваш ключ Anthropic або підписка Claude, ваші файли та кураторська бібліотека skill-ів і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використати Claude Code в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code широко вважають агентом для кодування з найкращим смаком до фронтенду — він міркує про інтерфейси з незвичною точністю, називаючи конкретні значення hex, відступи й типографічні шкали, і рефакторить UI у великій кодовій базі, не втрачаючи нитки. Але «з коробки» він усе ще тяжіє до загального вигляду, доки ви не дасте йому дизайн-систему, skill-и та реальні референси. Це практичний наскрізний посібник з використання Claude Code для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування у структурований процес разом з Open Design.", "Тут розглядається, чим насправді є Claude Code, чому він сильний у фронтенді, як налаштувати його з нуля, робочий процес із CLAUDE.md і Skills, офіційний двосторонній обмін із Figma, як він порівнюється з Codex і Cursor, пастки, через які вивід ШІ виглядає загальним, і як Open Design закриває цю прогалину як відкритий local-first дизайн-шар."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Цикл зворотного зв'язку дизайну Claude Code: термінальний агент, що ухвалює конкретні дизайн-рішення, браузер, що рендерить UI, і робочий простір зі стрілкою зворотного зв'язку", "caption": "Основний цикл: Claude Code продумує конкретні UI-рішення в терміналі, рендерить і перевіряє їх у справжньому браузері та сходиться до ваших референсів."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-claude-code", "label": "Чим насправді є Claude Code"}, {"id": "why-design", "label": "Чому Claude Code добрий у дизайні"}, {"id": "setup", "label": "Налаштування Claude Code для дизайну (з нуля)"}, {"id": "skills-workflow", "label": "Робочий процес із CLAUDE.md і Skills"}, {"id": "figma", "label": "Двосторонній обмін Claude Code + Figma"}, {"id": "vs", "label": "Claude Code проти Codex проти Cursor"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI slop»"}, {"id": "open-design", "label": "Дизайн із Claude Code в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-claude-code", "heading": "Чим насправді є Claude Code", "blocks": [{"kind": "p", "text": "Claude Code — це агентний інструмент кодування від Anthropic. Він читає вашу кодову базу, редагує файли, виконує команди й інтегрується з вашими інструментами розробки — планує, пише та перевіряє роботу за завданнями природною мовою, а не просто автодоповнює рядки."}, {"kind": "p", "text": "Він постачається на кількох поверхнях, що мають один і той самий рушій: термінальний CLI, розширення IDE для VS Code, Cursor і JetBrains, десктопний застосунок з візуальним переглядом diff та вебдосвід для тривалих завдань. Ваші файли CLAUDE.md, налаштування та сервери MCP переносяться між усіма ними."}, {"kind": "steps", "items": [{"label": "Файл інструкцій", "body": "Claude Code читає файл CLAUDE.md у корені проєкту на початку кожної сесії — природне місце, щоб закодувати ваші дизайн-конвенції, tokens і чеклісти рев'ю."}, {"label": "Skills", "body": "Agent Skills упаковують повторювані інструкції, скрипти та ресурси, які Claude завантажує за потреби, включно з офіційним Frontend Design skill від Anthropic для смаку."}, {"label": "План і субагенти", "body": "Він може планувати перед дією та породжувати субагентів, що працюють над різними частинами завдання паралельно, завдяки чому великі рефактори UI лишаються узгодженими."}]}, {"kind": "ul", "items": ["Постачальник: Anthropic", "Облікові дані: API-ключ Anthropic (BYOK, через Console) або підписка Claude (Pro / Max)", "Поверхні: термінальний CLI, розширення VS Code / Cursor / JetBrains, десктопний застосунок, веб"]}]}, {"id": "why-design", "heading": "Чому Claude Code добрий у дизайні", "blocks": [{"kind": "p", "text": "Серед агентів для кодування Claude Code має репутацію смакового у фронтенд-роботі. Це пояснюється кількома речами."}, {"kind": "steps", "items": [{"label": "Конкретні, а не розпливчасті рішення", "body": "Claude Code схильний обирати конкретні варіанти — точні значення hex, шкали відступів, типографічні градації та ієрархію компонентів — замість відмахування, і саме це відрізняє справжній інтерфейс від заглушки."}, {"label": "Міркування з урахуванням кодової бази", "body": "Маючи великий робочий контекст, він рефакторить UI одразу в багатьох файлах, повторно використовуючи ваші наявні компоненти й tokens замість того, щоб винаходити одноразові стилі."}, {"label": "Офіційний frontend skill", "body": "Anthropic постачає Frontend Design skill, який змушує Claude спершу написати дизайн-напрямок і свідомо уникати загальних системних шрифтів та передбачуваних фіолетових градієнтів."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Схема, що показує, як дизайн-система, skill і референсне зображення сходяться в добрий дизайн-результат", "caption": "Смак з'являється з трьох вхідних даних, які надаєте ви: дизайн-системи, skill-а та реальних референсних зображень."}, {"kind": "p", "text": "Урок той самий, що його Anthropic робить про власні моделі: Claude не має смаку за замовчуванням — наданий сам собі, він сходиться до статистичного центру вебдизайну (Inter, фіолетові градієнти, м'які тіні). Він створює добрий дизайн, коли ви даєте йому обмеження. Open Design упаковує саме ці вхідні дані, тому ці двоє пасують одне одному (далі — детальніше)."}]}, {"id": "setup", "heading": "Налаштуйте Claude Code для дизайну, з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Claude Code, який може будувати й перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Процес налаштування з п'яти кроків: встановлення, автентифікація, налаштування CLAUDE.md, додавання skill-а, перевірка", "caption": "Послідовність налаштування: встановлення → автентифікація → налаштування CLAUDE.md → додавання Frontend Design skill → увімкнення перевірки в браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої дизайн-правила", "body": "Помістіть свої tokens, примітиви та конвенції в CLAUDE.md і вкажіть на них Claude, щоб вивід відповідав бренду, а не звертався до загального вигляду."}, {"label": "Додайте перевірку в браузері", "body": "Підключіть Playwright або Chrome MCP, щоб Claude рендерив у справжньому браузері та перевіряв свій вивід на різних брейкпойнтах, а не лише підтверджував, що збірка проходить."}]}]}, {"id": "skills-workflow", "heading": "Робочий процес із CLAUDE.md і Skills", "blocks": [{"kind": "p", "text": "Найрезультативніший дизайн-цикл із Claude Code — це подавати йому реальні референси разом із вашим дизайн-контекстом, а потім ітерувати, доки UI не збіжиться — при цьому CLAUDE.md і Skills несуть обмеження, тож вам не доводиться пояснювати їх заново в кожному промпті."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є, — і включайте кілька станів (десктоп і мобільний, hover, порожній, завантаження), а не лише один hero-кадр.", "Будьте конкретні в промпті; розпливчасті промпти дають загальний UI навіть із сильним агентом.", "Тримайте свою дизайн-систему й конвенції в CLAUDE.md і кажіть Claude, де живуть tokens і канонічні примітиви.", "Додайте Frontend Design skill, щоб Claude обрав реальний естетичний напрямок перед написанням коду.", "Підключіть перевірку в браузері, щоб Claude рендерив, змінював розмір під брейкпойнти й порівнював із референсами — а не лише підтверджував, що збірка проходить."]}, {"kind": "p", "text": "Перетягніть референсне зображення в сесію та задайте промпт із конкретними обмеженнями:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Запускайте dev-сервер поруч, тримайте промпти невеликими й сфокусованими та комітьте вдалі ітерації / відкочуйте невдалі (кажучи Claude, коли ви відкочуєте), щоб кожен прохід будувався на чистій основі. Використовуйте режим планування для більших рефакторів, щоб переглянути підхід до будь-яких змін у файлах."}]}, {"id": "figma", "heading": "Claude Code + Figma: двосторонній обмін дизайн ↔ код", "blocks": [{"kind": "p", "text": "У лютому 2026 року Anthropic і Figma випустили першокласну двонапрямлену інтеграцію через сервер Figma MCP. Вона працює в обидва боки."}, {"kind": "steps", "items": [{"label": "Дизайн → Код", "body": "Виберіть фрейм у Figma або вставте посилання в Claude Code, підтягніть дизайн-контекст і попросіть реалізувати дизайн із вашою наявною бібліотекою компонентів. Code Connect тримає вивід узгодженим із вашими реальними компонентами."}, {"label": "Код → Дизайн", "body": "Зберіть і перегляньте функцію в браузері, а потім скажіть «Send this to Figma», щоб зафіксувати робочий UI як редаговані шари Figma — увесь екран або вибраний елемент."}]}, {"kind": "p", "text": "Встановіть її одного разу за допомогою claude plugin install figma@claude-plugins-official (Dev Mode MCP вимагає платного плану Figma). Той самий Figma MCP доступний для Claude Code, Codex, Cursor і VS Code — саме той тип переносної, мультиагентної можливості, яку Open Design створено оркеструвати."}]}, {"id": "vs", "heading": "Claude Code проти Codex проти Cursor для дизайну", "blocks": [{"kind": "p", "text": "Єдиного переможця для дизайн-роботи немає — у кожного агента своя сильна сторона, і досвідчені команди поєднують їх. Чесне резюме:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайні", "Найкраще для"], "rows": [["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) та UX-міркування з урахуванням кодової бази", "Фронтенд-міркування й рефактори з великим контекстом"], ["Codex", "Сильне візуальне опрацювання й розуміння зображень; асинхронні збірки в пісочниці", "Делеговані асинхронні збірки та переносні правила AGENTS.md"], ["Cursor", "Цикл «зроби й подивись» із живим попереднім переглядом та інлайн-правками", "Щільна робота над UI у режимі «ітеруй і спостерігай» усередині IDE"]]}, {"kind": "p", "text": "Сталий вердикт спільноти такий: смак походить від людей — усі три за замовчуванням тяжіють до загальної естетики без skill-ів, референсів і обмежень. Це і є справжня проблема, яку треба розв'язати — і вона має форму дизайн-інструмента, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI slop»", "blocks": [{"kind": "p", "text": "Навіть із репутацією Claude Code за смак найпоширеніша скарга на дизайн, згенерований ШІ, — що він виглядає загальним: шрифти Inter, фіолетові градієнти на білому, м'які тіні, завеликі заокруглені кути, естетика, яка «кричить, що це зробив ШІ». Сама Anthropic пояснює це збіжністю розподілу: безпечні рішення домінують у тренувальних даних вебу. Серед інших повідомлених проблем — поламані мобільні розкладки та інструкції, що протікають у текст UI."}, {"kind": "steps", "items": [{"label": "Встановіть Frontend Design skill", "body": "Він змушує Claude обрати реальний напрямок і явно уникає шрифтів та градієнтів, надмірно вживаних ШІ."}, {"label": "Увімкніть перевірку в браузері", "body": "Змусьте Claude рендерити й самоперевірятися на різних брейкпойнтах, щоб розкладки не ламались на мобільному непомітно."}, {"label": "Надайте tokens і референси", "body": "Реальні дизайн-tokens і референсні скриншоти — найпотужніший важіль якості виводу."}, {"label": "Закодуйте правила в CLAUDE.md", "body": "Помістіть правила штибу «без hero-карток, максимум два шрифти, ієрархія за брендом» туди, де агент читає їх щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожен спосіб пом'якшення зводиться до надання агенту кураторського дизайн-контексту. Підтримувати цей контекст вручну для кожного проєкту — це рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн із Claude Code всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це той дизайн-шар з відкритим кодом, якого постійно потребує наведений вище процес. Він трактує Claude Code як власний адаптер і обгортає його кураторською бібліотекою skill-ів і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — щоб дизайн-контекст, який робить Claude Code добрим, був на місці з першого запуску, а не збирався вручну щоразу."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Claude Code як свого агента.", "Автентифікуйтеся своїм API-ключем Anthropic (BYOK) або підпискою Claude — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та skill, а потім генеруйте презентації, прототипи й лендинги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в розміщеній хмарі."]}, {"kind": "p", "text": "Той самий агент Claude Code, той самий ключ — плюс реальний, переносний дизайн-процес з відкритим кодом навколо нього. Він local-first і Apache-2.0, тож ніщо у вашій роботі чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи добрий Claude Code для дизайн-роботи?", "text": "Так — його широко вважають агентом для кодування з найкращим смаком до фронтенду, що ухвалює конкретні рішення з урахуванням кодової бази щодо значень hex, відступів і типографічних шкал. Зі skill-ом Frontend Design, дизайн-системою та реальними референсними зображеннями в контексті він створює UI продакшн-якості, адаптивний, і може перевірити його в браузері. Без цього контексту він тяжіє до загального вигляду — і саме цю прогалину закриває Open Design."}, {"name": "Чи потрібна мені підписка Claude, щоб проєктувати з Claude Code?", "text": "Ви можете використовувати або API-ключ Anthropic (BYOK, через Console), або підписку Claude (Pro / Max). У будь-якому разі Open Design ніколи не проксіює ваші облікові дані — їх безпосередньо використовує ваш агент на вашій машині."}, {"name": "Claude Code чи Codex для фронтенд-дизайну?", "text": "Обидва сильні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази та фронтенд-міркуваннями; Codex має сильне візуальне опрацювання й чудово справляється з делегованими збірками в пісочниці. Багато команд використовують обидва — Open Design дозволяє перемикати агентів без зміни дизайн-процесу."}, {"name": "Як підключити Claude Code до Figma?", "text": "Встановіть офіційний плагін Figma командою claude plugin install figma@claude-plugins-official. Тоді ви зможете реалізовувати фрейми Figma в коді, використовуючи дизайн-контекст, і відправляти робочий UI назад у редаговані фрейми Figma за допомогою «Send this to Figma». Dev Mode MCP вимагає платного плану Figma."}, {"name": "Що таке Skills і CLAUDE.md?", "text": "CLAUDE.md — це markdown-файл у корені проєкту, який Claude Code читає на початку кожної сесії — місце, щоб закодувати ваші дизайн-конвенції. Skills упаковують повторювані інструкції та ресурси, які Claude завантажує за потреби, включно з офіційним Frontend Design skill від Anthropic. Open Design постачає кураторську бібліотеку обох, щоб ви пропустили налаштування для кожного проєкту."}, {"name": "Як уникнути загальної естетики «AI slop»?", "text": "Встановіть Frontend Design skill, надайте реальні дизайн-tokens і референсні скриншоти, закодуйте правила бренду в CLAUDE.md та увімкніть перевірку в браузері. Open Design постачає це як кураторську бібліотеку, щоб ви пропустили налаштування для кожного проєкту."}, {"name": "Чи пов'язаний Open Design з Anthropic?", "text": "Ні. Claude Code — продукт Anthropic; Open Design — незалежний проєкт з відкритим кодом, який підтримує його як власний адаптер. Claude і Claude Code — торгові марки Anthropic."}, {"name": "Чи мої файли й облікові дані в безпеці?", "text": "Так — Open Design local-first і Apache-2.0. Ваші файли, артефакти й DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані Anthropic використовуються безпосередньо вашим агентом і ніколи не маршрутизуються через сервери Open Design."}], "ctaTitle": "Проєктуйте з Claude Code, відкрито.", "ctaBody": "Підключіть власний ключ Anthropic або підписку Claude, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтесь.", "ctaActions": [{"label": "Використати Claude Code в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex для дизайну — Open Design",
        description: "Як люди використовують OpenAI Codex для UI та вебдизайну — плагін Product Design, інтеграцію з Figma, фронтенд-skill-и — і як Open Design перетворює Codex на local-first дизайн-агента з відкритим кодом.",
        breadcrumb: "Codex",
        label: "Агент · Codex",
        heading: "Codex для дизайну.",
        lead: "Codex — це агент для кодування від OpenAI. Із плагіном Product Design та інтеграцією Figma він став серйозним дизайн-інструментом. Open Design вбудовує Codex у дизайн-процес з відкритим кодом — ваш ключ OpenAI або підписка ChatGPT, ваші файли, local-first.",
        rich: {"heroCtaLead": "Open Design перетворює Codex на local-first дизайн-агента з відкритим кодом — ваш ключ OpenAI, ваші файли та кураторська бібліотека skill-ів і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використати Codex в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex починався як генератор коду, але у 2026 році став надійним інструментом для проєктування справжніх інтерфейсів — щойно ви даєте йому правильні референси, skill-и та цикл перевірки. Це практичний наскрізний посібник з використання Codex для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування в структурований дизайн-процес разом з Open Design.", "Тут розглядається, чим є Codex сьогодні, чому він раптом став добрим у фронтенді, як налаштувати його з нуля, цикл «скриншот → UI», офіційний двосторонній обмін із Figma, як він порівнюється з Cursor і Claude Code, пастки, через які вивід ШІ виглядає загальним, і як Open Design закриває цю прогалину як відкритий local-first дизайн-шар."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Цикл зворотного зв'язку дизайну Codex: термінальний агент, браузер, що рендерить UI, і робочий простір зі стрілкою зворотного зв'язку", "caption": "Основний цикл: Codex будує UI у терміналі, рендерить і перевіряє його у справжньому браузері та ітерує до ваших референсів."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-codex", "label": "Чим насправді є OpenAI Codex"}, {"id": "why-design", "label": "Чому Codex тепер добрий у дизайні"}, {"id": "setup", "label": "Налаштування Codex для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «скриншот → UI»"}, {"id": "figma", "label": "Двосторонній обмін Codex + Figma"}, {"id": "vs", "label": "Codex проти Cursor проти Claude Code"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI slop»"}, {"id": "open-design", "label": "Дизайн із Codex в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-codex", "heading": "Чим насправді є OpenAI Codex (і чим він не є)", "blocks": [{"kind": "p", "text": "Спершу — уточнення, яке збиває з пантелику майже всіх, хто шукає «Codex». Початковий OpenAI Codex був моделлю автодоповнення коду 2021 року, що живила ранній GitHub Copilot і була виведена з експлуатації у 2023 році. Ця сторінка не про неї. Сьогоднішній Codex — це агентний інструмент кодування від OpenAI: він планує, пише, виконує й перевіряє код за завданнями природною мовою."}, {"kind": "p", "text": "Сучасний Codex постачається на чотирьох поверхнях: термінальний CLI (переписаний на Rust, під ліцензією Apache-2.0), розширення IDE для VS Code, Cursor і Windsurf, хмарний/вебдосвід для делегованих асинхронних завдань і десктопний застосунок із вбудованим браузером та Computer Use."}, {"kind": "steps", "items": [{"label": "Модель за замовчуванням", "body": "Станом на середину 2026 року рекомендована модель — gpt-5.5, а gpt-5.4 — це модель, яку OpenAI явно тренувала для фронтенду й роботи з комп'ютером."}, {"label": "Файл інструкцій", "body": "Codex читає файл AGENTS.md у вашому проєкті (міжінструментальний стандарт) для правил проєкту — природне місце, щоб закодувати ваші дизайн-конвенції."}, {"label": "Пісочниця", "body": "Він працює в пісочниці рівня ядра (workspace-write за замовчуванням), тож агент, що редагує ваш UI, не може вийти за межі проєкту."}]}, {"kind": "ul", "items": ["Постачальник: OpenAI", "Облікові дані: API-ключ OpenAI (BYOK) або підписка ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Ліцензія CLI: Apache-2.0, відкритий код"]}]}, {"id": "why-design", "heading": "Чому Codex тепер добрий у дизайні", "blocks": [{"kind": "p", "text": "На початку 2026 року зійшлися три речі, що зробили Codex справжнім дизайн-інструментом, а не загальним генератором коду."}, {"kind": "steps", "items": [{"label": "Модель, натренована для фронтенду", "body": "OpenAI випустила GPT-5.4 — свою першу основну модель, натреновану для фронтенду й роботи з комп'ютером, із набагато кращим розумінням зображень у дизайн-процесі та сильнішою самоперевіркою. Вона навіть може генерувати mood-борди та візуальні варіанти перед тим, як обрати фінальні ассети."}, {"label": "Офіційний frontend skill", "body": "Каталог openai/skills постачає кураторський frontend-skill, що нав'язує реальний смак: розкладки без карток, повноширинні hero-блоки, ієрархія за брендом, стриманий рух, щонайбільше два шрифти й один акцентний колір — і змушує Codex написати візуальну тезу перед побудовою."}, {"label": "Перевірка в браузері", "body": "Зі skill-ом Playwright Codex відкриває справжній браузер, змінює розмір під брейкпойнти й порівнює свій вивід із референсом, а не лише перевіряє, що збірка проходить."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Схема, що показує, як дизайн-система, skill і референсне зображення сходяться в добрий дизайн-результат", "caption": "Смак з'являється з трьох вхідних даних, які надаєте ви: дизайн-системи, skill-а та реальних референсних зображень."}, {"kind": "p", "text": "Урок за всіма трьома: Codex не має смаку за замовчуванням. Він створює добрий дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичний skill і конкретні референси. Open Design упаковує саме ці вхідні дані, тому ці двоє пасують одне одному (далі — детальніше)."}]}, {"id": "setup", "heading": "Налаштуйте Codex для дизайну, з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Codex, який може будувати й перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Процес налаштування з п'яти кроків: встановлення, автентифікація, налаштування, встановлення skill-а, перевірка", "caption": "Послідовність налаштування: встановлення → автентифікація → налаштування AGENTS.md → встановлення frontend skill → увімкнення перевірки в браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої дизайн-правила", "body": "Помістіть свої tokens, примітиви та конвенції в AGENTS.md або DESIGN.md і вкажіть на них Codex, щоб вивід відповідав бренду, а не звертався до загального вигляду."}, {"label": "Виберіть правильний рівень міркування", "body": "OpenAI зазначає, що низький-середній рівні міркування часто дають сильніші фронтенд-результати, ніж найвище налаштування."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «скриншот → UI»", "blocks": [{"kind": "p", "text": "Найрезультативніший дизайн-цикл із Codex — перетворити референсне зображення на робочий, адаптивний UI та ітерувати, доки воно не збіжиться. Власні рекомендації OpenAI зводяться до п'яти кроків."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є, — і включайте кілька станів (десктоп і мобільний, hover, порожній, завантаження), а не лише один hero-кадр.", "Будьте конкретні в промпті; розпливчасті промпти дають загальний UI.", "Підготуйте дизайн-систему й скажіть Codex, де живуть tokens і канонічні примітиви.", "Увімкніть інтерактивний skill Playwright, щоб Codex рендерив у справжньому браузері й змінював розмір під брейкпойнти.", "Ітеруйте, змушуючи Codex порівнювати свою реалізацію зі скриншотами — а не лише підтверджувати, що збірка проходить."]}, {"kind": "p", "text": "Подавайте зображення, перетягуючи скриншот у термінал або через прапорець зображення, а потім задавайте промпт із конкретними обмеженнями:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Запускайте dev-сервер у другому терміналі, тримайте промпти невеликими й сфокусованими та комітьте вдалі ітерації / відкочуйте невдалі (кажучи Codex, коли ви відкочуєте), щоб кожен прохід будувався на чистій основі."}]}, {"id": "figma", "heading": "Codex + Figma: двосторонній обмін дизайн ↔ код", "blocks": [{"kind": "p", "text": "У лютому 2026 року OpenAI і Figma оголосили про офіційне партнерство, перетворивши попередню бета-версію Figma MCP на першокласну двонапрямлену інтеграцію. Вона працює в обидва боки."}, {"kind": "steps", "items": [{"label": "Дизайн → Код", "body": "Скопіюйте «link to selection» фрейму у Figma, вставте його в Codex із get_design_context і попросіть реалізувати дизайн із вашою наявною бібліотекою компонентів."}, {"label": "Код → Дизайн", "body": "Інструмент generate_figma_design («Code to Canvas») перетворює живий робочий UI назад на редаговані фрейми Figma — увесь екран, вибраний елемент або цілий файл."}]}, {"kind": "p", "text": "Figma MCP працює як віддалений сервер і звільнений від лімітів швидкості. Додайте його одного разу, і він стане доступним для Codex, Claude Code, Cursor, VS Code тощо — саме той тип переносної, мультиагентної можливості, яку Open Design створено оркеструвати."}]}, {"id": "vs", "heading": "Codex проти Cursor проти Claude Code для дизайну", "blocks": [{"kind": "p", "text": "Єдиного переможця для дизайн-роботи немає — у кожного агента своя сильна сторона, і досвідчені команди поєднують їх. Чесне резюме:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайні", "Найкраще для"], "rows": [["Codex", "Сильне візуальне опрацювання після GPT-5.4 + frontend-skill; розуміння зображень", "Делеговані асинхронні збірки, запуски в пісочниці, переносні правила AGENTS.md"], ["Cursor", "Цикл «зроби й подивись» із живим попереднім переглядом та інлайн-правками", "Щільна робота над UI у режимі «ітеруй і спостерігай» усередині IDE"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) та UX з урахуванням кодової бази", "Фронтенд-міркування й рефактори з великим контекстом"]]}, {"kind": "p", "text": "Сталий вердикт спільноти такий: смак походить від людей — усі три за замовчуванням тяжіють до загальної естетики без skill-ів, референсів і обмежень. Це і є справжня проблема, яку треба розв'язати — і вона має форму дизайн-інструмента, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI slop»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на дизайн, згенерований Codex, — що він виглядає загальним: м'які градієнти, плаваючі панелі, завеликі заокруглені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив ШІ». Серед інших повідомлених проблем — поламані мобільні розкладки, інструкції, що протікають у текст UI, та швидке досягнення лімітів використання."}, {"kind": "steps", "items": [{"label": "Встановіть frontend skill", "body": "Кураторський естетичний skill змушує Codex обрати реальний напрямок замість вигляду за замовчуванням."}, {"label": "Увімкніть перевірку Playwright", "body": "Змусьте Codex рендерити й самоперевірятися на різних брейкпойнтах, щоб розкладки не ламались на мобільному непомітно."}, {"label": "Надайте tokens і референси", "body": "Реальні дизайн-tokens і референсні скриншоти — найпотужніший важіль якості виводу."}, {"label": "Закодуйте правила в AGENTS.md", "body": "Помістіть правила штибу «без hero-карток, максимум два шрифти, ієрархія за брендом» туди, де агент читає їх щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожен спосіб пом'якшення зводиться до надання агенту кураторського дизайн-контексту. Підтримувати цей контекст вручну для кожного проєкту — це рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн із Codex всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це той дизайн-шар з відкритим кодом, якого постійно потребує наведений вище процес. Він трактує Codex як власний адаптер і обгортає його кураторською бібліотекою skill-ів і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — щоб дизайн-контекст, який робить Codex добрим, був на місці з першого запуску, а не збирався вручну щоразу."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Codex як свого агента.", "Автентифікуйтеся своїм API-ключем OpenAI (BYOK) або підпискою ChatGPT — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та skill, а потім генеруйте презентації, прототипи й лендинги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в розміщеній хмарі."]}, {"kind": "p", "text": "Той самий агент Codex, той самий ключ — плюс реальний, переносний дизайн-процес з відкритим кодом навколо нього. Він local-first і Apache-2.0, тож ніщо у вашій роботі чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи справді OpenAI Codex може виконувати дизайн-роботу?", "text": "Так — із frontend skill, дизайн-системою та реальними референсними зображеннями в контексті Codex (особливо на GPT-5.4) створює UI продакшн-якості, адаптивний, і може перевірити його в браузері. Без цього контексту він тяжіє до загального вигляду — і саме цю прогалину закриває Open Design."}, {"name": "Це плагін OpenAI Codex Product Design?", "text": "Ні. Open Design — незалежний проєкт з відкритим кодом, який інтегрує Codex як агента. Він доповнює власний інструментарій OpenAI local-first відкритою бібліотекою skill-ів і дизайн-систем."}, {"name": "Чи потрібна мені підписка ChatGPT, щоб проєктувати з Codex?", "text": "Ви можете використовувати або API-ключ OpenAI (BYOK), або свою підписку ChatGPT. Вхід через ChatGPT зазвичай дає щедріші ліміти; у будь-якому разі Open Design ніколи не проксіює ваші облікові дані."}, {"name": "Codex чи Claude Code для фронтенд-дизайну?", "text": "Обидва сильні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази; Codex має сильне візуальне опрацювання після GPT-5.4 й чудово справляється з делегованими збірками в пісочниці. Багато команд використовують обидва — Open Design дозволяє перемикати агентів без зміни дизайн-процесу."}, {"name": "Як підключити Codex до Figma?", "text": "Додайте офіційний сервер Figma MCP (codex mcp add figma --url https://mcp.figma.com/mcp). Тоді ви зможете реалізовувати фрейми Figma в коді за допомогою get_design_context і відправляти робочий UI назад у редаговані фрейми Figma за допомогою generate_figma_design."}, {"name": "Як уникнути загальної естетики «AI slop»?", "text": "Встановіть frontend skill, надайте реальні дизайн-tokens і референсні скриншоти, закодуйте правила бренду в AGENTS.md та увімкніть перевірку Playwright. Open Design постачає це як кураторську бібліотеку, щоб ви пропустили налаштування для кожного проєкту."}, {"name": "Чи пов'язаний Open Design з OpenAI?", "text": "Ні. Codex — продукт OpenAI; Open Design — незалежний проєкт з відкритим кодом, який підтримує його як власний адаптер. OpenAI і Codex — торгові марки OpenAI."}, {"name": "Чи мої файли й облікові дані в безпеці?", "text": "Так — Open Design local-first. Ваші файли, артефакти й DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані OpenAI використовуються безпосередньо вашим агентом і ніколи не маршрутизуються через сервери Open Design."}], "ctaTitle": "Проєктуйте з Codex, відкрито.", "ctaBody": "Підключіть власний ключ OpenAI, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтесь.", "ctaActions": [{"label": "Використати Codex в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor для дизайнерів — Open Design",
        description: "Як дизайнери використовують Cursor для UI та вебдизайну — Design Mode, Figma-у-код, Figma MCP — і як Open Design перетворює Cursor на local-first дизайн-агента з відкритим кодом.",
        breadcrumb: "Cursor",
        label: "Агент · Cursor",
        heading: "Cursor для дизайнерів.",
        lead: "Cursor — це AI-редактор коду, тепер із візуальним Design Mode. Дизайнери використовують його, щоб редагувати UI вказуванням і малюванням, і перетворювати Figma на код. Open Design вбудовує Cursor Agent у дизайн-процес з відкритим кодом, що тримає ваші файли локально.",
        rich: {"heroCtaLead": "Open Design перетворює Cursor на local-first дизайн-агента з відкритим кодом — ваш акаунт Cursor або ключі моделей, ваші файли та кураторська бібліотека skill-ів і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використати Cursor в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor — це AI-first редактор коду, який зробив «зроби й подивись, як воно рендериться» стандартним способом випускати UI. З режимом Agent, інлайн-правками, попереднім переглядом усередині редактора та Figma через MCP він став справжнім дизайн-інструментом — щойно ви даєте йому правильні референси, правила та цикл перевірки. Це практичний наскрізний посібник з використання Cursor для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування в структурований дизайн-процес разом з Open Design.", "Тут розглядається, чим насправді є Cursor, чому його щільний цикл «ітеруй і спостерігай» добрий для дизайну, як налаштувати його з нуля, цикл «скриншот і попередній перегляд → UI», двосторонній обмін із Figma через MCP, як він порівнюється з Codex і Claude Code, пастки, через які вивід ШІ виглядає загальним, і як Open Design закриває цю прогалину як відкритий local-first дизайн-шар."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Збіжність дизайну Cursor: редактор ліворуч, кураторський хаб skill-ів і дизайн-систем посередині зі знаком Cursor у центрі та відрендерений UI праворуч", "caption": "Основна ідея: Cursor редагує й рендерить UI в редакторі, а кураторський дизайн-хаб подає йому систему, skill-и та референси, що роблять вивід умисним."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-cursor", "label": "Чим насправді є Cursor"}, {"id": "why-design", "label": "Чому Cursor добрий у дизайні"}, {"id": "setup", "label": "Налаштування Cursor для дизайну (з нуля)"}, {"id": "preview-workflow", "label": "Робочий процес «попередній перегляд → UI»"}, {"id": "figma", "label": "Cursor + Figma через MCP"}, {"id": "vs", "label": "Cursor проти Codex проти Claude Code"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI slop»"}, {"id": "open-design", "label": "Дизайн із Cursor в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-cursor", "heading": "Чим насправді є Cursor", "blocks": [{"kind": "p", "text": "Cursor — це AI-first редактор коду, створений компанією Anysphere. Це форк VS Code, тож він зберігає звичний редактор, розширення та комбінації клавіш, але перебудовує робочий процес навколо AI-агента, який може читати весь ваш проєкт, редагувати кілька файлів, виконувати команди та ітерувати разом з вами в циклі."}, {"kind": "p", "text": "Для дизайн-роботи важливі поверхні — це режим Agent (ви описуєте результат, а Cursor планує й редагує між файлами), інлайн-правки та доповнення Tab для швидких налаштувань, попередній перегляд / браузер усередині редактора, щоб бачити робочий UI, не залишаючи вікно, і підтримка MCP, що дозволяє підтягувати зовнішній контекст, як-от живий файл Figma."}, {"kind": "steps", "items": [{"label": "Правила проєкту", "body": "Cursor читає файли інструкцій проєкту — версіоновані правила `.mdc` під `.cursor/rules` та звичайний `AGENTS.md` — тож ви можете закодувати свої дизайн-конвенції там, де агент читає їх щоразу."}, {"label": "Моделі", "body": "Cursor гнучкий до моделей: він постачається з передовими моделями через вашу підписку й також підтримує підключення власних ключів моделей, тож ви обираєте рушій за тим самим робочим процесом редактора."}, {"label": "MCP", "body": "Він розмовляє Model Context Protocol, тож зовнішні сервери — найрелевантніше, сервер Figma MCP — стають першокласним контекстом для агента."}]}, {"kind": "ul", "items": ["Постачальник: Anysphere", "Облікові дані: акаунт / підписка Cursor (Hobby / Pro / Business) або власні ключі моделей (BYOK)", "Форма: AI-first редактор коду (форк VS Code) з агентом і попереднім переглядом усередині редактора"]}]}, {"id": "why-design", "heading": "Чому Cursor добрий у дизайні", "blocks": [{"kind": "p", "text": "Дизайн-перевага Cursor — не окрема функція, а щільність циклу «зроби й подивись». Три речі роблять його схожим на дизайн-інструмент, а не на загальний генератор коду."}, {"kind": "steps", "items": [{"label": "Щільний цикл «ітеруй і спостерігай»", "body": "Ви задаєте промпт, Cursor редагує між файлами, а попередній перегляд усередині редактора рендерить результат миттєво — тож ви налаштовуєте відступи, ієрархію та рух за секунди замість того, щоб ходити кругом через окремий термінал і браузер."}, {"label": "Пряме візуальне редагування", "body": "Окрім чату, Cursor дозволяє вибирати елементи в попередньому перегляді й підправляти стилі, тож дрібні візуальні корекції відчуваються як дизайн-правки, а не археологія коду."}, {"label": "Правила проєкту та контекст MCP", "body": "З `.cursor/rules` (або `AGENTS.md`) і сервером Figma MCP агент працює з вашими tokens, компонентами та реальними дизайн-специфікаціями замість того, щоб вгадувати."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Схема, що показує, як дизайн-система, skill і референсне зображення сходяться в добрий дизайн-результат", "caption": "Смак з'являється з трьох вхідних даних, які надаєте ви: дизайн-системи, skill-а та реальних референсних зображень."}, {"kind": "p", "text": "Урок той самий, що його вчить кожен агент: Cursor не має смаку за замовчуванням. Він створює добрий дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичний skill і конкретні референси. Open Design упаковує саме ці вхідні дані, тому ці двоє пасують одне одному (далі — детальніше)."}]}, {"id": "setup", "heading": "Налаштуйте Cursor для дизайну, з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Cursor, який може будувати, переглядати й перевіряти UI відносно вашої дизайн-системи."}, {"kind": "ol", "items": ["Встановіть Cursor із cursor.com і увійдіть зі своїм акаунтом Cursor або налаштуйте власні ключі моделей (BYOK) у Settings.", "Відкрийте свій проєкт і виберіть модель у панелі чату / Agent.", "Додайте правила проєкту: створіть `.cursor/rules/*.mdc` для структурованих, обмежених glob-ами конвенцій, або звичайний `AGENTS.md` для простих, читабельних інструкцій.", "Підключіть сервер Figma MCP (опційно), щоб агент міг читати живий дизайн-контекст.", "Запустіть свій dev-сервер і використовуйте попередній перегляд усередині редактора, щоб бачити й перевіряти UI під час ітерацій."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Процес налаштування з п'яти кроків: встановлення, автентифікація, налаштування правил, додавання skill-а, перевірка", "caption": "Послідовність налаштування: встановлення → автентифікація → налаштування правил проєкту → додавання skill-а → увімкнення перевірки через попередній перегляд."}, {"kind": "p", "text": "Мінімальний файл правил проєкту змушує агента проєктувати під бренд замість звертання до загального вигляду. Помістіть його туди, де Cursor читає його щоразу:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Закодуйте свої дизайн-правила", "body": "Помістіть свої tokens, примітиви та конвенції в `.cursor/rules` або `AGENTS.md` і вкажіть на них Cursor, щоб вивід відповідав бренду, а не звертався до загального вигляду."}, {"label": "Тримайте промпти невеликими", "body": "Щільний цикл Cursor винагороджує сфокусовані запити — ітеруйте по одному компоненту чи стану за раз і спостерігайте попередній перегляд між проходами."}]}]}, {"id": "preview-workflow", "heading": "Робочий процес «попередній перегляд → UI»", "blocks": [{"kind": "p", "text": "Найрезультативніший дизайн-цикл із Cursor — перетворити референс на робочий, адаптивний UI та ітерувати в редакторі, доки він не збіжиться — спостерігаючи живий попередній перегляд увесь час замість того, щоб вгадувати."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є, — і включайте кілька станів (десктоп і мобільний, hover, порожній, завантаження), а не лише один hero-кадр.", "Будьте конкретні в промпті; розпливчасті промпти дають загальний UI.", "Підготуйте дизайн-систему й скажіть Cursor, де живуть tokens і канонічні примітиви.", "Тримайте попередній перегляд усередині редактора відкритим, а dev-сервер запущеним, щоб кожна правка рендерилась миттєво на потрібних вам брейкпойнтах.", "Ітеруйте, порівнюючи відрендерений UI з референсами — і використовуйте прямий вибір елементів у попередньому перегляді для дрібних візуальних корекцій."]}, {"kind": "p", "text": "Подавайте референси, прикріплюючи зображення до чату, а потім задавайте промпт із конкретними обмеженнями:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Комітьте вдалі ітерації й відкочуйте невдалі (кажучи Cursor, коли ви відкочуєте), щоб кожен прохід будувався на чистій основі — та сама дисципліна, що не дає будь-якому циклу агента зноситися."}]}, {"id": "figma", "heading": "Cursor + Figma: дизайн ↔ код через MCP", "blocks": [{"kind": "p", "text": "Cursor підключається до Figma через офіційний сервер Figma MCP, що дає агенту структурований доступ до живого файлу Figma замість плаского скриншота. Це усуває здогадки з передачі."}, {"kind": "steps", "items": [{"label": "Дизайн → Код", "body": "Скопіюйте посилання на фрейм у Figma, вставте його в Cursor і попросіть реалізувати дизайн. Сервер MCP надає реальний дизайн-контекст — компоненти, змінні, дані розкладки, tokens — тож згенерований код відповідає джерелу, а не наближає його."}, {"label": "Лишайтеся узгодженими", "body": "З дизайн-tokens, стилями та компонентами, що послідовно використовуються у Figma (і Code Connect, де доступно), вивід Cursor лишається прив'язаним до вашої реальної дизайн-системи, а не винаходить примітиви заново."}]}, {"kind": "p", "text": "Налаштуйте віддалений сервер Figma MCP одного разу, і він стане доступним для Cursor як першокласний контекст. Оскільки MCP — це відкритий стандарт, той самий сервер можна повторно використовувати в Cursor, Claude Code, Codex і VS Code — саме той тип переносної, мультиагентної можливості, яку Open Design створено оркеструвати."}]}, {"id": "vs", "heading": "Cursor проти Codex проти Claude Code для дизайну", "blocks": [{"kind": "p", "text": "Єдиного переможця для дизайн-роботи немає — у кожного агента своя сильна сторона, і досвідчені команди поєднують їх. Чесне резюме:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайні", "Найкраще для"], "rows": [["Cursor", "Цикл «зроби й подивись» із живим попереднім переглядом усередині редактора та прямим редагуванням елементів", "Щільна робота над UI у режимі «ітеруй і спостерігай» усередині IDE"], ["Codex", "Сильне візуальне опрацювання з frontend skill; розуміння зображень і запуски в пісочниці", "Делеговані асинхронні збірки та переносні правила AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) та UX з урахуванням кодової бази", "Фронтенд-міркування й рефактори з великим контекстом"]]}, {"kind": "p", "text": "Сталий вердикт спільноти такий: смак походить від людей — усі три за замовчуванням тяжіють до загальної естетики без skill-ів, референсів і обмежень. Це і є справжня проблема, яку треба розв'язати — і вона має форму дизайн-інструмента, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI slop»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на дизайн, згенерований Cursor, — що він виглядає загальним: м'які градієнти, плаваючі панелі, завеликі заокруглені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив ШІ». Серед інших повідомлених проблем — розкладки, що ламаються на мобільному, та інструкції, що протікають у текст UI."}, {"kind": "steps", "items": [{"label": "Додайте дизайн-skill", "body": "Кураторський естетичний skill змушує Cursor обрати реальний напрямок замість вигляду за замовчуванням."}, {"label": "Використовуйте попередній перегляд для перевірки", "body": "Рендерте й самоперевіряйтеся на різних брейкпойнтах у попередньому перегляді всередині редактора, щоб розкладки не ламались на мобільному непомітно."}, {"label": "Надайте tokens і референси", "body": "Реальні дизайн-tokens і референсні скриншоти — найпотужніший важіль якості виводу."}, {"label": "Закодуйте правила в `.cursor/rules`", "body": "Помістіть правила штибу «без hero-карток, максимум два шрифти, ієрархія за брендом» туди, де агент читає їх щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожен спосіб пом'якшення зводиться до надання агенту кураторського дизайн-контексту. Підтримувати цей контекст вручну для кожного проєкту — це рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн із Cursor всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це той дизайн-шар з відкритим кодом, якого постійно потребує наведений вище процес. Він трактує Cursor як власний адаптер і обгортає його кураторською бібліотекою skill-ів і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — щоб дизайн-контекст, який робить Cursor добрим, був на місці з першого запуску, а не збирався вручну щоразу."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Cursor як свого агента.", "Автентифікуйтеся своїм акаунтом Cursor або власними ключами моделей (BYOK) — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та skill, а потім генеруйте презентації, прототипи й лендинги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в розміщеній хмарі."]}, {"kind": "p", "text": "Той самий агент Cursor, той самий ключ — плюс реальний, переносний дизайн-процес з відкритим кодом навколо нього. Він local-first і Apache-2.0, тож ніщо у вашій роботі чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи справді Cursor може виконувати дизайн-роботу?", "text": "Так — із дизайн-skill, дизайн-системою та реальними референсними зображеннями в контексті Cursor створює UI продакшн-якості, адаптивний, а його попередній перегляд усередині редактора дозволяє перевіряти й уточнювати його візуально. Без цього контексту він тяжіє до загального вигляду — і саме цю прогалину закриває Open Design."}, {"name": "Це офіційний продукт Cursor?", "text": "Ні. Open Design — незалежний проєкт з відкритим кодом, який інтегрує Cursor як агента. Він доповнює Cursor local-first відкритою бібліотекою skill-ів і дизайн-систем."}, {"name": "Чи потрібна мені підписка Cursor, щоб проєктувати з Cursor?", "text": "Ви можете використовувати акаунт / підписку Cursor або підключити власні ключі моделей (BYOK). У будь-якому разі Open Design ніколи не проксіює ваші облікові дані — їх безпосередньо використовує ваш агент."}, {"name": "Cursor чи Claude Code для фронтенд-дизайну?", "text": "Обидва сильні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази; перевага Cursor — його щільний цикл «зроби й подивись» із живим попереднім переглядом усередині редактора. Багато команд використовують обидва — Open Design дозволяє перемикати агентів без зміни дизайн-процесу."}, {"name": "Як підключити Cursor до Figma?", "text": "Додайте офіційний сервер Figma MCP у Cursor, потім вставте посилання на фрейм Figma в чат і попросіть Cursor реалізувати його. Сервер надає реальні компоненти, змінні та дані розкладки, тож згенерований код відповідає вихідному дизайну."}, {"name": "Як уникнути загальної естетики «AI slop»?", "text": "Додайте дизайн-skill, надайте реальні дизайн-tokens і референсні скриншоти, закодуйте правила бренду в `.cursor/rules` або `AGENTS.md` і перевіряйте на різних брейкпойнтах у попередньому перегляді. Open Design постачає це як кураторську бібліотеку, щоб ви пропустили налаштування для кожного проєкту."}, {"name": "Чи пов'язаний Open Design з Cursor або Anysphere?", "text": "Ні. Cursor — продукт Anysphere; Open Design — незалежний проєкт з відкритим кодом, який підтримує його як власний адаптер. Cursor і Anysphere — торгові марки Anysphere, Inc."}, {"name": "Чи мої файли й облікові дані в безпеці?", "text": "Так — Open Design local-first. Ваші файли, артефакти й DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані Cursor чи моделі використовуються безпосередньо вашим агентом і ніколи не маршрутизуються через сервери Open Design."}], "ctaTitle": "Проєктуйте з Cursor, відкрито.", "ctaBody": "Підключіть власний акаунт Cursor або ключі моделей, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтесь.", "ctaActions": [{"label": "Використати Cursor в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode для дизайну — Open Design",
        description: "Як люди використовують OpenCode для UI та вебдизайну — файли design.md, UI/UX skill-и, Figma MCP — і як Open Design перетворює OpenCode на local-first дизайн-агента з відкритим кодом.",
        breadcrumb: "OpenCode",
        label: "Агент · OpenCode",
        heading: "OpenCode для дизайну.",
        lead: "OpenCode — це термінальний AI-агент для кодування з відкритим кодом. Дизайнери прикручують до нього дизайн-skill-и та файли DESIGN.md, щоб генерувати справжній UI. Open Design робить це структурованим процесом з відкритим кодом — підключіть ключі своїх постачальників, тримайте все локально.",
        rich: {"heroCtaLead": "Open Design перетворює OpenCode на local-first дизайн-агента з відкритим кодом — будь-яка модель, яку ви обираєте, з вашим власним ключем постачальника, ваші файли та кураторська бібліотека skill-ів і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використати OpenCode в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode — це термінальний AI-агент для кодування з відкритим кодом, навмисно незалежний від моделей: ви підключаєте власний ключ постачальника й запускаєте будь-яку модель за тим самим робочим процесом. Така відкритість робить його природною базою для дизайн-роботи — але, як і кожен агент, він створює добрий UI лише тоді, коли ви даєте йому правильні референси, skill-и та цикл перевірки. Це практичний наскрізний посібник з використання OpenCode для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування в структурований дизайн-процес разом з Open Design.", "Тут розглядається, чим насправді є OpenCode, чому відкритий агент, незалежний від моделей, добре пасує дизайну, як налаштувати його з нуля, цикл «скриншот → UI», як AGENTS.md і MCP розширюють його, як він порівнюється з Codex, Claude Code та Cursor, пастки, через які вивід ШІ виглядає загальним, і як Open Design закриває цю прогалину як відкритий local-first дизайн-шар — природне поєднання, адже обидва проєкти з відкритим кодом і працюють на вашій власній машині."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Цикл зворотного зв'язку дизайну OpenCode: термінальний TUI-агент, браузер, що рендерить UI, і робочий простір зі стрілкою зворотного зв'язку", "caption": "Основний цикл: OpenCode будує UI у терміналі, рендерить і перевіряє його у справжньому браузері та ітерує до ваших референсів — на будь-якій моделі, яку ви оберете."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-opencode", "label": "Чим насправді є OpenCode"}, {"id": "why-design", "label": "Чому відкритий агент із будь-якою моделлю пасує дизайну"}, {"id": "setup", "label": "Налаштування OpenCode для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «скриншот → UI»"}, {"id": "extend", "label": "AGENTS.md, MCP та сесії, якими можна ділитися"}, {"id": "vs", "label": "OpenCode проти Codex проти Claude Code проти Cursor"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI slop»"}, {"id": "open-design", "label": "Дизайн із OpenCode в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-opencode", "heading": "Чим насправді є OpenCode", "blocks": [{"kind": "p", "text": "OpenCode — це AI-агент для кодування з відкритим кодом, створений для терміналу й підтримуваний командою, що стоїть за SST (Anomaly Innovations). Він читає ваш репозиторій, виконує команди, редагує файли й спілкується з великою мовною моделлю — але, на відміну від прив'язаних до вендора агентів, він не постачає власну модель. Ви спрямовуєте його на будь-який постачальник і модель, які захочете, і підключаєте власний ключ."}, {"kind": "p", "text": "Він працює як термінальний UI (TUI), з десктопним застосунком та розширеннями IDE поверх того самого рушія. Під капотом він використовує клієнт-серверну архітектуру, тож агент, що виконує роботу, відокремлений від поверхні, з якої ви ним керуєте. Два вбудовані агенти — build і plan — перемикаються клавішею Tab."}, {"kind": "steps", "items": [{"label": "Незалежний від моделей", "body": "Моделі та постачальники беруться з models.dev, відкритого каталогу. Ви налаштовуєте їх в opencode.json рядком provider/model-id і можете вимкнути постачальників, яких не хочете завантажувати — тож той самий дизайн-процес працює на Anthropic, OpenAI, Google, OpenRouter, локальних моделях тощо."}, {"label": "Файл інструкцій", "body": "OpenCode читає файл AGENTS.md у вашому проєкті (міжінструментальний стандарт, також сумісний із CLAUDE.md) для правил проєкту — природне місце, щоб закодувати ваші дизайн-конвенції. Запустіть /init, щоб згенерувати його."}, {"label": "Розширюваний", "body": "Він підтримує інтеграцію LSP, сервери MCP, теми, комбінації клавіш і кастомні команди, а також посилання на сесії, якими можна ділитися, для співпраці."}]}, {"kind": "ul", "items": ["Супровід: SST / Anomaly Innovations (проєкт з відкритим кодом)", "Облікові дані: ваш(і) власний(і) API-ключ(і) постачальника моделей — BYOK, без прив'язки до вендора", "Ліцензія: MIT, відкритий код"]}]}, {"id": "why-design", "heading": "Чому відкритий агент із будь-якою моделлю пасує дизайн-роботі", "blocks": [{"kind": "p", "text": "OpenCode не має єдиної «дизайн-моделі», як її має вендорний агент — і в цьому суть. Оскільки він незалежний від моделей і відкритий, ви можете запускати той самий дизайн-процес на тій моделі, яка зараз найкраща у фронтенді, замінити її пізніше або відкотитися до локальної моделі — і все без зміни вашого налаштування."}, {"kind": "p", "text": "Але самого вибору моделі мало для смаку. Як і кожен агент для кодування, OpenCode створює загальний UI, доки ви не дасте йому обмежень. Добрий дизайн-вивід походить із трьох вхідних даних, які надаєте ви."}, {"kind": "steps", "items": [{"label": "Дизайн-система", "body": "Реальні tokens, примітиви та конвенції, які агент повторно використовує, щоб вивід відповідав бренду, а не звертався до загального вигляду."}, {"label": "Естетичний skill", "body": "Кураторський skill, що нав'язує реальний смак — стриманий рух, ієрархія за брендом, щонайбільше два шрифти й один акцентний колір — і змушує агента обрати напрямок перед побудовою."}, {"label": "Конкретні референси", "body": "Справжні референсні зображення та кілька станів (десктоп і мобільний, hover, порожній, завантаження), а не один hero-кадр."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Схема, що показує, як дизайн-система, skill і референсне зображення сходяться в добрий дизайн-результат", "caption": "Смак з'являється з трьох вхідних даних, які надаєте ви: дизайн-системи, skill-а та реальних референсних зображень — незалежно від того, яку модель ви запускаєте."}, {"kind": "p", "text": "Урок: OpenCode дає вам свободу моделі, але смак усе одно походить із кураторського дизайн-контексту. Open Design упаковує саме ці вхідні дані, тому ці двоє пасують одне одному — обидва з відкритим кодом і local-first (далі — детальніше)."}]}, {"id": "setup", "heading": "Налаштуйте OpenCode для дизайну, з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до OpenCode, який може будувати й перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Процес налаштування з п'яти кроків: встановлення, автентифікація ключем постачальника, налаштування AGENTS.md, додавання skill-а, перевірка", "caption": "Послідовність налаштування: встановлення → автентифікація (ваш ключ постачальника) → налаштування AGENTS.md → додавання skill-а → перевірка у справжньому браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої дизайн-правила", "body": "Помістіть свої tokens, примітиви та конвенції в AGENTS.md (або DESIGN.md, на який є посилання звідти), щоб вивід відповідав бренду, а не звертався до загального вигляду. Опція instructions в opencode.json може вказувати на додаткові файли правил через glob-и."}, {"label": "Виберіть здатну модель", "body": "Оскільки OpenCode незалежний від моделей, виберіть той постачальник/модель, що зараз найсильніший у фронтенді, для дизайн-проходу — і лишіть решту свого процесу незмінною."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «скриншот → UI»", "blocks": [{"kind": "p", "text": "Найрезультативніший дизайн-цикл із будь-яким агентом — перетворити референсне зображення на робочий, адаптивний UI та ітерувати, доки воно не збіжиться. Та сама форма з п'яти кроків застосовна в OpenCode."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є, — і включайте кілька станів (десктоп і мобільний, hover, порожній, завантаження), а не лише один hero-кадр.", "Будьте конкретні в промпті; розпливчасті промпти дають загальний UI.", "Підготуйте дизайн-систему й скажіть OpenCode, де живуть tokens і канонічні примітиви (в AGENTS.md).", "Запустіть dev-сервер і змусьте агента рендерити у справжньому браузері, змінюючи розмір під брейкпойнти, щоб перевірити результат.", "Ітеруйте, змушуючи OpenCode порівнювати свою реалізацію зі скриншотами — а не лише підтверджувати, що збірка проходить."]}, {"kind": "p", "text": "Посилайтеся на файли через @ у TUI для нечіткого пошуку у вашій робочій директорії, виконуйте shell-команди інлайн із початковим !, і керуйте діями через команди /. Потім задавайте промпт із конкретними обмеженнями:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Тримайте промпти невеликими й сфокусованими, комітьте вдалі ітерації й відкочуйте невдалі (кажучи OpenCode, коли ви відкочуєте), щоб кожен прохід будувався на чистій основі."}]}, {"id": "extend", "heading": "AGENTS.md, MCP та сесії, якими можна ділитися", "blocks": [{"kind": "p", "text": "Три точки розширення роблять OpenCode практичним для сталої дизайн-роботи, і всі три чисто лягають на відкритий дизайн-процес."}, {"kind": "steps", "items": [{"label": "Правила AGENTS.md", "body": "Правила проєкту живуть в AGENTS.md у корені репозиторію (або глобальні правила в ~/.config/opencode/AGENTS.md). Це довговічна домівка для ваших дизайн-конвенцій, що читається щоразу, і вона сумісна з файлами CLAUDE.md, які використовують інші агенти."}, {"label": "Сервери MCP", "body": "OpenCode підтримує як локальні (command), так і віддалені (URL) сервери MCP, налаштовані під ключем mcp — переносний спосіб привнести дизайн-контекст і зовнішні інструменти, що працюють між агентами, а не лише в OpenCode."}, {"label": "Сесії, якими можна ділитися", "body": "Команда /share створює публічне посилання на розмову для співпраці чи рев'ю, а /unshare відкликає його — корисно для отримання відгуку про дизайн-прохід."}]}, {"kind": "p", "text": "Це переносні, мультиагентні можливості — саме той тип речей, який Open Design створено оркеструвати, а не відтворювати для кожного проєкту."}]}, {"id": "vs", "heading": "OpenCode проти Codex проти Claude Code проти Cursor для дизайну", "blocks": [{"kind": "p", "text": "Єдиного переможця для дизайн-роботи немає — у кожного агента своя сильна сторона, і досвідчені команди поєднують їх. Чесне резюме:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайні", "Найкраще для"], "rows": [["OpenCode", "Відкритий код і незалежність від моделей; запускайте будь-який постачальник за одним термінальним процесом", "Свобода BYOK, перемикання моделей, повністю відкриті та local-first налаштування"], ["Codex", "Сильне візуальне опрацювання з frontend skill; розуміння зображень", "Делеговані асинхронні, збірки в пісочниці, переносні правила AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) та UX з урахуванням кодової бази", "Фронтенд-міркування й рефактори з великим контекстом"], ["Cursor", "Цикл «зроби й подивись» із живим попереднім переглядом та інлайн-правками", "Щільна робота над UI у режимі «ітеруй і спостерігай» усередині IDE"]]}, {"kind": "p", "text": "Сталий вердикт спільноти такий: смак походить від людей — усі вони за замовчуванням тяжіють до загальної естетики без skill-ів, референсів і обмежень. Це і є справжня проблема, яку треба розв'язати — і вона має форму дизайн-інструмента, а не моделі, і саме тому відкритий агент на кшталт OpenCode так добре поєднується з відкритим дизайн-шаром."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI slop»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на дизайн, згенерований ШІ, — що він виглядає загальним: м'які градієнти, плаваючі панелі, завеликі заокруглені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив ШІ». Серед інших повідомлених проблем — поламані мобільні розкладки та інструкції, що протікають у текст UI. Жодна з них не унікальна для OpenCode; це те, що стається, коли будь-який агент працює без кураторського дизайн-контексту."}, {"kind": "steps", "items": [{"label": "Додайте естетичний skill", "body": "Кураторський дизайн-skill змушує агента обрати реальний напрямок замість вигляду за замовчуванням."}, {"label": "Перевіряйте у справжньому браузері", "body": "Рендерте й самоперевіряйтеся на різних брейкпойнтах, щоб розкладки не ламались на мобільному непомітно."}, {"label": "Надайте tokens і референси", "body": "Реальні дизайн-tokens і референсні скриншоти — найпотужніший важіль якості виводу."}, {"label": "Закодуйте правила в AGENTS.md", "body": "Помістіть правила штибу «без hero-карток, максимум два шрифти, ієрархія за брендом» туди, де агент читає їх щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожен спосіб пом'якшення зводиться до надання агенту кураторського дизайн-контексту — незалежно від того, яку модель ви запускаєте. Підтримувати цей контекст вручну для кожного проєкту — це рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн із OpenCode всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це той дизайн-шар з відкритим кодом, якого постійно потребує наведений вище процес. Він трактує OpenCode як власний адаптер і обгортає його кураторською бібліотекою skill-ів і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — щоб дизайн-контекст, який робить будь-якого агента добрим, був на місці з першого запуску, а не збирався вручну щоразу. Обидва проєкти з відкритим кодом і local-first, що робить поєднання природним."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть OpenCode як свого агента.", "Автентифікуйтеся своїм власним API-ключем постачальника моделі (BYOK) — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть будь-який постачальник і модель, а також дизайн-систему та skill, а потім генеруйте презентації, прототипи й лендинги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в розміщеній хмарі."]}, {"kind": "p", "text": "Той самий агент OpenCode, та сама свобода моделі — плюс реальний, переносний дизайн-процес з відкритим кодом навколо нього. Він local-first і Apache-2.0, тож ніщо у вашій роботі чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи справді OpenCode може виконувати дизайн-роботу?", "text": "Так — із естетичним skill, дизайн-системою та реальними референсними зображеннями в контексті OpenCode створює UI продакшн-якості, адаптивний, і може перевірити його в браузері. Оскільки він незалежний від моделей, ви запускаєте ту модель, яка зараз найкраща у фронтенді. Без цього кураторського контексту він тяжіє до загального вигляду — і саме цю прогалину закриває Open Design."}, {"name": "Яку модель слід використовувати з OpenCode для дизайну?", "text": "Будь-яку, що вам до вподоби — OpenCode незалежний від постачальників через models.dev, тож ви можете запускати Anthropic, OpenAI, Google, OpenRouter або локальні моделі за тим самим процесом і перемикатися будь-коли. Якість дизайн-виводу залежить набагато більше від вашого skill-а, дизайн-системи та референсів, ніж від самої моделі."}, {"name": "Чи зроблено Open Design командою OpenCode (SST)?", "text": "Ні. Open Design — незалежний проєкт з відкритим кодом, який інтегрує OpenCode як агента. Він доповнює OpenCode local-first відкритою бібліотекою skill-ів і дизайн-систем."}, {"name": "Чи потрібна мені особлива підписка, щоб проєктувати з OpenCode?", "text": "Ні — OpenCode працює за BYOK. Ви підключаєте власний API-ключ постачальника моделі, і Open Design ніколи не проксіює ваші облікові дані. Немає прив'язки до вендора."}, {"name": "OpenCode, Codex чи Claude Code для фронтенд-дизайну?", "text": "Усі сильні, і багато команд поєднують їх. Перевага OpenCode — бути повністю з відкритим кодом і незалежним від моделей; Codex чудовий у делегованих збірках у пісочниці; Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази. Open Design дозволяє перемикати агентів без зміни дизайн-процесу."}, {"name": "Як розширити OpenCode для дизайн-контексту?", "text": "Закодуйте правила в AGENTS.md, додайте сервери MCP під ключем mcp для переносних інструментів і дизайн-контексту та використовуйте сесії, якими можна ділитися, для рев'ю. Open Design постачає кураторську бібліотеку skill-ів і дизайн-систем, щоб ви пропустили налаштування для кожного проєкту."}, {"name": "Чи пов'язаний Open Design з OpenCode або SST?", "text": "Ні. OpenCode — проєкт з відкритим кодом, який підтримує SST (Anomaly Innovations); Open Design — незалежний проєкт з відкритим кодом, який підтримує його як власний адаптер."}, {"name": "Чи мої файли й облікові дані в безпеці?", "text": "Так — Open Design local-first. Ваші файли, артефакти й DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані постачальника моделі використовуються безпосередньо вашим агентом і ніколи не маршрутизуються через сервери Open Design."}], "ctaTitle": "Проєктуйте з OpenCode, відкрито.", "ctaBody": "Підключіть власний ключ постачальника моделі, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо відкритого агента, яким ви вже користуєтесь.", "ctaActions": [{"label": "Використати OpenCode в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
    },
  };
}
